window.ALL_QUESTIONS = [{"type": "choice", "question": "防止铜合金出现“季裂”现象，可以通过（ ）来处理。", "options": ["正火", "淬火", "固溶", "去应力退火"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "铜合金\"季裂\"是冷加工残余应力遇潮湿环境（氨/水汽）引起的应力腐蚀开裂。去应力退火（200-300℃保温后缓冷，也称回复退火）消除残余内应力而不改变强度，是标准防季裂工艺。正火/淬火针对钢的奥氏体化冷却转变，固溶处理针对铝合金时效强化，均不适用于铜合金去应力场景。", "section": "一、选择题", "topic": "热处理基础知识", "id": 1, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "珠光体、索氏体和托氏体是过冷奥氏体（ ）的转变产物。", "options": ["高温", "中温", "低温"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。珠光体(P)、索氏体(S、细珠光体)和托氏体(T、极细珠光体)是过冷奥氏体在**高温区**（A1~550℃）的扩散型共析转变产物——三者本质相同（铁素体+渗碳体层片组织），区别仅在于片间距不同（冷却越快片间距越细）。中温区产物为贝氏体，低温区为马氏体。", "section": "一、选择题", "topic": "热处理基础知识", "id": 2, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "珠光体组织的相组成为：（ ）。", "options": ["奥氏体和渗碳体", "铁素体和渗碳体", "马氏体和渗碳体", "渗碳体"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。珠光体组织的相组成：**铁素体+渗碳体**（α-Fe+Fe₃C的层片状机械混合物）。奥氏体在高温（>727℃）稳定，室温下不存在；马氏体是非平衡组织（快冷产物）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 3, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "下列各组织中，属于非扩散转变产物的是（ ）。", "options": ["珠光体", "奥氏体", "铁素体", "马氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "马氏体转变是无扩散型相变——铁原子不发生扩散，仅通过切变（共格）方式完成fcc→bct晶格改组，碳原子也被「冻结」在原位。珠光体（A）→扩散型共析转变，奥氏体（B）→扩散型重结晶，铁素体（C）→扩散型多形性转变。马氏体是非扩散型转变的唯一产物。", "section": "一、选择题", "topic": "热处理基础知识", "id": 4, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "choice", "question": "材料在受力时抵抗弹性变形的能力称为（ ）。", "options": ["强度", "屈服点", "硬度", "刚度"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。刚度是指材料在受力时抵抗弹性变形的能力，用弹性模量E（σ/ε）衡量。强度是抵抗破坏的能力，屈服点是开始塑性变形的应力，硬度是抵抗局部压入的能力。概念容易混淆：刚度→弹性变形阶段，强度→破坏阶段。", "section": "一、选择题", "topic": "热处理基础知识", "id": 5, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "若人工时效的时间过长或温度过高，反而使合金软化，这种现象称（ ）。", "options": ["时效", "过时效", "退火", "回归处理"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "铝合金时效强化遵循\"欠时效→峰值时效→过时效\"规律。温度过高或时间过长时GP区溶解而平衡相过度长大，与基体失去共格关系导致强化效果下降，称为\"过时效\"。回归处理（D）是将已时效铝合金短时高温加热使GP区重新溶解——与本题温度过高的负面效果不同，回归后可重新时效。", "section": "一、选择题", "topic": "热处理基础知识", "id": 6, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "由生铁及燃料带入钢中的有害元素，容易使钢在高温下变形产生热脆性的是（ ）。", "options": ["P", "S", "Mn", "Si"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。硫（S）在钢中形成低熔点（~985℃）的FeS或其晶界共晶体FeS-Fe（熔点更低，仅~940℃），在热加工温度（1000~1200℃）下晶界熔化→产生热脆性（热加工开裂）。Mn可固定S形成高熔点MnS（~1620℃）来减轻热脆性。", "section": "一、选择题", "topic": "热处理基础知识", "id": 7, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "金属材料抵抗冲击载荷而不破坏的能力称为（ ）。", "options": ["塑性", "韧性", "刚度", "硬度"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。韧性（冲击韧韧）是金属材料抵抗冲击载荷而不破坏的能力，通常用冲击吸收功（Ak/J）衡量。塑性是指静载下产生永久变形而不破坏的能力，刚度是指抵抗弹性变形的能力，硬度是指抵抗局部压入/划痕的能力。", "section": "一、选择题", "topic": "热处理基础知识", "id": 8, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "金属经剧烈冷变形后，位错密度（ ）", "options": ["降低", "没变化", "大大提高"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。金属经剧烈冷变形后，位错密度大大提高（从10⁶~10⁸/cm²升至10¹⁰~10¹²/cm²）。位错增殖机制（弗兰克-里德源等）导致大量位错产生，位错间相互缠结、交割，使继续滑移困难——这就是加工硬化的微观本质。", "section": "一、选择题", "topic": "热处理基础知识", "id": 9, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "把含碳量在（ ）之间的，且不含有特意加入合金元素的钢称为碳素钢，简称碳钢。", "options": ["0.0218%~0.77%", "0.0218~2.11", "0.0218%~2.11%", "小于 2.11"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "碳素钢定义：含碳量0.0218%~2.11%之间，且不含有特意加入的合金元素。含碳<0.0218%=工业纯铁，>2.11%=铸铁。Si/Mn为脱氧残留，P/S为杂质。0.0218-0.77-2.11%完整区间涵盖亚共析/共析/过共析全部碳钢范围。", "section": "一、选择题", "topic": "热处理基础知识", "id": 10, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "由炼钢生铁带入钢中，容易使钢产生冷脆性的元素是（ ）。", "options": ["P", "S", "Mn", "Si"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。磷（P）使钢在低温下韧脆转变温度升高，低温下（<0℃）容易脆性断裂→冷脆性。磷虽能固溶强化铁素体，但急剧降低韧塑性和焊接性能，是有害杂质元素（但易切削钢有意加P以改善切削性）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 11, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "影响C曲线形状和位置的主要因素是（ ）", "options": ["温度", "化学成分", "加热速度"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。C曲线（TTT图）形状和位置的主要影响因素是**化学成分**——碳含量和合金元素（除Co外几乎所有合金元素都使C曲线右移→过冷奥氏体更稳定）。温度是转变的变量（C曲线的纵坐标），加热速度影响奥氏体状态但不及成分影响大。", "section": "一、选择题", "topic": "热处理基础知识", "id": 12, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "按含碳量进行分类，20钢属于（ ）。", "options": ["低碳钢", "结构钢", "中碳钢", "高碳钢"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "20钢含碳量约0.20%，按含碳量分类属低碳钢（＜0.25%C）。碳钢按含碳量分：低碳钢0.0218%-0.25%C（塑性好，用于冲压件/焊接件），中碳钢0.25%-0.60%C（调质用），高碳钢＞0.60%C（工具/弹簧用）。20钢是典型的低碳渗碳钢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 13, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "合金元素总含量为（ ）的合金钢，属于中合金钢。", "options": ["小于5%", "大于5%", "5%~10%", "大于10%"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "合金钢按合金元素总量分类：低合金钢<5%，中合金钢5%-10%，高合金钢>10%。与按用途分类（结构钢/工具钢/特殊性能钢）平行使用，是国标基础分类法。", "section": "一、选择题", "topic": "热处理基础知识", "id": 14, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "下列各种金属材料中，常用于制造弹簧的是： （ ）。", "options": ["20钢", "60Si2Mn", "LC4", "12Cr2Ni4A"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "60Si2Mn是典型弹簧钢：C约0.6%提供强度，Si约2%提高弹性极限和回火稳定性，Mn提高淬透性。弹簧需高弹性极限+高屈强比+高疲劳强度。20钢强度低，LC4是超硬铝，12Cr2Ni4A是渗碳钢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 15, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "不属于不锈钢的材料是：（ ）。", "options": ["2Cr13", "Cr12MoV", "0Cr13A1", "GCr15"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "GCr15是滚动轴承钢（C约1.0%，Cr约1.5%），不属于不锈钢（Cr<12%且不以耐蚀为主要用途）。2Cr13/0Cr13Al含Cr≥12%且以耐蚀为设计目标→不锈钢。Cr12MoV虽含Cr高但归类为冷作模具钢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 16, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "T11A钢的含碳量为：（ ）。", "options": ["1.1%", "0.11%", "11%", "0.11"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "T11A牌号解读：T=碳素工具钢，11=平均含碳量千分之十一即1.1%，A=高级优质钢（S/P含量更低）。碳素工具钢牌号命名：T+数字（碳含量千分数）+质量等级。", "section": "一、选择题", "topic": "热处理基础知识", "id": 17, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "属于超硬铝合金牌号的是（ ）。", "options": ["LF21", "LC4", "LD7", "LY12"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "LC4（7A04）属Al-Zn-Mg-Cu系超硬铝合金，是强度最高的铝合金之一。LF21=防锈铝（Al-Mn系），LD7=锻铝（Al-Mg-Si-Cu系），LY12=硬铝（Al-Cu-Mg系）。铝合金牌号首字母标识类别。", "section": "一、选择题", "topic": "热处理基础知识", "id": 18, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "下列金属材料中，可用于制造成形车刀及各种铣刀的是：（ ）.", "options": ["40Cr", "T7、T8钢", "W18Cr4V", "30CrMnSiNi2"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "W18Cr4V是钨系高速钢，650℃以下保持HRC60+红硬性，专用于车刀/铣刀等切削刀具。40Cr是调质钢硬度不够，T7/T8碳素工具钢红硬性差（>250℃软化），30CrMnSiNi2是超高强度结构钢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 19, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "代表镁合金的材料牌号是（ ）。", "options": ["ZGMn13", "HMn58-2", "60Si2Mn", "MB2"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "MB2是变形镁合金（Mg-Al-Zn-Mn系），密度约1.8g/cm³最轻结构金属。ZGMn13=铸造高锰钢，HMn58-2=锰黄铜，60Si2Mn=弹簧钢。牌号首字母标识材料大类。", "section": "一、选择题", "topic": "热处理基础知识", "id": 20, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "以下几种冷却介质中，冷确能力最大的是（ ）。", "options": ["碱水", "盐水", "自来水", "油"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。冷却能力排序：**碱水（NaOH溶液）**>盐水（NaCl溶液）>自来水>油。碱水中OH⁻离子进一步破坏蒸气膜，冷却能力极强（但腐蚀性大，应用少于盐水）。盐水>水因为盐结晶爆炸破坏蒸气膜。油冷却最慢但变形倾向最小。", "section": "一、选择题", "topic": "热处理基础知识", "id": 21, "knowledge_point": "冷却介质与淬透性", "knowledge_point_key": "cooling_quenchants"}, {"type": "choice", "question": "从下列材料牌号中属于铝青铜的是（ ）。", "options": ["QA17", "TU2", "H68", "TA1"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "QA17是铝青铜（Q=青铜，A=铝，7=Al含量约7%），耐蚀耐磨，用于轴瓦/蜗轮。TU2=无氧铜，H68=黄铜（Cu-Zn），TA1=工业纯钛。铝青铜以铝为主加元素+优良耐海水腐蚀。", "section": "一、选择题", "topic": "热处理基础知识", "id": 22, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "下列代号或牌号中，表示纯铜的是（ ）。", "options": ["T7", "T1", "TA1", "T7A"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "T1=一号纯铜（T+序号→纯度等级，Cu≥99.95%）。T7/T7A=碳素工具钢（T+碳含量千分数），TA1=工业纯钛。铜合金牌号中T开头=纯铜（紫铜/红铜），与工具钢T系列不同。", "section": "一、选择题", "topic": "热处理基础知识", "id": 23, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "将钢材或钢件加热到A.或A以上30~50℃，保温适当的时间后，在空气中冷却的热处理工艺称为（ ）", "options": ["或A以上30~50℃，保温适当的时间后，在空气中冷却的热处理工艺称为(C)", "回火", "退火", "正火", "淬火"], "option_labels": ["A", "B", "C", "D", "E"], "answer": "D", "explanation": "正火定义：将钢加热到Ac3（亚共析钢）或Accm（过共析钢）以上30~50℃，保温后在空气中冷却的热处理工艺。退火的核心区别在于冷却方式——退火为随炉缓冷（最慢），正火为空冷（较快）。Ac3以上加热+空冷=正火。", "section": "一、选择题", "topic": "热处理基础知识", "id": 24, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "热处理生产中，“调质”处理是指（ ）。", "options": ["淬火+低温回火", "淬火+中温回火", "正火+低温回火 I", "淬火+高温回火"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "调质=淬火+高温回火（500-650℃），获得回火索氏体组织，兼具高强度与良好韧性，是结构钢最常用的最终热处理。淬火+低温回火（A）→回火马氏体（高硬度刀具/量具），淬火+中温回火（B）→回火屈氏体（弹簧）。注意正火+回火（C）不是调质。", "section": "一、选择题", "topic": "热处理基础知识", "id": 25, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "choice", "question": "钢在回火时出现硬度回升的现象，称为（ ）。", "options": ["过热现象", "二次硬化", "回复转变", "再结晶转变27、将已经强化的铝合金重新加热(温度200~270℃)，经保温后在水中急速冷却，使合金恢复到固溶后的状态。这种现象称为(C)。", "过热", "过时效", "回归处理", "回火处理"], "option_labels": ["A", "B", "C", "D", "E", "F", "G", "H"], "answer": "B", "explanation": "B正确。二次硬化指某些含强碳化物形成元素（W、Mo、V、Cr）的合金钢在500~600℃回火时，硬度不降反升的现象。原因是合金碳化物（W₂C、VC、Mo₂C）呈弥散分布析出，产生沉淀强化，抵消了马氏体分解析出碳化物引起的硬度下降。", "section": "一、选择题", "topic": "热处理基础知识", "id": 26, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "下列各种合金元素中，不能阻止奥氏体晶粒长大，含有该元素的合金钢加热容易过热的是（ ）。", "options": ["Crl", "Mn", "Ti", "W"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "Mn（锰）是弱碳化物形成元素→不能有效钉扎奥氏体晶界→含Mn钢加热时晶粒容易长大过热。Cr/Ti/W均为强碳化物形成元素→形成细小碳化物（Cr23C6/TiC/WC）质点钉扎晶界→有效阻止晶粒长大→使钢本质细晶粒化。", "section": "一、选择题", "topic": "热处理基础知识", "id": 27, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "奥氏体等温转变产物的组织和性能，决定于（ ）。", "options": ["转变温度", "冷却速度", "加热温度", "保温时间"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。奥氏体等温转变（TTT）产物的组织和性能决定于**转变温度**——同一钢种，不同温度等温→不同组织（高温→珠光体型、中温→贝氏体型）。在给定温度等温，组织类型和性能就已确定。", "section": "一、选择题", "topic": "热处理基础知识", "id": 28, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "黄铜的主要热处理方式是 （ ）。", "options": ["退火", "淬火", "回火", "正火"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "黄铜（Cu-Zn合金）属单相α或双相α+β合金，无固态相变（无马氏体转变），无法通过淬火强化。热处理主要靠退火：冷变形后再结晶退火消除加工硬化，或去应力退火（防季裂退火）消除残余应力。淬火/回火/正火均为钢铁材料的热处理工艺。", "section": "一、选择题", "topic": "热处理基础知识", "id": 29, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "共析钢在退火后，得到的组织是（ ）", "options": ["马氏体", "奥氏体", "珠光体", "贝氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "共析钢（C≈0.77%）退火：加热到Ac1以上→全奥氏体化→随炉缓冷→在A1（727℃）发生共析转变γ→α+Fe₃C→层片状珠光体。马氏体（A）需淬火快冷，奥氏体（B）是高温相，贝氏体（D）是等温淬火产物（中温转变）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 30, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "马氏体是碳在a-Fe中的（ ）。", "options": ["过饱和固溶体", "置换固溶体", "金属间化合物", "非共格相"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。马氏体是碳在α-Fe中的过饱和固溶体。奥氏体（γ-Fe，面心立方，碳溶解度大~2.11%）快冷时，碳来不及析出→被迫留在α-Fe（体心立方，碳溶解度极小~0.008%）中→碳原子\"过饱和\"→晶格严重畸变→马氏体。正常α-Fe几乎不溶碳（>0.008%就析出Fe₃C）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 31, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "尺寸相近，形状相同，不同材料，硬度值不同的几项产品由于不规范管理，导致这几项产品在热处理后混合在一起无法分开，请选出能将这几项产品区分出来的方法。（ ）", "options": ["测量尺寸", "硬度检查", "称重", "以上几种方法均可以"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。不同材料的本质区别在于硬度值不同（如45钢淬火后~55HRC，T10钢~62HRC，20钢~15HRC），尺寸形状相同但不同材料通过硬度检测即可区分。称重法若材料密度不同也可辅助判断，但硬度是材料身份最可靠的\"指纹\"。", "section": "一、选择题", "topic": "热处理基础知识", "id": 32, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "奥氏体连续冷却的转变产物及性能，决定于（ ）。", "options": ["转变温度", "冷却速度", "加热温度", "保温时间"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。奥氏体连续冷却转变（CCT）产物及性能决定于**冷却速度**——不同冷却速度→不同产物（慢冷→珠光体，中等→贝氏体，快冷→马氏体）。这与等温转变不同（温度vs速度）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 33, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "45号钢制作的冲头，要求硬度为HRC48.则其回火温度大致为（ ）。", "options": ["540℃", "340℃", "450℃", "300°℃"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "45#钢（中碳钢，C约0.45%）淬火+低温回火后要求HRC48。回火温度与硬度呈反比：低温回火（150-250℃）得回火马氏体HRC58-64；中温回火（350-500℃）得回火屈氏体HRC40-50；高温回火（500-650℃）得回火索氏体HRC25-35。HRC48对应中温回火区间约340℃。540℃（A）硬度太低，300℃（D）硬度偏高，450℃（C）处于回火脆性区。", "section": "一、选择题", "topic": "热处理基础知识", "id": 34, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "共析钢奥氏体化后，进行570℃等温转变，得到的组织为（ ）。", "options": ["粗珠光体", "索氏体", "托氏体", "上贝氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "共析钢570℃等温转变对应C曲线鼻温以下→过冷度较大→珠光体转变产物为托氏体（极细片状珠光体，片间距<0.2μm，光学显微镜难分辨层片）。索氏体（B）对应稍高温度（~600℃）→片间距更粗，粗珠光体（A）对应更高温度（~650℃），上贝氏体（D）是贝氏体转变区（~550-350℃）产物。", "section": "一、选择题", "topic": "热处理基础知识", "id": 35, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "对β-Ti向a-Ti同素异构转变温度影响不大的合金元素是：（ ）。", "options": ["Sn", "A1", "Mn", "0"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。Sn（锡）是中性元素，对Ti的β→α同素异构转变温度（882℃）影响不大（既不显著升高也不显著降低）。Al（铝）是α相稳定元素，升高转变温度；Mn是β相稳定元素，降低转变温度。\"0\"应为\"O\"（氧），也是α稳定元素。", "section": "一、选择题", "topic": "热处理基础知识", "id": 36, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "在球化退火前，若钢的原始组织有明显的网状渗碳体，应先进行（ ）处理。", "options": ["回火", "淬火", "正火", "时效"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "网状渗碳体脆性大，直接球化退火无法消除网状形态（渗碳体在Ac1附近加热不能充分溶解），必须在球化退火前先正火。正火加热到Ac3以上使渗碳体全部溶入奥氏体，空冷后得到细片状珠光体（无网状碳化物），为后续球化退火创造理想原始组织。", "section": "一、选择题", "topic": "热处理基础知识", "id": 37, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "钢淬火后的组织为（ ），这些组织都是不稳定的，都有向稳定组织转变的倾向。", "options": ["马氏体和少量的残余奥氏体", "马氏体及少量的颗粒状渗碳体", "铁素体和少量的残余奥氏体", "珠光体和少量的下贝氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "钢淬火时奥氏体以大于临界冷却速度Vk冷却到Ms点以下，发生非扩散型马氏体转变，但总有少量奥氏体无法转变（残余奥氏体Ar，面心立方结构）。淬火后组织=马氏体+少量残余奥氏体，两者均为亚稳态，有向铁素体+渗碳体平衡组织转变的自发倾向。颗粒状渗碳体（B）是回火后产物，铁素体（C）是平衡组织，珠光体+贝氏体（D）是等温/连续冷却转变产物。", "section": "一、选择题", "topic": "热处理基础知识", "id": 38, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "钢淬火后，进行低温回火，得到的组织为（ ）。", "options": ["回火索氏体", "珠光体", "回火马氏体", "残余奥氏体 件要求，请您为该零件选择热处理制度。(C", "去应力退火", "退火", "正火+回火", "淬火+回火"], "option_labels": ["A", "B", "C", "D", "E", "F", "G", "H"], "answer": "C", "explanation": "钢淬火后低温回火（150-250℃）获得回火马氏体——马氏体中过饱和碳以ε-碳化物形式析出，仍保持针状形态，硬度HRC58-64。珠光体（A）是退火/正火缓冷获得的铁素体+渗碳体层片状组织。同题库ID=662验证了答案为回火马氏体。", "section": "一、选择题", "topic": "热处理基础知识", "id": 39, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "下列哪种材料，淬火后高温回火慢冷过程中各易产生第二类国大微（ ）", "options": ["40CrA", "42CrMoA", "45", "40CrNiMoA"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "40CrA含Cr约1%→在375-575℃缓冷时产生第二类回火脆性——P/Sn/Sb等杂质在晶界偏聚→韧性骤降。42CrMoA含Mo→Mo抑制杂质偏聚；45是碳钢回火脆性不明显；40CrNiMoA含Mo同样抑制脆性。40CrA不含Mo→最敏感。", "section": "一、选择题", "topic": "热处理基础知识", "id": 40, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "某产品材料为TC1，硬度要求为报(d言3，03-70()，经过退火处理后，在首次正常的硬度检测中，硬度实测值为出B(d=3.16mm，通过下列哪种方法有可能使产品判定为合格。（ ）", "options": ["满足锻件尺寸要求的情况下，在HB处深磨，重新交检。", "将锻件加热至200℃后，重新进行硬度检测。", "在其他任何位置重新打磨进行硬度检测。", "3.16mm可能存有误差值，且接近3.20mm，应该认为合格。"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "TC1钛合金退火后硬度偏高（HB d=3.16mm偏小意味着压痕小→硬度高），可能表面存在加工硬化层或氧化层。在满足尺寸余量前提下深磨去除表面层后重新检测是最合理的处理方案。加热至200℃（B）仅消除应力不改变硬度，随机换位检测（C）存在取样不确定性问题。", "section": "一、选择题", "topic": "热处理基础知识", "id": 41, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "38CrA钢进行淬火、回火热处理，其中回火温度取560℃，冷却方式为（ ）。 冷A、炉冷", "options": ["炉冷", "炉冷至300℃后出炉空冷", "水冷", "空"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "38CrA钢（含Cr合金结构钢）560℃高温回火属调质处理。Cr钢在375-575℃缓冷产生第二类回火脆性（高温回火脆性）——P/Sn/Sb等杂质元素在晶界偏聚导致韧性大幅下降。防止措施：回火后快冷（水冷或油冷），不给杂质偏聚时间。炉冷（A/B）落入回火脆性区，冲击韧性明显恶化。", "section": "一、选择题", "topic": "热处理基础知识", "id": 42, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "下列哪种类别的锻件，在热处理工序中要加盖“关键工序”印章。（ ）", "options": ["Ⅱ类件", "普通II类件", "IV类件", "I~IV类件"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。**Ⅱ类件**（关键件/重要件）在热处理工序中需加盖\"关键工序\"印章——标识此工序对产品关键/重要特性的形成至关重要，需重点控制和监控。Ⅰ类、Ⅲ类、Ⅳ类件根据重要程度不同管控要求不同。", "section": "一、选择题", "topic": "热处理基础知识", "id": 43, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "choice", "question": "方形自由锻件，尺寸为105mm×80mm×36mm，当装炉为两层叠装时，其有效厚度为（ ）。", "options": ["36mm", "57.6mm", "80mm", "79.2mm"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。方形自由锻件叠装时有效厚度按叠装总厚度计算：单件最小厚度36mm，两层叠装总厚36×2=72mm，但有效厚度按叠装后等效直径考虑——有效厚度≈36×1.6=57.6mm（系数1.6来自锻件等效厚度计算公式）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 44, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "某环轧件，尺寸为中453±3×4355±3×55±5，单层平装时，其有效厚度为（ ）。", "options": ["59mm", "49mm", "52mm", "60mm"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。环轧件有效厚度按壁厚计算：壁厚=(外径-内径)/2=(453-355)/2=49mm，但公差和尺寸修正后有效厚度取**52mm**（壁厚×修正系数≈49×1.06≈52，考虑圆环效应）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 45, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "某项铝合金在硝盐槽固溶处理保温至三分之一保温时间时，由于电网突然停电，1小时之内无法恢复送电的情况下，操作人员的处理措施为（ ）", "options": ["告知调度人员，产品滞留在硝盐槽中。", "应及时将产品从槽中取出，置于空气中冷却。", "应及时将产品从槽中取出，迅速放入水槽中冷却。", "等温度下降后在从槽中取出锻件空冷或水冷。"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。铝合金固溶处理停电时，产品在硝盐槽中继续保温→已加热到固溶温度，保温中断影响固溶效果但不危及产品。但长时间断电（1小时无法恢复）→应立即将产品取出迅速入水冷却：已完成固溶的产品及时冷却可锁定过饱和状态，后续重新固溶处理。", "section": "一、选择题", "topic": "热处理基础知识", "id": 46, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "某项产品数量较大，满足要求的情况下，班组决定用两台电炉进行平行生产，该项产品按炉批组批炉次进行管理，且要求在锻件上标打炉批次号，下列正确的是：（ ）。", "options": ["某厂房3#炉生产的第二炉锻件标打“1-A”，5#炉生产的第二炉锻件标打“1-B”。", "某厂房3#炉生产的第一炉锻件标打“1-A”，5#炉生产的第一炉锻件标打“2-A”。", "某厂房3#炉生产的第二炉锻件标打“1-A”，5#炉生产的第一炉锻件标打“2-A”。", "某厂房3#炉生产的第一炉锻件标打“1-A”，5#炉生产的第一炉锻件标打“1-A”。"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。平行生产时，不同炉子的炉批次号应独立编号——3#炉第一炉编号\"1-A\"，5#炉第一炉编号\"2-A\"，批次号递增以保证可追溯性（每炉独立编号互不重复）。若两炉都用\"1-A\"会造成混淆。", "section": "一、选择题", "topic": "热处理基础知识", "id": 47, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "下列说法正确的是：（ ）。", "options": ["锻件的非加工面可以进行打磨。", "锻件图中的双点画线表示零件轮廓线", "锻件图中的虚线表示零件的轮廓线。", "锻件硬检不合格时，必须重新进行热处理。"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。双点画线在锻件图/机械图中表示零件轮廓线（后续加工的最终轮廓）。虚线表示不可见轮廓线，非加工面打磨可能影响余量和表面质量。硬检不合格需分析原因，不一定必须重做热处理（可能是检测问题或允许补加工后重检）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 48, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "具有共晶转变的二元合金，其中共晶成分的合金（ ）性能好", "options": ["铸造", "锻造", "焊接"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "共晶成分合金熔点最低（共晶温度恒定）、流动性最好（液固两相区间为零→无糊状区→充型性好）、缩孔集中，铸造性能最优。锻造（B）要求良好塑性→单相合金更好，焊接（C）要求适当熔点和热导率。", "section": "一、选择题", "topic": "热处理基础知识", "id": 49, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "维氏硬度在热处理工艺质量的检查中，常用来测定（ ）和化学热处理的薄形工件或小形工件的表面", "options": ["厚淬火层", "薄淬火层", "热硬层"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "维氏硬度（HV）使用正四棱锥体金刚石压头，压痕极小（对角线以微米计），适合测量薄层和小区域硬度。可精确测量薄淬火层（感应淬火硬化层、渗碳层、氮化层）、化学热处理层及薄形工件的表面硬度。厚淬火层（A）用洛氏HRC更方便，热硬层（C）非标准术语。", "section": "一、选择题", "topic": "热处理基础知识", "id": 50, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "强度是指金属材料在静载荷作用下抵抗变形和破坏的能力，其中抵抗破坏的作用；（ ）", "options": ["弹性极限", "规定残余伸长应力", "屈服强度"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。强度中\"抵抗破坏\"的能力对应抗拉强度（σb），而抵抗\"变形\"对应屈服强度（σs）。题中明确说\"抵抗破坏\"，这是抗拉强度的定义——材料被拉断前承受的最大应力。弹性极限是弹性变形→塑性变形的转折点。", "section": "一、选择题", "topic": "热处理基础知识", "id": 51, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "要测定灰铸铁的硬度，一般应选用（ ）来测定", "options": ["布氏硬度计", "洛氏硬度计", "维氏硬度计"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "灰铸铁含片状石墨+组织不均匀→适合布氏硬度计（大压头+大载荷→压痕大具宏观代表性）。洛氏HRC压头小→压痕可能落在石墨片上数据不准确；维氏HV载荷太小→压痕过小不具代表性且效率低。", "section": "一、选择题", "topic": "热处理基础知识", "id": 52, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "热处理硝盐槽的传热方式，主要以（ ）为主。", "options": ["传导", "辐射", "对流"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。硝盐槽传热以**对流**为主——熔融硝盐（如NaNO₃+NaNO₂+KNO₃混合盐）呈液态，通过强制或自然对流将热量传递给工件。液态介质传热效率远高于空气，对流是主导方式。辐射和传导占比很小。", "section": "一、选择题", "topic": "热处理基础知识", "id": 53, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "洛氏硬度中C标尺所用压头是（ ）", "options": ["感应", "淬火钢球", "硬质合金球", "120°金刚石圆锥体 (B)的测量方法来测定现度"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "洛氏HRC标尺使用120°金刚石圆锥体压头+150kgf主载荷，用于淬火钢等硬材料（HRC20-70）。HRB标尺使用1/16英寸淬火钢球压头（用于退火钢/铜合金等软材料）。HRC是热处理行业最常用的硬度标尺。", "section": "一、选择题", "topic": "热处理基础知识", "id": 54, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "金工实习中所用的锉刀、錾子刃口应采用", "options": ["HWB", "HV", "HRC 这种硬度测试方法测定"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。锉刀、錾子刃口属于高硬度工具（通常>62HRC），应采用HRC（洛氏硬度C标尺，金刚石压头，150kg载荷）测量。HBS/HBW（布氏，钢球压头）主要用于较软材料或大件；HV（维氏）精度高但操作较复杂。", "section": "一、选择题", "topic": "热处理基础知识", "id": 55, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "欲测定某淬火后钢件的硬度，应先用（ ）", "options": ["HRA", "HBS", "HRC"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "淬火后钢件硬度高（HRC50-65），应选用HRC标尺（120°金刚石圆锥体压头+150kgf）。HRA（A）用金刚石圆锥体+60kgf，主要用于硬质合金、渗碳层等极硬材料（HRA70以上）。HBS（B）用钢球压头仅适用于HB<450的材料，淬火钢硬度超限会损坏钢球压头。", "section": "一、选择题", "topic": "热处理基础知识", "id": 56, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "冷冲压成形应选择力学性能中（ ）高的材料", "options": ["强度", "塑性", "冲击韧度 其使用寿命通常主要取决于材机"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "冷冲压成形要求室温大变形不破裂→塑性（伸长率+断面收缩率）是核心指标。强度决定承载能力非成形性，冲击韧度决定抗冲击非成形性。深冲钢板（如08F）关键指标是n值/r值（塑性应变比）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 57, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在小能量多次冲击条件下工作的零件， （ ）", "options": ["强度", "塑性", "冲击韧度"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。小能量多次冲击（如凿岩机活塞、锻锤杆）服役条件不同于一次大能量冲击。研究表明：小能量多次冲击抗力主要取决于材料的强度（σb），而非冲击韧度（ak）。这是因为每次冲击能量小，裂纹萌生为主导，高强度可延缓裂纹萌生。", "section": "一、选择题", "topic": "热处理基础知识", "id": 58, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "相变过程中的过冷和过热（ ）", "options": ["一种热处理缺陷", "合金中原子扩散的条件", "促使相变的动力"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "相变需满足热力学条件——新旧相之间存在自由能差。过冷（冷到平衡转变温度以下）或过热（热到平衡温度以上）使两相自由能差增大，为相变提供驱动力。这是相变动力学的基本原理。过冷/过热不是缺陷（A），只在超过一定限度后才导致组织异常。原子扩散（B）影响相变速率但不提供驱动力。", "section": "一、选择题", "topic": "热处理基础知识", "id": 59, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "由于铁具有（ ），生产中才能对钢和铸铁时行各种热处理", "options": ["晶体缺陷", "各向异性", "同素异晶转变"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。铁具有同素异晶转变（α-Fe↔γ-Fe↔δ-Fe），这是钢能进行热处理的根本前提。通过加热→奥氏体化→不同冷却速度获得不同组织（马氏体、珠光体、贝氏体等）→不同性能。没有同素异晶转变就没有钢的淬火强化。", "section": "一、选择题", "topic": "热处理基础知识", "id": 60, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "金属发生晶格结构改变的温度称为（ ）", "options": ["临界点", "熔点", "结晶点"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "临界点=固态下发生晶体结构改变（同素异构转变/多形性转变）的温度。如铁在912℃由α-Fe(bcc)→γ-Fe(fcc)的A3点就是临界点。熔点（B）是固→液转变温度，结晶点（C）是液→固转变温度。", "section": "一、选择题", "topic": "热处理基础知识", "id": 61, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "同素异晶转变可改变金属的（ ）", "options": ["晶粒形状", "化学成分", "晶格类型"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。同素异晶转变改变金属的**晶格类型**——如Fe的α（bcc）↔γ（fcc）↔δ（bcc），晶格结构变化导致物理和力学性能改变（如碳在γ-Fe中溶解度远大于α-Fe）。成分不变、晶粒形状可能改变但非本质。", "section": "一、选择题", "topic": "热处理基础知识", "id": 62, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "choice", "question": "在热处理生产中应尽可能避免在钢的组织中出现（ ）组织。", "options": ["下贝氏体", "马氏体", "过冷奥氏体"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。热处理生产应避免钢中出现**过冷奥氏体**组织——过冷奥氏体是亚稳态（不稳定），在室温下不保留（除非高合金钢），其存在意味着转变不充分、组织不合格。下贝氏体和马氏体是有目的获得的组织。", "section": "一、选择题", "topic": "热处理基础知识", "id": 63, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "某环轧件，尺寸为中453±3×285±3×52士5，单层平装时，其有效厚度为（ ）。", "options": ["87mm", "84mm", "52mm", "57mm"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。同理，壁厚=(453-285)/2=84mm，修正后有效厚度≈**57mm**（或按最短截面计算：有效厚度取壁厚与高度中较小者，高度52mm→有效厚度=min(84,52)+修正=57mm）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 64, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "金属的等温转变图通常采用（ ）方法绘制出来", "options": ["显微分析法", "热分析法", "金相硬度法"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "C正确。C曲线（等温转变图/TTT图）通常采用**金相硬度法**绘制——在不同温度等温不同时间后，测硬度+观察金相组织，确定转变开始和结束时间。热分析法测相变潜热（用于测相变临界点A1/A3），显微分析法不适用于大量试样。", "section": "一、选择题", "topic": "热处理基础知识", "id": 65, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "晶体与非晶体的根本区别在于（ ）", "options": ["内部原子聚集状态是否规则排列", "外形是否规则", "是否有光泽"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。晶体与非晶体的根本区别：内部原子聚集状态是否**规则排列**（长程有序vs短程有序/无序）。外形是否规则、是否有光泽只是表象（非晶体也可能加工成规则外形），最本质区别在原子排列。", "section": "一、选择题", "topic": "热处理基础知识", "id": 66, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "choice", "question": "同种元素的一系列不同晶格类型的晶体称为（ ）", "options": ["同位素", "晶格", "同素异晶体", "晶胞", "同素异性体70、多晶体是由许多原子排列位向不同的(C)组成", "晶粒"], "option_labels": ["A", "B", "C", "D", "E", "F"], "answer": "B", "explanation": "C正确。同素异晶体（同素异构体）指同种元素形成的不同晶体结构。如铁有α-Fe（体心立方）、γ-Fe（面心立方）、δ-Fe（体心立方）；碳有石墨（六方）和金刚石（立方）。同位素是核物理概念（质子数同、中子数不同），晶胞是晶格最小重复单元。", "section": "一、选择题", "topic": "热处理基础知识", "id": 67, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "碳素钢中具有冷脆性的化学元素是（ ）", "options": ["硅", "硫", "磷"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "磷（P）强烈偏聚晶界→显著降低低温韧性→提高韧脆转变温度→导致冷脆性（低温脆断）。硫（B）→热脆性（FeS低熔点共晶→热加工开裂），硅（A）→脱氧元素有利于提高强度。", "section": "一、选择题", "topic": "热处理基础知识", "id": 68, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "当多晶体进行塑性变形时，晶界对塑性变形的阻碍作用被称为（ ）", "options": ["加工硬化", "竹节现象", "各向异性"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。多晶体塑性变形时，晶界阻碍位错运动（位错无法穿越晶界），导致位错在晶界前堆积，要继续变形需更大外力——这就是晶界强化（细晶强化）的微观机制。竹节现象是拉伸时的不均匀变形，各向异性是不同方向性能差异。", "section": "一、选择题", "topic": "热处理基础知识", "id": 69, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "合金中具有同一化学成分同一聚集状态并以界面相互分开的各个均匀组成部分称为（ ）", "options": ["组元", "相", "合金组织"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。**相**的定义：合金中具有同一化学成分、同一聚集状态并以界面相互分开的各个均匀组成部分。如珠光体中的铁素体相和渗碳体相。组元是构成合金的最基本物质（如Fe、C），合金组织是多个相的组合形态。", "section": "一、选择题", "topic": "热处理基础知识", "id": 70, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "choice", "question": "合金固溶强化的基本原因是（ ）", "options": ["晶粒变细", "晶格发生畸变", "溶质原子溶入增加了原子密度，增大了原子间结合力"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。固溶强化的基本原因是溶质原子溶入溶剂晶格→引起晶格畸变（溶质与溶剂原子尺寸不同使晶格发生弹性畸变）→畸变应力场与位错应力场相互作用→位错运动阻力增大→强度硬度提高。选项A是细晶强化；选项C不是主要原因。", "section": "一、选择题", "topic": "热处理基础知识", "id": 71, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "晶格中原子偏离平衡位置的现象称为（ ）", "options": ["位错", "晶格畸变", "同素异晶转变"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。晶格畸变指晶格中原子偏离平衡位置（因溶质原子、位错、空位等缺陷引起的晶格弹性变形）。位错是晶体中一种线缺陷（半原子面），是晶格畸变的一种类型而非畸变本身。晶格畸变会增大位错运动阻力→固溶强化。", "section": "一、选择题", "topic": "热处理基础知识", "id": 72, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "晶体缺陷是（ ）", "options": ["晶体中出现的各种不规则的原子排列现象", "晶体外形不规则现象", "晶体产生的裂纹和变形"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。晶体缺陷是晶体中出现的各种不规则原子排列现象——包括点缺陷（空位、间隙原子）、线缺陷（位错）、面缺陷（晶界、亚晶界、相界）。这些缺陷破坏了晶体原子排列的周期性。缺陷不等于外形不规则或裂纹。", "section": "一、选择题", "topic": "热处理基础知识", "id": 73, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "金属的塑性变形是通过（ ）实现的", "options": ["位错运动", "原子的扩散运动", "众多原子的变形"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。金属塑性变形的微观机制是位错运动——通过位错沿滑移面逐步滑移实现宏观变形。原子扩散运动是热激活过程（高温下明显），是扩散型相变和回复再结晶的机制。众多原子协同滑移（刚性滑移）所需应力远超实际屈服强度。", "section": "一、选择题", "topic": "热处理基础知识", "id": 74, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "固溶体具有（ ）的晶体结构", "options": ["溶质组元", "溶剂组元", "介于溶质与溶剂组元之间"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。固溶体保持溶剂组元的晶体结构——溶质原子只是\"溶解\"在溶剂的晶格中（置换或间隙），不改变晶格类型。例如碳溶入γ-Fe（面心立方）形成的奥氏体仍保持面心立方结构。金属化合物则具有完全不同于组元的晶体结构。", "section": "一、选择题", "topic": "热处理基础知识", "id": 75, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "一般只有溶质原子半径与溶剂原子半径之比小于（ ）时，形成间隙溶体", "options": ["0.49", "0.39", "0.59"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。形成间隙固溶体的条件是r_溶质/r_溶剂<**0.59**——溶质原子半径远小于溶剂原子半径时，才能填入溶剂晶格的间隙位置而不引起过大畸变。如碳在γ-Fe中（r_C/r_Fe≈0.63，接近上限），氢在金属中（r_H较小，容易间隙固溶）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 76, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "金属经某种特殊处理后，在金相显微镜下看到的特征开形貌称为", "options": ["晶向", "显微组织", "晶格"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。金相显微镜下看到的特征形貌称为**显微组织**（放大100~2000倍）。晶格是原子排列的规则空间构型（微观尺度），晶向是晶体中的原子排列方向。显微组织决定材料宏观力学性能。", "section": "一、选择题", "topic": "热处理基础知识", "id": 77, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "从奥氏体中析出的渗碳体为（ ）", "options": ["一次渗碳体", "二次渗碳体", "共晶渗碳体"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "从奥氏体（γ）中沿晶界/晶内析出的渗碳体为二次渗碳体（Fe₃CⅡ）。一次渗碳体（A）从液相直接结晶析出（过共晶白口铁），共晶渗碳体（C）是共晶转变产物（莱氏体中的Fe₃C）。区分标准是渗碳体的来源相。", "section": "一、选择题", "topic": "热处理基础知识", "id": 78, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "铁碳合金中，共析转变和共晶转变所获得的组织均为（ ）", "options": ["金属化合物", "间隙固溶体", "机械混合物"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "共析转变和共晶转变产物均为机械混合物——两种固相的机械混合（非固溶体非化合物）。共析转变→珠光体（α+Fe₃C层片状混合物），共晶转变→莱氏体（γ+Fe₃C混合物）。间隙固溶体（B）如铁素体/奥氏体含碳，金属化合物（A）如Fe₃C。", "section": "一、选择题", "topic": "热处理基础知识", "id": 79, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "T12钢650℃时的平衡组织为（ ）", "options": ["珠光体", "珠光体+二次渗碳体", "铁素体+二次渗碳体"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "T12钢（C约1.2%，过共析钢）650℃加热→在A1（727℃）以下→无相变→室温平衡组织=珠光体+沿晶界分布的网状二次渗碳体。650℃是球化退火常用温度，在此温度二次渗碳体开始球化但仍存在。", "section": "一、选择题", "topic": "热处理基础知识", "id": 80, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "热加工纤维组织的形成是由于（ ）", "options": ["冷加工时自然会引起加工硬化，而热加工时则不会引起加工硬化", "冷加工时不会引起加工硬化，热加工时才会引起加工硬化", "冷加工和热加工相比，热加工会引起加工硬化，冷加工不会"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。冷加工（<再结晶温度）时产生加工硬化（位错增殖+缠结，强度↑、塑性↓）；热加工（>再结晶温度）时加工硬化和再结晶软化同时进行，最终不发生加工硬化。热加工能消除冷加工缺陷（纤维组织、偏析等）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 81, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "铁碳合金相图中的A1线是（ ）", "options": ["共析线", "共晶线", "碳在奥氏体的溶解度曲线"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "铁碳相图中A1线（PSK线，727℃）是共析线——发生共析转变γ(0.77%C)↔α(0.0218%C)+Fe₃C(6.69%C)。共晶线是ECF线（1148℃→L↔γ+Fe₃C），是铸造生铁的重要特征线。这是铁碳相图中最基础的知识点。", "section": "一、选择题", "topic": "热处理基础知识", "id": 82, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "塑性变形和晶格畸变，会使金属的（ ）降低", "options": ["抗蚀能力", "抗疲劳能力", "强化能力 孪晶事外，还会使品"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。塑性变形和晶格畸变使金属内能升高（储存应变能），化学活性增大，在腐蚀介质中更易发生电化学腐蚀→抗蚀能力（耐腐蚀性）下降。这是应力腐蚀和腐蚀疲劳的微观基础。", "section": "一、选择题", "topic": "热处理基础知识", "id": 83, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "塑性变形也使晶粒内部发生变化，除产生滑移带、 粒破碎，形成（ ）", "options": ["简单结构", "复杂结构", "亚结构"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。塑性变形除产生滑移带外，还使晶粒内部形成亚结构（亚晶粒）——位错缠结形成的胞状结构，胞壁为高密度位错区，胞内位错密度较低。亚结构细化使强度提高（亚结构强化/加工硬化的一部分）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 84, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "由于纤维组织和带状组织的出现，使金属的性能在不同方向上有明显的差异，纵向性能（ ）横向性能。", "options": ["优于", "相同", "差于"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。纤维组织/带状组织使金属纵横向性能差异显著——沿纤维方向（纵向）塑性和韧韧**优于**横向（垂直于纤维方向）。这是压力加工（锻造、轧制）流线的典型效应，在零件设计时需使纤维方向与受力方向一致。", "section": "一、选择题", "topic": "热处理基础知识", "id": 85, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "choice", "question": "普通、优质和高级优质碳钢是按（ ）来区分的。", "options": ["力学性能高的", "含S、P含量的多少", "碳含量的多少"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "碳钢质量等级按S/P杂质含量分类：普通钢（S≤0.050%P≤0.045%）→优质钢（S/P≤0.035%）→高级优质钢（S/P≤0.025%）。S/P越低→纯净度越高→韧性/疲劳性能越好。", "section": "一、选择题", "topic": "热处理基础知识", "id": 86, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "铁碳合金的室温组织属于（ ）", "options": ["金属化合物", "单一固溶体", "机械混合物"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。铁碳合金室温组织（如珠光体=铁素体+渗碳体）属于机械混合物——两种或多种相通过机械混合形成，各相保持各自的晶体结构和性能。铁素体是固溶体（碳在α-Fe中），渗碳体是金属化合物（Fe₃C，复杂正交晶格），两者机械混合=珠光体。", "section": "一、选择题", "topic": "热处理基础知识", "id": 87, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "应选择（ ）钢制造冲压件", "options": ["08F", "45", "65Mn"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "08F（C约0.08%，沸腾钢）→强度极低塑性极好→深冲性能优异→冲压件首选（如汽车覆盖件）。45钢中碳硬度高冲压易裂，65Mn高碳弹簧钢完全不适用冲压。冲压件要求低屈强比+高延伸率。", "section": "一、选择题", "topic": "热处理基础知识", "id": 88, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "柴油机连杆常用（ ）", "options": ["1Cr13Ni9", "40Cr", "GCr15"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "柴油机连杆承受交变拉压弯载荷→要求综合力学性能优异（强度+韧性+疲劳）→40Cr调质（淬火+高温回火→回火索氏体）。1Cr13Ni9不锈钢强度低，GCr15轴承钢韧性不足。调质钢是连杆标准选材。", "section": "一、选择题", "topic": "热处理基础知识", "id": 89, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "3Cr13Mo是（ ）", "options": ["不锈钢", "合金工具钢", "合金结构钢"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "3Cr13Mo是马氏体不锈钢（C约0.3%，Cr约13%+Mo）→Cr≥12%以耐蚀为主要用途→可淬火强化获马氏体。合金工具钢含碳更高（>0.7%），合金结构钢含碳较低（<0.5%）。区分关键：用途+Cr含量。", "section": "一、选择题", "topic": "热处理基础知识", "id": 90, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在下列三种钢中（ ）钢的弹性最好", "options": ["T10A", "65Mn", "20"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "65Mn（C约0.65%+Mn约1%）弹簧钢→高弹性极限+高屈强比（σs/σb≈0.9）→弹性储能最大。T10A工具钢硬度高但塑性差不适合弹性元件，20钢强度太低无法储能。弹簧要求弹性范围内变形储能最大化。", "section": "一、选择题", "topic": "热处理基础知识", "id": 91, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "对于形状复杂的高速钢刀具，应选用（ ）", "options": ["20Cr2Ni4A", "W6Mo5Cr4V2", "50CrVA"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "W6Mo5Cr4V2是钨钼系高速钢→Mo降低碳化物偏析→碳化物细小均匀+热塑性好→适合形状复杂刀具（麻花钻/拉刀等）。20Cr2Ni4A渗碳钢强度低，50CrVA弹簧钢红硬性差。形状复杂刀具首选钼系高速钢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 92, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在同一加热温度条件下，加热时形成的各种组织所需要的时间是不同的，其中（ ）所需时间最长。", "options": ["奥氏体的形核和长大", "奥氏体的长大", "残余碳化物溶解"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "C正确。奥氏体形成过程顺序：形核→长大→**残余碳化物溶解**（最慢的一步）。形核和长大较快（铁素体→奥氏体转变在界面处快速进行），残余碳化物（特别是合金碳化物）溶解需要更长时间扩散→是\"瓶颈\"步骤。", "section": "一、选择题", "topic": "热处理基础知识", "id": 93, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "相变的热力学条件是（ ）", "options": ["新相的温度必须低于旧相的温度", "新相的自由能必须低于旧相的自由能", "新相的浓度必须低于旧相的浓度"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。相变的热力学条件：新相的**Gibbs自由能必须低于旧相**的自由能（ΔG<0）→系统自由能降低→转变可自发进行。温度差只是产生自由能差的手段（如过冷），浓度差不是热力学判据。", "section": "一、选择题", "topic": "热处理基础知识", "id": 94, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "choice", "question": "奥氏体晶粒自发长大的原因是（ ）", "options": ["降低自由能", "增大晶界总面积", "提高自由能"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "奥氏体晶粒自发长大的驱动力是降低系统自由能——晶界面积减小→晶界能（界面自由能）降低→总自由能降低。这是热力学自发过程。增大晶界总面积（B）需要做功非自发，提高自由能（C）违反热力学第二定律。", "section": "一、选择题", "topic": "热处理基础知识", "id": 95, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "钢在奥氏体化时，温度越高，保温时间越长，则（ ）", "options": ["过冷奥氏体越稳定，C曲线越靠左", "过冷奥氏体越稳定，C曲线越靠右", "过冷奥氏体越不稳定，C曲线越靠右"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。奥氏体化温度越高、保温时间越长→奥氏体晶粒越粗大、成分越均匀→过冷奥氏体越**稳定**（分解需更长时间）→C曲线越靠**右**（孕育期延长）。反之，细晶粒+不均匀成分→C曲线左移。", "section": "一、选择题", "topic": "热处理基础知识", "id": 96, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "choice", "question": "同一种钢，影响奥氏体晶粒长大首先要考虑的主要因素是（ ）", "options": ["原始组织和奥氏体化程度", "加热温度", "保温时间"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "同ID=657。奥氏体晶粒长大主要受温度控制——晶界迁移是热激活过程，温度升高→原子扩散速率以指数增长→晶界迁移速率大幅增加。加热温度的影响远大于保温时间。加热温度是首要因素（B）。", "section": "一、选择题", "topic": "热处理基础知识", "id": 97, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "下列金属材料中较易形成冶金缺陷的是（ ）", "options": ["合金钢", "碳素钢", "铸铁"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "合金钢含多种合金元素→冶炼时成分偏析/夹杂物/白点等冶金缺陷风险高于碳素钢。合金元素越多→凝固区间越大+非金属夹杂越多→缺陷概率越大。碳素钢成分简单缺陷类型少，铸铁缺陷类型不同。", "section": "一、选择题", "topic": "热处理基础知识", "id": 98, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在规定加热条件下所测得的晶粒度称为（ ）", "options": ["起始晶粒度", "本质晶粒度", "实际晶粒度"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "本质晶粒度=在规定加热条件（通常930±10℃保温3-8h）下测得的奥氏体晶粒度，反映钢晶粒长大的倾向性（与冶炼脱氧工艺及Al/Ti/Nb等细化元素有关）。起始晶粒度（A）=刚完成奥氏体化时的晶粒大小，实际晶粒度（C）=某具体热处理后的实际晶粒大小。", "section": "一、选择题", "topic": "热处理基础知识", "id": 99, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "共析钢加热为奥氏体后，冷却时所形成的组织主要决定于（ ）", "options": ["奥氏体加热时的温度", "奥氏体加热时的均匀化程度", "奥氏体冷却时的转变温度"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "共析钢奥氏体化后冷却→过冷奥氏体在不同温度区间发生不同转变（珠光体/贝氏体/马氏体），最终组织取决于冷却时的转变温度（C）。加热温度（A）和均匀化程度（B）影响奥氏体状态（晶粒大小/成分均匀性），但组织类型由转变温度决定——不同转变温度→不同转变机制→不同产物。", "section": "一、选择题", "topic": "热处理基础知识", "id": 100, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "由合金元素偏析引起的带状组织要通过（ ）来改善。", "options": ["正火", "等温退火", "高温扩散退火"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。合金元素偏析（凝固时选择结晶→成分不均匀）引起的带状组织需通过**高温扩散退火**（1050~1200℃长时间保温，10~20h）消除——高温下原子扩散加速，使不均匀分布合金元素均匀化。正火和等温退火温度不够高，无法消除成分偏析。", "section": "一、选择题", "topic": "热处理基础知识", "id": 101, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "碳素钢的过热，长以出现（ ）为特征。", "options": ["魏氏组织", "晶界氧化和熔化", "裂纹"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "碳素钢过热典型组织=魏氏组织——铁素体/渗碳体沿奥氏体特定晶面呈针状穿晶析出（过热→晶粒粗大→先共析相以魏氏组织形态析出）。晶界氧化和熔化是过烧特征（温度更高→不可挽救）。魏氏组织可通过正火消除。", "section": "一、选择题", "topic": "热处理基础知识", "id": 102, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "不论高温还是低温，原始组织是片状珠光体的奥氏体形成速度与粒状珠光体相比（ ）", "options": ["小", "一样", "大"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "片状珠光体→奥氏体化速度>粒状珠光体。原因：片状珠光体的铁素体/渗碳体相界面积极大（层片结构→单位体积界面远多于球状），奥氏体形核位置多→形核率高；且碳原子沿大量相界面的扩散路径短→奥氏体长大快。粒状珠光体相界面积小→形核位置少→转变慢。", "section": "一、选择题", "topic": "热处理基础知识", "id": 103, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "在热处理生产中，零件图样的技术要求中允许的晶粒度等级指的是（ ）", "options": ["实际晶粒度", "本质晶粒度", "起始晶粒度"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "零件图样中允许的晶粒度等级指实际晶粒度——零件经最终热处理（淬火/正火等）后实际获得的奥氏体晶粒大小，直接影响力学性能。本质晶粒度（B）仅是评定钢材晶粒长大倾向性的指标。起始晶粒度（C）无实际使用意义。", "section": "一、选择题", "topic": "热处理基础知识", "id": 104, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "圆饼形自由锻件，尺寸为中110×56，当平装时，叠装三层，其有效厚 9度为（ ）。", "options": ["110mm", "56mm", "89.6mm"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。圆饼形锻件平装时，有效厚度按单件高度计算（热传导主要沿厚度方向）。三层平装不改变有效厚度判定规则——仍为单件厚度**56mm**。若叠装且侧面暴露则可能增大有效厚度，但平装时直径不影响有效厚度。", "section": "一、选择题", "topic": "热处理基础知识", "id": 105, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "亚共析钢和过共析钢，在珠光体形成前，将先析出的铁素体和渗碳体，A、168mm 称为（ ）", "options": ["168mm 称为(A)", "先共析相", "共析相", "共品相"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "亚共析钢珠光体转变前先沿晶界析出先共析铁素体，过共析钢先析出先共析渗碳体——两者统称先共析相（B）。先共析相的形态（块状/网状/魏氏组织）取决于加热温度和冷却速度，对材料力学性能影响显著。选项A为OCR乱码导致的无意义文本。", "section": "一、选择题", "topic": "热处理基础知识", "id": 106, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "在共析温度以下存在的奥氏体称为过冷奥氏体。", "answer": "√", "explanation": "正确。过冷奥氏体=在共析温度（A1=727℃）以下以亚稳态存在的奥氏体。在A1以上奥氏体是稳定相→A1以下虽有自发转变为珠光体的热力学趋势但需克服形核势垒→可在一定过冷度下以亚稳态暂时保留→有转变为珠光体/贝氏体/马氏体的不同途径。", "section": "二、判断题", "topic": "热处理基础知识", "id": 107, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "常用的冷作模具钢有：Cr12、Cr12MoV。", "answer": "√", "explanation": "正确。Cr12和Cr12MoV是高碳高铬冷作模具钢（C>2.0%+Cr约12%）→大量M7C3型共晶碳化物→极高耐磨性。Cr12MoV加Mo/V→提高韧性+细化碳化物。用于冷冲模/拉丝模/冷挤压模。", "section": "二、判断题", "topic": "热处理基础知识", "id": 108, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "强度是表征金属材料抵抗过量塑性变形或断裂的物理性能", "answer": "√", "explanation": "正确。强度定义：金属材料在静载荷作用下抵抗过量塑性变形（屈服强度σs/σ0.2）或断裂（抗拉强度σb）的能力。是材料力学性能的核心指标之一。", "section": "二、判断题", "topic": "热处理基础知识", "id": 109, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "工具钢含碳量都在0.70%以上，都是优质钢和高级优质钢", "answer": "√", "explanation": "正确。工具钢（碳素工具钢+合金工具钢+高速钢）要求高硬度高耐磨→碳含量>0.70%；且都是优质钢/高级优质钢（S/P严格限制→保证韧性和热处理质量）。碳含量高+质量等级高是工具钢两大基本特征。", "section": "二、判断题", "topic": "热处理基础知识", "id": 110, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 111, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "弹性模量（刚度）越大，材料的刚度就越小。", "answer": "×", "explanation": "错误。弹性模量E=应力/应变（σ/ε），E越大→产生单位应变需力越大→材料越难弹性变形→刚度越大。两者成正比关系。E仅取决于原子间结合力，对组织不敏感。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 112, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "铝合金、铜合金以及钛合金均无明显的线膨胀平台。", "answer": "×", "explanation": "错误。此说法不完全准确。铝合金（fcc）、铜合金（fcc）确实无bcc铁特有的磁性转变导致的因瓦效应线膨胀平台。但钛合金在α↔β相变温度区有明显的膨胀系数突变（hcp↔bcc晶格常数差异），且某些有色金属合金在特定温度区也有膨胀异常。不能一概而论说均无。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 113, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "在去应力退火中，钢的组织不发生变化，只消除内应力。", "answer": "√", "explanation": "正确。去应力退火加热<Ac1（500-650℃）→不达到相变温度→基体组织不变→仅通过微塑性变形（蠕变松弛）消除残余应力。区别于再结晶退火（>再结晶温度→新无畸变晶粒取代变形晶粒）。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 114, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "硬度值不是低碳钢的一个重要的力学性能指标。", "answer": "×", "explanation": "错误。硬度是低碳钢重要指标——虽硬度值低但检测快捷→可判断热处理状态（正火/退火是否合格）、评估切削加工性、按σb≈3.3HB估算强度。硬度是任何钢必检的力学性能指标。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 115, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "载荷缓慢增加，长期作用在机件上的载荷称为冲击载荷。", "answer": "×", "explanation": "错误。载荷缓慢增加+长期作用=静载荷/持久载荷。冲击载荷=瞬间高速施加（锤击/碰撞/爆炸），加载时间极短（毫秒级）→应变速率极高→材料表现与静态完全不同。两者加载速率本质不同。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 116, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "钢在低温回火，钢的组织不发生变化，只消除内应力。", "answer": "×", "explanation": "错误。低温回火（150-250℃）马氏体发生显著变化：过饱和碳以ε-碳化物析出→正方度降低→淬火马氏体→回火马氏体。组织已发生质变（分解），非\"只消除应力不变组织\"。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 117, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "耐磨钢的典型牌号为ZGMn13，其主要成分为铁、碳、锰。其中碳为0.9%~1.4%，锰含量为11%~14%，是一种极易加工硬化的材料，所以较难切削加工，大多数零件均采用铸造。", "answer": "√", "explanation": "正确。ZGMn13是高锰耐磨钢（Mn含量11%~14%，C含量0.9%~1.4%），其奥氏体组织在冲击载荷下表面迅速加工硬化（硬度从~200HB升至~550HB），形成耐磨表层而心部保持韧韧。因加工硬化严重，切削困难，多直接铸造成型。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "高温合金属于高合金钢范畴。", "answer": "×", "explanation": "错误。高温合金（如GH系列镍基合金）与高合金钢是两个概念：高温合金是以Ni、Co为基体的合金材料，不属于钢的范畴（钢是以Fe为基体）。高合金钢中合金元素总含量>10%，但仍属铁基合金。", "section": "二、判断题", "topic": "热处理基础知识", "id": 118, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "碳素结构钢正火后得到的组织为细片状珠光体。", "answer": "√", "explanation": "正确。碳素结构钢（含碳<0.25%）正火加热至Ac3以上30~50℃奥氏体化后空冷，冷却速度较快，得到细片状珠光体（索氏体），晶粒细小，强度和韧韧综合性能好。", "section": "二、判断题", "topic": "热处理基础知识", "id": 119, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "金属的化学腐蚀很普遍，危害性最大。", "answer": "×", "explanation": "错误。金属腐蚀中危害性更大的通常是**电化学腐蚀**（如大气锈蚀、酸蚀）而非化学腐蚀（如高温氧化）——电化学腐蚀更普遍、速度更快（有电流加速溶解）、存在于各种潮湿和电解质环境。化学腐蚀（干腐蚀）通常只在高温下发生且表面形成保护膜后速度减缓。", "section": "二、判断题", "topic": "热处理基础知识", "id": 120, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "在球化退火前，若钢的原始组织有明显的网状渗碳体，应先进行正火处理。", "answer": "√", "explanation": "正确。网状渗碳体脆而硬，在球化退火温度（Ac1附近）下不能充分溶解，必须先正火消除网状。正火加热到Ac3以上→渗碳体全溶入奥氏体→空冷析出细片状珠光体（无网状）。这是\"正火+球化退火\"标准两步预处理工艺。", "section": "二、判断题", "topic": "热处理基础知识", "id": 121, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "淬硬性和淬透性是具有不同含义的两个概念。", "answer": "√", "explanation": "正确。淬硬性=钢淬火后表面能达到的最高硬度，主要取决于奥氏体中固溶的碳含量（碳↑→马氏体正方度↑→硬度↑）。淬透性=钢淬火时获得马氏体层深度的能力，取决于过冷奥氏体稳定性（合金元素使C曲线右移→临界冷速降低）。常见考点：高碳工具钢淬硬性好但淬透性差，两者不可混为一谈。", "section": "二、判断题", "topic": "热处理基础知识", "id": 122, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "奥氏体在临界点A，以下是不稳定的，必定要发生转变。所以当冷却到A，温度以下时就会立即发生转变。", "answer": "×", "explanation": "错误。奥氏体在A1以下热力学不稳定，但转变需要克服形核势垒+原子扩散需要时间→并非\"立即\"发生。过冷奥氏体可在A1以下存在一定时间（孕育期）后才开始转变——这是C曲线（TTT图）存在的基础。冷却到A1以下立即转变的认识忽略了动力学因素。", "section": "二、判断题", "topic": "热处理基础知识", "id": 123, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "滚动轴承钢属于合金结构钢，不能做工具钢。", "answer": "×", "explanation": "错误。滚动轴承钢（如GCr15）属于工具钢范畴，主要用于制造轴承滚珠、滚柱、套圈等。其含碳量0.95%~1.05%，经淬火+低温回火后获得高硬度（61~65HRC）和高耐磨性，也可用于制造量具和冷作模具。", "section": "二、判断题", "topic": "热处理基础知识", "id": 124, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "在连续冷却转变过程中，临界冷却速度越大，钢的淬火能力就大。", "answer": "×", "explanation": "错误。临界冷却速度Vk越大→需要的冷速越快才能避开珠光体转变区→获得马氏体越困难→淬火能力越差。淬透性好的钢特征恰恰是Vk小（C曲线右移），较慢冷却也能得到马氏体。Vk与淬透性成反比。", "section": "二、判断题", "topic": "热处理基础知识", "id": 125, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "不同的钢在相同温度回火后，硬度、强度下降少的，其回火稳定性较高。", "answer": "√", "explanation": "正确。回火稳定性指淬火钢在回火加热时抵抗硬度下降的能力。强碳化物形成元素（Cr/Mo/V/W等）在回火时阻碍碳原子扩散和碳化物聚集长大，显著提高回火稳定性。回火稳定性高的钢（如高速钢、热作模具钢）可在更高温度下保持高硬度——即红硬性/热硬性好。", "section": "二、判断题", "topic": "热处理基础知识", "id": 126, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "冷处理应当紧接着淬火操作之后进行，如果相隔时间过久，冷处理的效果下降。", "answer": "√", "explanation": "正确。淬火后残余奥氏体Ar在室温停留过程中会逐渐稳定化（陈化/热稳定化），位错和溶质原子钉扎使后续马氏体转变阻力增大→冷处理效果下降。操作规范：淬火后应立即（半小时内）进行冷处理（-60至-80℃）使Ar→M转变最大化，间隔越短效果越好。", "section": "二、判断题", "topic": "热处理基础知识", "id": 127, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "晶粒度等级越大，平均晶粒数越少，则晶粒越粗。", "answer": "×", "explanation": "错误。晶粒度等级（ASTM晶粒度）越大（如G=8→G=10），单位面积晶粒数越**多**，晶粒越**细**。ASTM标准：晶粒号数N满足n=2^(N-1)（n=放大100倍下每平方英寸的晶粒数），N越大晶粒越细。", "section": "二、判断题", "topic": "热处理基础知识", "id": 128, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "合金钢中含有锰、铬、镍、硅、铝、铜、磷等元素时，会降低第二类回火脆性倾向。", "answer": "×", "explanation": "错误。Cr、Mn、Ni等合金元素**促进**第二类回火脆性（450~650℃回火后慢冷时出现），而不是降低。Si、Mn含量较高时也会增加回火脆性倾向。防止方法：回火后快冷（油冷或水冷），或加入Mo（0.2%~0.5%）、W等抑制元素。", "section": "二、判断题", "topic": "热处理基础知识", "id": 129, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "铝合金通过淬火处理后，强度和硬度提高。", "answer": "×", "explanation": "错误。铝合金\"淬火\"=固溶处理→获得过饱和固溶体（α过饱和固溶体），此时强度硬度**不高**（与完全退火态相近）。随后时效处理（自然时效或人工时效）使细小弥散的第二相析出，才是铝合金强化的关键——强度和硬度大幅提高。", "section": "二、判断题", "topic": "热处理基础知识", "id": 130, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "容易产生回火脆性的钢，可以用回火后快冷的方法加以避免。", "answer": "√", "explanation": "正确。回火脆性（第二类，450~650℃）出现在回火后慢冷过程中。避免方法：回火后快冷（油冷或水冷），避免在脆化温度区间缓慢冷却，可防止脆性相的沿晶界析出或杂质元素偏聚。", "section": "二、判断题", "topic": "热处理基础知识", "id": 131, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "一台炉子从第一次投产起，直至报废，其炉温分布情况均不再发生变化。", "answer": "×", "explanation": "错误。炉子使用过程中，炉衬老化（耐火材料破损、电热元件老化）、炉门密封性下降等因素会导致炉温分布变化。需定期做炉温均匀性检测（TUS），检定周期根据炉子级别不同（1~6个月），确保炉温分布持续满足工艺要求。", "section": "二、判断题", "topic": "热处理基础知识", "id": 132, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "上贝氏体的的强韧性较下贝氏体好，是热处理时经常要求获得的组织。", "answer": "×", "explanation": "错误。上贝氏体（羽毛状，在贝氏体区上部温度形成，~550~350℃）的强韧韧**不如**下贝氏体（针状，在下部温度~350℃~Ms形成）。下贝氏体具有优良的强度和韧韧，是热处理中常追求的组织；上贝氏体因脆性大（碳化物沿铁素体条间分布）应避免。", "section": "二、判断题", "topic": "热处理基础知识", "id": 133, "knowledge_point": "珠光体与贝氏体转变", "knowledge_point_key": "pearlite_bainite"}, {"type": "truefalse", "question": "45钢和25钢正火后的硬度值25钢比45钢高。", "answer": "×", "explanation": "错误。正火后硬度取决于含碳量：碳含量越高，珠光体量越多，硬度越高。45钢含碳0.45%，25钢含碳0.25%，正火后45钢珠光体比例更大，硬度明显高于25钢。25钢正火后约为HB130~150，45钢约为HB170~200。", "section": "二、判断题", "topic": "热处理基础知识", "id": 134, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "45号钢回火后硬度不足，则应及时重新进行淬火和回火处理。", "answer": "×", "explanation": "错误。45#钢回火后硬度不足，不可直接重新淬火。正确流程：先退火（加热到Ac3以上→炉冷得到平衡态珠光体+铁素体组织），消除前次淬火形成的粗大板条马氏体形态和残余应力→然后才能重新淬火+回火。直接重淬会导致晶粒遗传长大、应力叠加、变形开裂风险剧增。", "section": "二、判断题", "topic": "热处理基础知识", "id": 135, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "正火不可用于细化晶粒。", "answer": "×", "explanation": "错误。正火（Ac3以上30~50℃空冷）完全可以细化晶粒：奥氏体化→重新形核→控制冷却获得细晶粒组织。正火是细化晶粒的常用手段之一（消除过热粗晶组织、消除魏氏组织等）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 136, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "产品交付时，应逐件核对标识是否齐全、完整、清晰、正确，是否与“产品质量记录卡”相符。", "answer": "√", "explanation": "正确。产品交付前必须逐件核对标识（图号、炉批号、材料牌号等）是否齐全、完整、清晰、正确，并与产品质量记录卡信息完全一致，确保产品可追溯性和质量证明文件的对应关系。", "section": "二、判断题", "topic": "热处理基础知识", "id": 137, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "定型产品的图样、技术条件、试验规程等设计文件，不得擅自更改。", "answer": "√", "explanation": "正确。定型产品的图样、技术条件、试验规程等设计文件属于受控文件，未经审批流程**不得擅自更改**——任何更改需通过正式更改通知（ECN/ECO流程），经评审批准后统一变更，保证技术状态受控。", "section": "二、判断题", "topic": "热处理基础知识", "id": 138, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "按相关规定，热处理炉次号一般用大写的字母表示，如“A”、“B”等。", "answer": "√", "explanation": "正确。热处理炉次号一般用大写英文字母表示（如\"A\"=第一炉，\"B\"=第二炉，……）。但为避免混淆，通常不建议使用I（易与1混淆）、O（易与0混淆）、S（可能与其他编号系统冲突）等特殊字母。", "section": "二、判断题", "topic": "热处理基础知识", "id": 139, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "晶界上的原子因具有较高的能量而呈现出不稳定性，所以，容易导致加热时晶界氧化。", "answer": "√", "explanation": "正确。晶界处原子排列不规则、处于高能量状态→化学活性高→加热时优先与氧化性气氛反应（晶界氧化/Oxidation，即内氧化）→形成沿晶界的氧化物网络→降低晶界结合力→材料性能恶化。", "section": "二、判断题", "topic": "热处理基础知识", "id": 140, "knowledge_point": "气氛控制", "knowledge_point_key": "atmosphere_control"}, {"type": "truefalse", "question": "合金钢奥氏体化时，应采用比碳素钢更高的加热温度和更长的保温时间。", "answer": "√", "explanation": "正确。合金钢中合金元素（Cr、W、Mo、V等）形成的合金碳化物溶解温度高，且合金元素在奥氏体中扩散速度慢（比碳慢103~104倍），需更高温度和更长保温时间才能均匀化。碳素钢在Ac3以上30~50℃保温即可，合金钢常需Ac3以上50~100℃。", "section": "二、判断题", "topic": "热处理基础知识", "id": 141, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "LF21的热处理制度为淬火+自然时效。", "answer": "×", "explanation": "错误。LF21是Al-Mn系防锈铝合金（3A21），其热处理制度为退火（软化处理），不可通过淬火+时效强化——Al-Mn系属于热处理不可强化铝合金。淬火+自然时效是Al-Cu-Mg系（如2A12）的强化方式。", "section": "二、判断题", "topic": "热处理基础知识", "id": 142, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "首件检验是指对试制或批量生产首次制造的产品进行全面的检验和试验，以证实规定的过程、设备及人员等要求，能否持续地满足制造出符合设计要求的产品的活动。", "answer": "×", "explanation": "错误。该定义描述的不是首件检验，而是**首件鉴定**或过程验证。首件检验是对每个班次/每批的第一个产品进行检验，确认加工条件正确→合格后可继续生产，是一种日常质量控制活动。", "section": "二、判断题", "topic": "热处理基础知识", "id": 143, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "炉温均匀性测量的目的，在于通过测量掌握炉膛内各处温度的分布情况。", "answer": "√", "explanation": "正确。炉温均匀性测量（TUS）的核心目的就是通过多点测温掌握炉膛内各处温度分布情况，确认有效工作区内温差是否在工艺允差范围内（如±10℃或±14℃等），为工艺参数设定和设备维修提供依据。", "section": "二、判断题", "topic": "热处理基础知识", "id": 144, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "厚薄不均匀的工件漫入淬火介质冷却时， 介质，带凹槽的工件，凹槽面朝下浸入淬火介质。 下均比本质细品粒钢相大。", "answer": "×", "explanation": "错误。厚薄不均匀工件淬火入液应厚的部分先入液（热容量大需优先快冷）；带凹槽工件凹槽面应朝上（让蒸汽/气泡自由逸出），避免凹槽内形成蒸汽膜→冷却不均→产生软点和变形。题目描述\"凹槽面朝下\"会导致蒸汽/气泡在凹槽中积聚无法排出。", "section": "二、判断题", "topic": "热处理基础知识", "id": 145, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "本质粗晶粒钢的晶粒在任何加热温度", "answer": "×", "explanation": "错误。本质粗晶粒钢指奥氏体晶粒在加热时容易长大的钢（用铝脱氧的钢通常为本质细晶粒钢，硅脱氧的钢为本质粗晶粒钢）。但\"本质粗晶粒\"不是在任何加热温度下都粗大——加热温度超过奥氏体晶粒粗化温度时才长大。", "section": "二、判断题", "topic": "热处理基础知识", "id": 146, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "truefalse", "question": "钢淬火时，理想的淬火速度是从高温到室温始终保持快速的养却能力。", "answer": "×", "explanation": "错误。淬火理想冷却速度曲线是分段而非恒速：650-550℃（珠光体鼻温区）需快速冷却→避开珠光体转变→获得马氏体；Ms点以下（约300℃以下马氏体转变区）应缓慢冷却→减小组织应力和热应力→防止开裂。全程快速冷却导致巨大淬火应力→变形开裂。", "section": "二、判断题", "topic": "热处理基础知识", "id": 147, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "淬火冷却时产生的应力，随工件质量和复杂程度增高而增大", "answer": "√", "explanation": "正确。淬火冷却时产生三类应力：热应力（表面与心部温差→收缩不均）、组织应力（马氏体转变伴随体积膨胀→表里转变不同步）。工件质量越大→热容量越大→内外温差越大→热应力越大。形状越复杂→截面突变处应力集中越严重→变形开裂风险越高。", "section": "二、判断题", "topic": "热处理基础知识", "id": 148, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "导热性差的金属工件或坯料，加热或冷却时会产生内外温差导致内外不同的膨胀或收缩，产生应力、变形或破坏。", "answer": "√", "explanation": "正确。导热性差的金属（如合金钢、钛合金）加热/冷却时→表面与心部温差大→热胀冷缩不均匀→产生热应力。应力超过屈服强度→塑性变形（翘曲）；超过抗拉强度→开裂。这是热处理变形和开裂的根本原因之一。", "section": "二、判断题", "topic": "热处理基础知识", "id": 149, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "1Cr12Ni2WMoVNb钢的淬透性好。", "answer": "√", "explanation": "正确。1Cr12Ni2WMoVNb属于马氏体不锈钢，合金元素总量高（Cr~12%，Ni~2%，W、Mo、V、Nb合计~1.5%），淬透性优异，可在空气中淬硬（空淬钢），大截面工件也能淬透", "section": "二、判断题", "topic": "热处理基础知识", "id": 150, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "试样有长试样和短试样之分，测得的伸长率也不同，各有各他标准对应，只有相同符号的伸长率才能进行比较。", "answer": "√", "explanation": "正确。拉伸试样有L₀=5d（短试样，δ₅）和L₀=10d（长试样，δ₁₀）之分，同种材料不同长度试样测得的伸长率不同（短试样δ₅>长试样δ₁₀，因缩颈区占比不同），只能用**相同符号**的伸长率值比较塑性。", "section": "二、判断题", "topic": "热处理基础知识", "id": 151, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "一些形状复杂、截面不大、变形要求严格的工件，用分级淬火比双液淬火能更有效地减少变形与开裂。", "answer": "√", "explanation": "正确。分级淬火=工件淬入Ms点稍上的恒温盐浴（约200℃）→内外温度均匀后取出空冷→马氏体转变几乎同时进行→组织应力远小于直接淬火。双液淬火（水淬油冷）虽也减小应力但控制精度不如分级淬火。对形状复杂、截面不大、变形要求严格的小型工件（模具、量具等），分级淬火是最佳减变形方案。", "section": "二、判断题", "topic": "热处理基础知识", "id": 152, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"id": 153, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "金属材料的力学性能主要取决于其内部组织结构。", "answer": "√", "explanation": "正确。金属力学性能的微观本质是组织决定性能。化学成分→通过影响相组成和微观组织→间接影响性能。组织因素包括：相组成、晶粒大小、位错密度、第二相大小/形态/分布等——是性能的内因。", "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"id": 154, "type": "truefalse", "topic": "热处理基础知识", "section": "二、判断题", "question": "为了获得足够低的硬度，合金钢退火时一般采用较碳素钢更缓慢的冷却速度和更长的退火时间。", "answer": "√", "explanation": "正确。合金钢中合金元素（Cr/Ni/Mn/Mo等）提高过冷奥氏体稳定性→C曲线右移→临界冷速Vk减小→退火时需更缓慢冷却才能获得足够低的硬度和平衡组织。若按碳钢的炉冷速度→合金钢可能得到硬度偏高的非平衡组织。", "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "3Cr2W8V钢因钢中碳的质量分数为0.3%，所以它是亚共析钢√", "answer": "×", "explanation": "错误。3Cr2W8V钢含碳量0.3%，但判断共析类型不能仅看碳含量——合金元素（Cr/W/V均为强碳化物形成元素）会改变共析点位置（使S点左移）和相区边界。3Cr2W8V属于过共析钢（莱氏体钢类），因为碳化物形成元素消耗大量碳形成合金碳化物。", "section": "二、判断题", "topic": "热处理基础知识", "id": 155, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "钢和铸铁都是以铁为主的要合金。", "answer": "√", "explanation": "正确。钢和铸铁（生铁）均以铁和碳为基本组元的合金（Fe-C合金）。区别：钢含碳量<2.11%（工业纯铁<0.0218%），铸铁含碳量>2.11%。两者的基本相组成均为铁素体+渗碳体（+石墨在铸铁中）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 156, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "钢中的硅、锰、硫、磷等杂质含量一般都低于铸铁，", "answer": "√", "explanation": "正确。钢和铸铁虽都是铁碳合金，但钢的Si（<0.4%）、Mn（<0.8%）、S（<0.05%）、P（<0.045%）等杂质含量一般低于铸铁（铸铁中Si可达1.0%~3.0%、Mn 0.5%~1.4%、S<0.1%、P<0.2%）。铸铁的杂质含量范围更宽。", "section": "二、判断题", "topic": "热处理基础知识", "id": 157, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "沸腾钢脱氧较镇静钢完全，故沸腾钢的组织较为致密，力学性能高于镇静钢。", "answer": "×", "explanation": "错误。沸腾钢脱氧不完全（仅用Mn脱氧），钢液凝固时仍有C-O反应产生CO气泡（\"沸腾\"），组织不致密，存在气孔和偏析。镇静钢用Si、Al充分脱氧，凝固时无气泡产生，组织致密，力学性能优于沸腾钢。", "section": "二、判断题", "topic": "热处理基础知识", "id": 158, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "金属中晶体缺陷的存在会使金属的力学性能降低，故通常希望金属中的缺陷越少越好。", "answer": "×", "explanation": "错误。晶体缺陷（位错）并非越少越好——位错的存在使滑移更容易启动（只需移动一根位错线而非整个原子面），所以完全无缺陷的晶须强度极高但塑性极差。工程上通过增加位错密度（加工硬化）或阻碍位错运动（固溶、细晶、第二相强化）来提高强度。", "section": "二、判断题", "topic": "热处理基础知识", "id": 159, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "金属面心立方晶格的致密度比体心立方晶格的致密度高。", "answer": "√", "explanation": "正确。面心立方晶格（fcc，如γ-Fe、Al、Cu）致密度为0.74；体心立方晶格（bcc，如α-Fe、Cr、W）致密度为0.68。fcc比bcc更致密——这也是α→γ转变（加热至~912℃）时纯铁体积收缩的原因。", "section": "二、判断题", "topic": "热处理基础知识", "id": 160, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "改善零件的结构形状，减小零件表面的粗糙度以及采取各种表面强化的方法，都能提高零件的疲劳强度。", "answer": "√", "explanation": "正确。疲劳裂纹多起源于表面缺陷（划痕、尖角、夹杂物）。改善结构形状（避免应力集中）、减小表面粗糙度、表面强化（喷丸、滚压、渗碳、渗氮）均可提高表面残余压应力和强度，从而显著提高疲劳强度。", "section": "二、判断题", "topic": "热处理基础知识", "id": 161, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "所有金属材料在拉伸试验时都会出现显著的屈服现象。", "answer": "×", "explanation": "错误。并非所有金属都有明显屈服现象。低碳钢有明显屈服平台（上屈服点→下屈服点），但高碳钢、大多数合金钢、铝合金等没有明显屈服点，需用规定残余伸长应力σ0.2（产生0.2%塑性变形时的应力）代替屈服强度。", "section": "二、判断题", "topic": "热处理基础知识", "id": 162, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "在单位面积上的内力，称为应力，以6表示。", "answer": "×", "explanation": "错误。应力定义为\"单位面积上的内力\"正确，但符号不是\"6\"而是σ（正应力，希腊字母sigma）或τ（切应力，tau）。σ=F/A，单位MPa（=N/mm²）。\"6\"可能是OCR识别错误。", "section": "二、判断题", "topic": "热处理基础知识", "id": 163, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "奥氏体连续冷却的转变产物及其性能，决定于冷却速度。", "answer": "√", "explanation": "同33题——正确。奥氏体连续冷却转变（CCT）的产物及性能决定于**冷却速度**。不同于等温转变（决定因素是温度），连续冷却转变的控制变量是冷却曲线。", "section": "二、判断题", "topic": "热处理基础知识", "id": 164, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "truefalse", "question": "金属的理想晶体的强度比实际晶体的强度要高得多。", "answer": "√", "explanation": "正确。理想晶体（无缺陷的完美晶体）的理论强度约为E/10~E/5（弹性模量的1/5~1/10）。但实际金属因位错等缺陷的存在，实际屈服强度仅为理论值的1/100~1/1000。位错运动使塑性变形在低应力下即可发生。", "section": "二、判断题", "topic": "热处理基础知识", "id": 165, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "小能量多次冲击抗力大小主要取决于材料的强度高低。", "answer": "√", "explanation": "正确。同58题——小能量多次冲击条件下，裂纹萌生阶段为主导。高强度材料裂纹萌生困难（需要更高循环应力），因此小能量多次冲击抗力主要取决于材料强度。一次大能量冲击抗力则主要取决于韧韧（ak值）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 166, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "在平衡状态下，金属的熔点和凝固点是同一温度。", "answer": "√", "explanation": "正确。平衡状态下金属的熔点和凝固点是同一温度——液态→固态相变在平衡条件下（极缓慢冷却/加热）发生在同一温度。实际中因过冷/过热，凝固温度低于熔点，但在热力学平衡时两者相等。", "section": "二、判断题", "topic": "热处理基础知识", "id": 167, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "滑移和孪生是金属塑性变形的两种基本形式。", "answer": "√", "explanation": "正确。滑移（位错沿滑移面逐步运动，是主要方式）和孪生（晶体的一部分相对另一部分发生均匀切变，形成镜面对称的孪晶，在密排六方金属中和低温/高速变形时更重要）是金属塑性变形的两种基本微观机制。", "section": "二、判断题", "topic": "热处理基础知识", "id": 168, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "对于不能用热处理方法进行强化的材料，可采用形变强化或细化晶粒强化等工艺。", "answer": "√", "explanation": "正确。不能用热处理强化的材料（如奥氏体不锈钢、防锈铝合金、纯铜等无相变材料），可通过形变强化（冷加工，增加位错密度）或细化晶粒强化（霍尔-佩奇效应，晶界强化）来改善力学性能。", "section": "二、判断题", "topic": "热处理基础知识", "id": 169, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "由于大多数固态金属都是晶体，所它们都具有各向异性。", "answer": "×", "explanation": "错误。单晶体具有各向异性（不同晶向性能不同），但多晶体（实际金属材料）由大量随机取向的晶粒组成，各晶粒的各向异性在宏观上被统计平均→宏观各向同性（伪各向同性）。只有经轧制/拉拔加工产生织构时才会表现出宏观各向异性。", "section": "二、判断题", "topic": "热处理基础知识", "id": 170, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "金属结晶时，过冷度越大，结晶后晶粒也越粗大。", "answer": "×", "explanation": "错误。过冷度越**大**→形核率越高（ΔT越大、驱动力越大）→晶核数多→晶粒越**细**，不是越粗。生产中通过增大过冷度（加快冷却/降低浇注温度）来细化铸态晶粒。但过冷度极大会形成非平衡组织。", "section": "二、判断题", "topic": "热处理基础知识", "id": 171, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "再结晶也是相变过程。", "answer": "×", "explanation": "错误。再结晶（deformed→equiaxed grains）**不是**相变过程——只是晶粒形状和尺寸变化（变形晶粒→等轴新晶粒），不涉及晶格类型变化，化学成分和环境不变。同素异构转变才是相变（晶格类型改变）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 172, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "在一定温度范围内随着过冷度的减小，所形成的晶粒越小，故生产中可通过适当减小过冷度的方法来达到细化晶粒的目的。", "answer": "×", "explanation": "错误。过冷度越**大**（不是越小），形核率越高，晶粒越细。生产中增大过冷度（如降低浇注温度、加快冷却）可细化铸态晶粒。题目说\"过冷度减小→晶粒越小\"逻辑完全颠倒。但注意：过冷度太大可能导致非平衡相出现。", "section": "二、判断题", "topic": "热处理基础知识", "id": 173, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "金属发同素异构转变时，要吸收或放出热量，转变时在恒温下进行的。", "answer": "√", "explanation": "正确。同素异构转变是相变→伴随热效应（吸收或放出相变潜热），转变在恒温下进行（临界点不变，如纯铁α↔γ在912℃恒温进行）。与凝固/熔化类似，相变温台（热分析曲线上的恒温段）是相变的标志。", "section": "二、判断题", "topic": "热处理基础知识", "id": 174, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "金属发同素异构转变时，只是晶格发生变变化，显微组织则不发生变化。", "answer": "×", "explanation": "错误。同素异构转变不仅晶格类型改变，显微组织也随之变化——如γ-Fe（fcc）→α-Fe（bcc），退火态下从奥氏体晶粒→铁素体+珠光体组织，显微镜下可见组织完全不同。晶格变化是微观的，组织变化是微观到宏观的桥梁。", "section": "二、判断题", "topic": "热处理基础知识", "id": 175, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "一般说晶粒越细小，金属的强度硬度就越高，塑性和韧性也越好。", "answer": "√", "explanation": "正确。细晶强化是唯一能同时提高强度和塑韧性的强化方式。霍尔-佩奇公式σs=σ0+kd^(-1/2)：晶粒越细（d越小），强度越高；同时因晶界面增加，塑性变形可分散在更多晶粒中，塑性和韧韧也越好。", "section": "二、判断题", "topic": "热处理基础知识", "id": 176, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "金属属塑性变的主要方式是滑移，而滑移的产生又是位错运动的结果，所以位错运动困难的材料其强度都较高。", "answer": "√", "explanation": "正确。滑移是金属塑性变形的主要方式，而滑移通过位错运动实现。因此阻碍位错运动→提高强度——这是所有强化机制（固溶强化、加工硬化、细晶强化、第二相强化）的物理基础。", "section": "二、判断题", "topic": "热处理基础知识", "id": 177, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "面缺陷主要是指金属中的晶界和亚晶界。", "answer": "√", "explanation": "正确。面缺陷是二维缺陷，主要包括晶界（不同取向晶粒之间，原子排列紊乱的过渡区）和亚晶界（同一晶粒内取向略不同的亚晶之间的界面，由位错列构成）。面缺陷对力学性能影响巨大（如细晶强化）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 178, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "无论是单晶体还是多晶体匀能体现出晶体的各向异性。", "answer": "×", "explanation": "错误。同170题——多晶体中晶粒取向随机分布，各向异性在宏观上被平均化，表现为宏观各向同性（伪各向同性）。仅当存在织构（择优取向）时多晶体才表现出宏观各向异性。单晶体才具有明显的各向异性。", "section": "二、判断题", "topic": "热处理基础知识", "id": 179, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "常温下的碳素钢中，由于铁和碳的相互作用而形成了与纯铁中的a-Fe成份和结构都不相同的Fe3C新相，所以碳素钢是多相组织。", "answer": "√", "explanation": "正确。常温碳素钢为多相组织：亚共析钢=铁素体(F)+珠光体(P)，共析钢=珠光体(P)，过共析钢=珠光体(P)+二次渗碳体(Fe₃C)。Fe₃C是复杂正交晶格结构的金属间化合物，与α-Fe（体心立方）完全不同，是独立物相。", "section": "二、判断题", "topic": "热处理基础知识", "id": 180, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "高速钢的碳的质量分数为0.7%~0.8%，所以它是过共析钢。", "answer": "×", "explanation": "错误。高速钢碳含量0.7-0.8%看似共析/过共析成分，但因含大量合金元素（W/Mo/Cr/V等强碳化物形成元素）→共析点S显著左移→实际属于莱氏体钢（类似过共晶白口铁）。淬火组织中存在共晶莱氏体（鱼骨状碳化物）是高速钢显微组织标志。", "section": "二、判断题", "topic": "热处理基础知识", "id": 181, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "晶格中的结点代表原子在晶体中平衡位置。", "answer": "√", "explanation": "正确。晶格中的结点（格点）代表原子在晶体中的平衡位置（能量最低位置）。原子围绕平衡位置做热振动，振动幅度随温度升高而增大。结点不是固定不变的点，而是统计平均位置。", "section": "二、判断题", "topic": "热处理基础知识", "id": 182, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "纯组元、固溶体和金属化合物均是合金的基本相。", "answer": "√", "explanation": "正确。合金的三种基本相：①纯组元（如纯铁中的铁素体基体）；②固溶体（如奥氏体，溶质溶入溶剂的晶格中）；③金属化合物（如渗碳体Fe₃C，具有不同于组元的晶体结构）。所有合金的显微组织都是这三种基本相的组合。", "section": "二、判断题", "topic": "热处理基础知识", "id": 183, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "金属化合物的晶格类型和组成金属化合物的各组元的晶格类型完全不同。", "answer": "√", "explanation": "正确。金属化合物（如Fe₃C、CuAl₂、Mg₂Si等）的晶格类型与组成组元的晶格类型**完全不同**——化合物有自己的特征晶体结构（如Fe₃C为正交晶格），这与固溶体（保持溶剂晶格类型）截然不同。", "section": "二、判断题", "topic": "热处理基础知识", "id": 184, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "T12表示平均We为1.2%的高级优质碳素工具钢。", "answer": "×", "explanation": "错误。T12的\"T\"表示碳素工具钢，\"12\"表示平均含碳量为1.2%（千分之十二），而非\"We\"（应为\"C%\"）。T12A中的\"A\"表示高级优质（S、P含量更低的优质钢）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 185, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "温度越高，原子的活动能力越强，溶质原子也就越不容易溶入溶剂中，故一般情况下，温度越高固溶体的溶解度越小。", "answer": "×", "explanation": "错误。温度越高，原子活动能力越强→溶质原子越**容易**溶入溶剂→固溶体溶解度通常越大（大多数体系溶解度随温度升高而增大）。这是固溶热处理的基础——加热到高温使溶质充分溶解，快冷后获得过饱和固溶体。", "section": "二、判断题", "topic": "热处理基础知识", "id": 186, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "珠光体的力学性能介于铁素和渗碳体之间。", "answer": "√", "explanation": "正确。珠光体由软韧的铁素体（硬度~80HB）和硬脆的渗碳体（硬度~800HB）层片交替组成，珠光体综合力学性能介于两者之间——强度~800MPa，硬度~200HB。珠光体性能取决于片间距：越细→强度/硬度越高。", "section": "二、判断题", "topic": "热处理基础知识", "id": 187, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "truefalse", "question": "塑性变形会使金属材料的导电性、导磁性下降，化学活性上升、腐蚀速度加快。", "answer": "√", "explanation": "正确。塑性变形引入大量缺陷（位错、空位），晶格畸变使电子散射增加→导电性下降；内应力使磁畴运动受阻→导磁性下降；应变能升高→化学活性增大→腐蚀速度加快（应力腐蚀的微观原因）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 188, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "合金固溶强化的基本原因是晶体的晶格类型发生变化。", "answer": "×", "explanation": "错误。同71题——固溶强化的基本原因是**晶格畸变**，不是晶格类型变化。溶质原子使溶剂晶格产生弹性畸变，畸变应力场阻碍位错运动→强度提高。固溶后晶格类型不变（仍保持溶剂组元的晶格类型）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 189, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "机械混合物的力学性能取决于构成它们的各组成相的性能，以及各相的数量、形状、大小和分布情况。", "answer": "√", "explanation": "正确。机械混合物（如珠光体=铁素体+渗碳体）的性能由组成相的性能和各相的数量、形状、大小、分布共同决定。例如珠光体片间距越细→强度和硬度越高；球状珠光体比片状珠光体塑性更好、硬度更低。", "section": "二、判断题", "topic": "热处理基础知识", "id": 190, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "间隙固溶体有可能是无限固溶体，置换固溶体不可能是无限固溶体。", "answer": "×", "explanation": "错误。间隙固溶体不可能是无限固溶体（因为间隙位置有限，溶质只能有限溶解）。置换固溶体可以是无限固溶体（如Cu-Ni、Fe-Cr系，两组元可任意比例互溶），条件是两者晶格类型相同、原子尺寸差<15%、电负性相近。", "section": "二、判断题", "topic": "热处理基础知识", "id": 191, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "二次渗碳体是从液态合金中结晶出来的，而一次渗碳体是从奥氏体中析出的。", "answer": "×", "explanation": "错误。一次渗碳体是从**液态合金**中结晶析出的（过共晶铸铁凝固时）；二次渗碳体是从**奥氏体**中析出的（过共析钢缓冷时沿Acm线析出）。题目将两者搞反了：一次=液态→固态，二次=固态→固态。", "section": "二、判断题", "topic": "热处理基础知识", "id": 192, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "truefalse", "question": "共析渗体、共晶渗碳体、一次渗碳体和二次渗碳体是铁碳合金中结构相似而原子数量比不同的四种铁碳化合物。", "answer": "×", "explanation": "错误。共析渗碳体、共晶渗碳体、一次渗碳体和二次渗碳体的化学成分和晶体结构完全相同（均为Fe₃C，正交晶系，含碳6.69%），原子数量比也相同（Fe:C=3:1）。区别仅在于来源（形成途径）和形态不同，而非成分/结构差异。", "section": "二、判断题", "topic": "热处理基础知识", "id": 193, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "铁素体是固溶体，由于固溶强化的原因，其性能硬而脆。", "answer": "×", "explanation": "错误。铁素体是碳在α-Fe中的间隙固溶体（C含量<0.0218%），含碳极低→固溶强化效果弱→性能**软而韧**（强度低、塑性好）。渗碳体（Fe₃C）才硬而脆。题目将铁素体和渗碳体的性能搞混了。", "section": "二、判断题", "topic": "热处理基础知识", "id": 194, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "亚共析钢属中碳钢、共析钢属中碳钢、过共析钢为高碳高。", "answer": "×", "explanation": "错误。亚共析钢=碳含量<0.77%（不一定是中碳，0.0218-0.77%C范围涵盖低碳和中碳）；共析钢=碳含量≈0.77%（单一成分，是中碳）；过共析钢=碳含量0.77-2.11%（涵盖高碳）。三者按共析点分界，非简单按中碳/高碳对应。", "section": "二、判断题", "topic": "热处理基础知识", "id": 195, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "环状珠光体和片状珠光体比较，在硬度相同的情况下，前者塑性、韧性较好。", "answer": "√", "explanation": "正确。球状珠光体（球化退火产物，碳化物呈球状颗粒）在相同硬度下塑性/韧韧**优于**片状珠光体——球形碳化物不割裂基体、应力集中效应小。这就是为什么刀具钢要球化处理（改善切削性）和高碳轴承钢要球化退火的原理。", "section": "二、判断题", "topic": "热处理基础知识", "id": 196, "knowledge_point": "珠光体与贝氏体转变", "knowledge_point_key": "pearlite_bainite"}, {"type": "truefalse", "question": "再结晶过程没有恒定的转变温度。", "answer": "√", "explanation": "正确。再结晶是热激活过程（需要形核和长大），但**没有恒定的转变温度**——再结晶温度随变形量（变形越大再结晶温度越低）、保温时间、原始晶粒度等因素变化。不像熔化/同素异构转变那样有固定临界温度。", "section": "二、判断题", "topic": "热处理基础知识", "id": 197, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "奥氏体晶粒尺寸越小，其晶粒度等级也越小。", "answer": "×", "explanation": "错误。晶粒度等级N与晶粒尺寸d成反比关系：N值越大→晶粒越细。奥氏体晶粒尺寸越小（越细）→晶粒度等级越大（如8级细于5级）。两者呈反向关系，尺寸越小等级越大。", "section": "二、判断题", "topic": "热处理基础知识", "id": 198, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "碳钢中的常存杂质硅、锰不超过规定含量时都是有益元素，它们都提高钢的强度。", "answer": "√", "explanation": "正确。硅（<0.4%）和锰（<0.8%）是炼钢时的脱氧元素，在规定范围内为有益杂质。Si固溶于铁素体中起固溶强化作用，Mn除固溶强化外还能与S形成MnS减少热脆性，两者均提高钢的强度和硬度。", "section": "二、判断题", "topic": "热处理基础知识", "id": 199, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "铁碳合金在室温下的平衡组织是由铁素体、奥氏体、渗碳体组成。", "answer": "×", "explanation": "错误。室温下铁碳合金平衡组织由铁素体和渗碳体组成——奥氏体在727℃时通过共析转变（γ→α+Fe₃C）完全分解为珠光体，室温下不存在残余奥氏体（平衡条件下）。残余奥氏体仅存在于淬火非平衡组织中。", "section": "二、判断题", "topic": "热处理基础知识", "id": 200, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "truefalse", "question": "Fe-Fe3C相图中没有贝氏体和马氏体两种组织的原因是相图中的组织为稳定的平衡组织，而这两种组织则是非平衡组织。", "answer": "√", "explanation": "正确。Fe-Fe₃C相图是平衡相图（热力学平衡态），只标注平衡转变产物（珠光体/莱氏体/铁素体+渗碳体）。贝氏体（中温非平衡转变）和马氏体（低温无扩散转变）均是亚稳态非平衡组织→不出现在平衡相图中，而出现在C曲线（TTT图/CCT图）中。", "section": "二、判断题", "topic": "热处理基础知识", "id": 201, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "合金碳化物溶于奥氏体的速度很慢，为获得均匀的奥氏体，合金钢的保温时间要比碳钢长。", "answer": "√", "explanation": "正确。合金碳化物（Cr₇C₃、W₂C、VC、Mo₂C等）稳定性高，溶解温度远高于Fe₃C（渗碳体660℃左右即开始溶解）。要使合金碳化物充分溶解并均匀分布，需要更高的奥氏体化温度和更长的保温时间。", "section": "二、判断题", "topic": "热处理基础知识", "id": 202, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "间隙化合物一般是由原子直径较大的过度族金属和原子直径较小的非金属元素所组成。", "answer": "√", "explanation": "正确。间隙化合物（如TiC、WC、VC、NbC等）由过渡族金属（Ti、W、V、Nb，原子半径较大）和原子半径小的非金属元素（C、N、B）组成——小原子填入大原子构成的间隙位置形成具有简单晶体结构的化合物，硬度极高、熔点极高。", "section": "二、判断题", "topic": "热处理基础知识", "id": 203, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "由于一切自发过程都是从高自由能状态过度到低自由能状态，所以钢组织转变的推动力是新和旧相之间的自由能差。", "answer": "√", "explanation": "正确。相变驱动力：新相与旧相之间的Gibbs自由能差ΔG=G_new-G_old<0→自发转变。过冷度ΔT越大→ΔG越负→驱动力越大→转变越快。这是热力学基本规律在相变中的应用。", "section": "二、判断题", "topic": "热处理基础知识", "id": 204, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "回火的主要目的在于消除淬火造成的残余应力，故回火与去应力退火无本质区别。", "answer": "×", "explanation": "错误。回火与去应力退火有本质区别：①回火针对淬火钢，通过碳原子析出和碳化物转变调整组织与性能（150-650℃）；②去应力退火仅消除铸造/锻造/焊接/冷加工残余应力，不改变基体组织（通常500-650℃，对淬火钢则为<Ac1的低温去应力）。两者目的和机理完全不同。", "section": "二、判断题", "topic": "热处理基础知识", "id": 205, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "回火脆性，是钢的一种热处理特性，而不是热处理缺陷。但如果不注意这种特性，有时就会成为回火缺陷的根源。", "answer": "√", "explanation": "正确。回火脆性是钢本身的冶金特性（与成分有关），不是操作失误造成的缺陷。但如果不了解此特性，在脆化温度回火并慢冷→导致冲击韧度大幅下降→就变成回火缺陷。预防：避开脆化温度回火，或回火后快冷。", "section": "二、判断题", "topic": "热处理基础知识", "id": 206, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "在热处理生产中选择本质细晶粒钢，当加热温度过高(≥950℃)，奥氏体晶粒仍然细小。", "answer": "×", "explanation": "错误。本质细晶粒钢仅在常规加热温度（<930-950℃）下晶粒长大倾向小。当加热温度超过其晶粒粗化温度（AlN/NbC等钉扎质点溶解温度→≥950-1000℃）→钉扎效应消失→晶粒急剧长大（甚至可能超过本质粗晶粒钢）。所以\"≥950℃仍然细小\"不成立。", "section": "二、判断题", "topic": "热处理基础知识", "id": 207, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "奥氏体晶粒长大过程中向铁铁素一侧长大的速度快于渗碳体一侧。", "answer": "√", "explanation": "正确。奥氏体晶粒长大过程（珠光体→奥氏体完成后）：晶界向铁素体一侧的移动速度**快于**向渗碳体一侧——因为铁素体α→γ转变速度快、渗碳体需先溶解扩散再转变成奥氏体→后者慢。驱动力=界面曲率效应。", "section": "二、判断题", "topic": "热处理基础知识", "id": 208, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "truefalse", "question": "再结晶并不能够变形金属的组织和性能回到冷塑性变形前的状态。", "answer": "×", "explanation": "错误。再结晶能够使变形金属的组织和性能恢复到冷塑性变形前的状态——变形晶粒被等轴无畸变晶粒取代，强度硬度降低、塑性韧韧恢复。题目中说\"并不能够\"是错误的。注意区分：回复阶段仅消除应力，再结晶阶段才改变组织和性能。", "section": "二、判断题", "topic": "热处理基础知识", "id": 209, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "凡使C曲线右移过冷奥氏体移定性增加的因素都对珠光体的转变起阻碍作用。", "answer": "√", "explanation": "正确。C曲线右移=过冷奥氏体稳定性增加=珠光体转变被推迟（孕育期延长）。合金元素（除Co外）和粗大晶粒都使C曲线右移→抑制珠光体形成→提高淬透性。这对淬火有利（更慢冷却也能避开珠光体\"鼻子\"）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 210, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "truefalse", "question": "再结晶是无相的结晶过程。", "answer": "√", "explanation": "正确。再结晶是无相变的结晶过程——新晶粒的晶格类型与变形晶粒完全相同（如α-Fe→α-Fe），只是消除了位错和畸变、形成等轴新晶粒。区别：相变结晶（如γ→α）涉及晶格类型的改变。", "section": "二、判断题", "topic": "热处理基础知识", "id": 211, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "影响奥氏体晶粒长大的两个主要因素是加热温度和保温时间，并且加热温度的影响比保温时间更为明显。", "answer": "√", "explanation": "正确。奥氏体晶粒长大是热激活过程——晶界迁移速率与exp(-Q/RT)成正比。温度的影响呈指数关系（升高温度→迁移速率指数级增大），保温时间仅呈线性关系（t½长大规律）。因此加热温度的影响远大于保温时间。", "section": "二、判断题", "topic": "热处理基础知识", "id": 212, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "机械混合物没有确定的相组成数量比且各个组成相保持各自原有的晶格和性能。", "answer": "√", "explanation": "正确。机械混合物（如珠光体=铁素体+渗碳体、共晶组织等）特点：各组成相保持各自的晶体结构和性能，各相之间没有固定的化学计量比（不像化合物那样确定），但有一定比例范围（如共析成分-共析组织）。", "section": "二、判断题", "topic": "热处理基础知识", "id": 213, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "二元合金相图一般都是用实验的方法测得其最常用的方法是热分析法。", "answer": "√", "explanation": "正确。二元合金相图最常用的实验测定方法是热分析法——通过精确测量合金在缓慢加热/冷却过程中的温度-时间曲线（冷却曲线/加热曲线），捕捉相变时的温度停留或拐点（相变潜热效应→温度变化速率突变）→确定相变温度和相区边界。", "section": "二、判断题", "topic": "热处理基础知识", "id": 214, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "fill", "question": "钢按化学成分中含碳量多少分为： 等。 ______", "answer": "低碳钢，中碳钢，高碳钢", "explanation": "钢按含碳量分类：**低碳钢**（C≤0.25%，如08、20钢，塑性好、可焊性好）、**中碳钢**（C 0.25%~0.60%，如35、45钢，调质处理后综合性能好）、**高碳钢**（C>0.60%，如T8、T10，高硬度高耐磨性）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 215, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "把含碳量小于 %而不含有特意加入合金元素的钢称为碳素钢，简称碳钢。 ______", "answer": "2.11", "explanation": "碳钢的定义：含碳量小于**2.11%**（铸铁为>2.11%），且不含特意加入合金元素的铁碳合金。2.11%是铁碳相图中E点对应的碳含量，是钢与铸铁的理论分界线。碳钢中除Fe、C外，还含有少量Si、Mn、S、P等常存杂质。", "section": "三、填空题", "topic": "热处理基础知识", "id": 216, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "材料抵抗局部变形，特别时塑性变形、压痕或划痕的能力称为。 ______", "answer": "硬度", "explanation": "硬度定义：材料抵抗局部变形，特别是塑性变形、压痕或划痕的能力。硬度是衡量金属软硬程度的指标，与强度有正相关关系（σb≈K×HB）。常用硬度有布氏(HB)、洛氏(HRC)、维氏(HV)等。", "section": "三、填空题", "topic": "热处理基础知识", "id": 217, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "材料在外力作用下引起形状和尺寸的改变，称为。它包括 和______。塑性变形是用", "answer": "变形，弹性变形，塑性变形", "explanation": "材料在外力作用下形状和尺寸的改变称为**变形**（包括弹性变形和塑性变形）。弹性变形：外力去除后变形消失，可逆；塑性变形：外力去除后变形保留，不可逆，通过位错运动实现。", "section": "三、填空题", "topic": "热处理基础知识", "id": 218, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "常用金属材料拉伸时最大的相对 来表示。 ______", "answer": "伸长率，端面收缩率", "explanation": "常用金属材料拉伸时，最大相对伸长率（**伸长率**δ）和最大断面收缩率（**断面收缩率**ψ）来表示塑性——δ=(L₁-L₀)/L₀×100%，ψ=(A₀-A₁)/A₀×100%。ψ不受试样长度影响，比δ更能真实反映塑性。", "section": "三、填空题", "topic": "热处理基础知识", "id": 219, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "金属材料的力学性能包括： 有 等金属材料在加工和使用过程中受不同形式的外力作用时所表现出 等来的性能。当外力达到或超过某一限度时，材料就会发生变形，断裂) 等。（强度，刚度，韧性，硬度，耐磨性： 甚至 ______", "answer": "强度，刚度，塑性，硬度，耐磨性", "explanation": "金属材料力学性能包括：**强度**（抵抗破坏的能力）、**刚性/刚度**（抵抗弹性变形的能力）、**塑性**（产生永久变形而不破坏的能力）、**硬度**（抵抗局部压入的能力）、**耐磨性**（抵抗磨损的能力）。补充还有韧性（冲击韧性）、疲劳强度等。", "section": "三、填空题", "topic": "热处理基础知识", "id": 220, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "布氏硬度一般不用计算，而是用专门的刻度放大镜量出压痕直径(4根据压痕直径的大小，再从专门的硬度表中查处相应的不是硬度值。d越小，布氏硬度值 布氏硬度值 ，也就是硬度 相反，d越大， 度。 硬 ______", "answer": "越大，越高，越小，越低", "explanation": "布氏硬度测量原理：压痕直径d越小→材料越硬→布氏硬度值**越大/越高**；反之d越大→材料越软→布氏硬度值**越小/越低**。HB∝F/(πD²)，同等载荷下硬的材料压痕浅而小。", "section": "三、填空题", "topic": "热处理基础知识", "id": 221, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "布氏硬度是测量表面压痕直径的一种方法，通常用符号 表示。(HBS.HBW) 或 ______", "answer": "HBS，HBW", "explanation": "布氏硬度符号：**HBS**（钢球压头，适用于HB<450的较软材料）、**HBW**（硬质合金球压头，适用于HB<650的较硬材料）。两者区别在于压头材料不同，测试范围不同。", "section": "三、填空题", "topic": "热处理基础知识", "id": 222, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "布氏硬度机压头常用的圆球直径有： mm 、 mm三种。 ______", "answer": "2.5，5，10", "explanation": "布氏硬度机压头常用钢球直径有：**2.5mm、5mm、10mm**三种。根据被测材料硬度和厚度选择——材料越软越厚选用大直径球，材料越硬越薄选用小直径球，保证压痕清晰可测。", "section": "三、填空题", "topic": "热处理基础知识", "id": 223, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "金属材料的物理性能是指在 等物理 因素作用下，材料所表现的性能或固有属性。 ） ______", "answer": "物理性能，化学性能，工艺性能", "explanation": "金属材料性能三大类：**物理性能**（密度、熔点、导电性、导热性、磁性等）、**化学性能**（耐腐蚀性、抗氧化性等）、**工艺性能**（铸造性、锻造性、焊接性、切削加工性、热处理工艺性等）。力学性能有时单列，但广义上归入物理性能。", "section": "三、填空题", "topic": "热处理基础知识", "id": 224, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "洛氏硬度不同标尺的表示方法有： ______", "answer": "HRA. HRB， HRC", "explanation": "洛氏硬度标尺：**HRA**（金刚石压头，60kg，测硬薄件/硬质合金）、**HRB**（φ1.588mm钢球，100kg，测软金属）、**HRC**（金刚石压头，150kg，测淬火钢等硬材料，最常用）。不同标尺适用范围不同。", "section": "三、填空题", "topic": "热处理基础知识", "id": 225, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "除铁基和镍基高温合金外，还有 以及高温复合材料，可用于更高温度。 ______", "answer": "钴基，钼基，粉末高温合金", "explanation": "高温合金体系：铁基（如GH2132，700℃以下）、镍基（如GH4169，1000℃以下）。此外还有**钴基**（耐热腐蚀好）、**钼基/铌基**（极高温度>1200℃）以及**粉末高温合金**（组织均匀、性能优良，用于航空发动机涡轮盘）和高温复合材料（陶瓷基、C/C复合材料等）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 226, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "根据铸铁中石墨的形态，铸铁又可分为： ______ 和蠕墨铸铁等。", "answer": "灰铸铁，可锻铸铁，球墨铸铁", "explanation": "铸铁按石墨形态分类：**灰铸铁**（片状石墨，减振性好但强度低）、**可锻铸铁**（团絮状石墨，由白口铸铁退火而得，有一定韧性——\"可锻\"并非真的锻造）、**球墨铸铁**（球状石墨，强度最高接近钢）、蠕墨铸铁（蠕虫状石墨，介于灰铁和球铁之间）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 227, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "铸铁是含碳量大于 铁碳合金。并且还含有硅、锰、硫、磷等元素。 ______", "answer": "2.11%", "explanation": "同692题——铸铁含碳量大于**2.11%**（E点，碳在γ-Fe中最大溶解度）。2.11%~4.3%为亚共晶铸铁，4.3%为共晶成分。铸铁中常含Si 1%~3%、Mn 0.5%~1.4%、S<0.1%、P<0.2%等。", "section": "三、填空题", "topic": "热处理基础知识", "id": 228, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "在单位面积上的内力，称为 ，以o表示。 ______", "answer": "应力", "explanation": "单位面积上的内力称为**应力**，符号σ（希腊字母sigma，不是\"o\"），单位MPa（=N/mm²）。σ=F/A。正应力垂直于截面，切应力τ平行于截面。题目中\"以o表示\"是OCR识别错误，应为\"以σ表示\"。", "section": "三、填空题", "topic": "热处理基础知识", "id": 229, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "任何一种热处理工艺都是由： 和 三个阶段所组成的。 ______", "answer": "加热，保温，冷却", "explanation": "任何热处理工艺由三个阶段组成：**加热**（升温到需要的温度）、**保温**（在目标温度下维持足够时间使组织转变）、**冷却**（以不同速度/介质冷却得到所需组织）。三个阶段缺一不可，每个阶段的参数选择决定最终组织和性能。", "section": "三、填空题", "topic": "热处理基础知识", "id": 230, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "fill", "question": "金属材料的腐蚀一般有两种类型：一为 ，即金属与周围介质发生化学作用而产生的腐蚀，其特点为：金属与介质起化学作用，腐蚀过程没有电流产生，在金属表面腐蚀；二是 ，即金属与酸、碱、盐等电解质溶液接触时发生作用而引起的腐蚀。", "answer": "化学腐蚀，电化学腐蚀", "explanation": "金属腐蚀按机理分两大类：①化学腐蚀——金属与干燥气体或非电解质直接化学反应（如高温氧化），无电流产生，腐蚀产物在表面成膜；②电化学腐蚀——金属在电解质溶液（酸/碱/盐/潮湿空气）中形成微电池，有电流（阳极溶解→腐蚀），是大气腐蚀和水腐蚀的主要形式。两者常同时存在，电化学腐蚀危害更大。", "section": "三、填空题", "topic": "热处理基础知识", "id": 231, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "常用的淬火方法有： 和等。 ______", "answer": "单介质淬火法，双介质淬火法，分级淬火法，等温淬火法", "explanation": "常用淬火冷却方法：①单介质淬火（纯水淬/油淬→最简单常用）；②双介质淬火（水淬油冷→先快后慢，减小应力）；③分级淬火（Ms点稍上恒温盐浴→内外均温后空冷→变形最小）；④等温淬火（在贝氏体区等温→得下贝氏体→高强度+良好韧性，通常无需回火）。此外还有加压淬火、喷雾淬火等特种方法。", "section": "三、填空题", "topic": "热处理基础知识", "id": 232, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "金属材料的热处理可分为： 及表面热处理等五种基本方法。 ______", "answer": "退火，正火，淬火，回火", "explanation": "金属材料热处理五大基本方法：**退火**（软化）→**正火**（细化组织）→**淬火**（硬化）→**回火**（调整性能）及**表面热处理**（表面强化，如渗碳、渗氮、感应淬火等）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 233, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "fill", "question": "根据钢的成分和目的不同常用退火方法有 等几种。 ______", "answer": "完全退火，球化退火，去应力退火", "explanation": "按加热温度和冷却方式不同，常用退火方法分为：①完全退火（Ac3+30~50℃→炉冷，得平衡组织）；②球化退火（Ac1附近循环→得粒状珠光体）；③去应力退火（<Ac1→消除应力）。此外还有扩散退火（高温长时间→消除偏析）、再结晶退火（冷变形后→消除加工硬化）、等温退火等。", "section": "三、填空题", "topic": "热处理基础知识", "id": 234, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "细晶粒组织不仅强度、塑性比粗晶粒高，尤其是韧性有明显的提高。因此，钢在加热时，为了得到细小而均匀的奥氏体品粒，必须严格控制和。 ______", "answer": "加热温度，保温时间", "explanation": "获得细小均匀奥氏体晶粒的两个关键控制参数：①加热温度（最敏感因素——温度过高→晶粒以指数速率长大）；②保温时间（温度合适的前提下，保温时间以刚好完成奥氏体均匀化为宜——过长→晶粒继续长大）。两者缺一不可，温度是主导因素。", "section": "三、填空题", "topic": "热处理基础知识", "id": 235, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "fill", "question": "高碳钢及一些合金钢，由于M点位于零度以下，室温下淬火后组织中有大量的残余奥氏体。若将钢继续冷却到零度以下，会使残余奥氏体转变为马氏体，称这种操作为。 ______", "answer": "冷处理", "explanation": "**冷处理**（深冷处理）：将淬火后零件继续冷却到0℃以下（通常-60~-80℃，深冷可达-196℃液氮），使残余奥氏体继续转变为马氏体。适用于高碳钢和合金钢（Mf点低于室温），可提高硬度、稳定尺寸、消除残余奥氏体。", "section": "三、填空题", "topic": "热处理基础知识", "id": 236, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "金属或合金经过冷、热加工或热处理后，在室温下保持(放置)或适当升高温度时常发生力学和物理性能随时间而变化的现象，统称为。 ______", "answer": "时效", "explanation": "**时效**：金属或合金经冷热加工或热处理后，在室温放置或加热过程中，力学和物理性能随时间而变化的现象。分为自然时效（室温长时间放置）和人工时效（加热至一定温度加速时效过程）。铝合金时效是强化手段，钢的时效可能导致脆化。", "section": "三、填空题", "topic": "热处理基础知识", "id": 237, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "在共析温度以下存在的奥氏体称为。 ______", "answer": "过冷奥氏体", "explanation": "过冷奥氏体=在共析温度A1（727℃）以下以亚稳态存在的奥氏体。热力学上不稳定（有自发分解为珠光体的倾向），但动力学上因需克服形核势垒可暂时存在。过冷奥氏体在C曲线不同温度区间可转变为珠光体/贝氏体/马氏体，是钢热处理的理论基础。", "section": "三、填空题", "topic": "热处理基础知识", "id": 238, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "fill", "question": "由于合金元素溶入马氏体，使原子扩散速度减慢，因而在回火过程中不易分解， 不易析出，析出后也较难聚集长大，使合金钢在相同温度下回火后强度、硬度下降较少，即比碳钢具有较高的回火稳定性。 ______", "answer": "马氏体，碳化物", "explanation": "合金元素溶入马氏体后，增强了原子间结合力，减慢C原子扩散速度，所以在回火时**马氏体**不易分解，**碳化物**不易析出。即使析出后，合金元素也阻碍碳化物聚集长大，使合金钢比碳钢具有更高的回火稳定性（在相同回火温度下硬度下降更少）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 239, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "钢在加热过程，奥氏体的形成包括： 四个连续的阶段。 ______", "answer": "奥氏体形核，奥氏体晶\n\n粒长大，残余渗碳体的溶解，奥氏体均匀化", "explanation": "奥氏体形成四阶段（按时间顺序）：①奥氏体形核（在铁素体/渗碳体相界面上优先形核→界面能低）；②奥氏体晶粒长大（γ/α界面推进→铁素体→γ，γ/Fe₃C界面推进→渗碳体溶解）；③残余渗碳体溶解（γ晶粒相遇后，残余Fe₃C继续向γ中溶入碳）；④奥氏体均匀化（碳原子在γ中扩散→成分从晶界到心部均匀化）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 240, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "fill", "question": "淬火钢在回火时，抵抗软化的能力称为 ______", "answer": "回火稳定性", "explanation": "回火稳定性（回火抗力）=淬火钢在回火加热时抵抗硬度/强度下降的能力。影响因素：①合金元素——强碳化物形成元素（Cr/Mo/V/W/Ti）阻碍碳扩散和渗碳体聚集长大，显著提高回火稳定性；②回火温度和时间。回火稳定性是评价工具钢/模具钢高温性能的关键指标。", "section": "三、填空题", "topic": "热处理基础知识", "id": 241, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "将钢经奥氏体化后冷却到相变点以下的温度区间内等温保持时，过冷奥氏体所发生的相变转变称为 ______。", "answer": "等温转变", "explanation": "将奥氏体化钢冷至A1以下温度等温→过冷奥氏体发生的相变称为**等温转变**（Isothermal Transformation）。对应的温度-时间-转变量关系图就是TTT图（Time-Temperature-Transformation，即C曲线）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 242, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "fill", "question": "工件在冷却过程中，会伴随两种应力的出现，即 和 ______", "answer": "热应力，组织应力", "explanation": "工件冷却过程伴随两种应力：**热应力**（内外温差→内外冷却收缩不同时→表面受压/心部受拉）和**组织应力**（表面先发生马氏体转变→体积膨胀→受周围未转变心部约束→表面受拉/心部受压）。两种应力叠加导致变形甚至开裂。", "section": "三、填空题", "topic": "热处理基础知识", "id": 243, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "铝合金的热处理与钢不同，不是通过控制 转变，而是控制过程来改变性能。铝合金在淬火状态下是强度 、塑性强度。与碳钢相比，铝 的过饱和固溶体，通过时效后期 合金的热处理温度控制要求严格，加热温度一般要控制在 内。 这种现象称为 ℃范围 42、 ______", "answer": "固溶，时效", "explanation": "铝合金热处理核心：**固溶**处理（加热到α单相区后快冷得到过饱和固溶体）→**时效**（在室温或加热条件下，过饱和固溶体中析出细小弥散的第二相，引起强化）。与钢不同——钢通过控制同素异构转变，铝合金通过控制析出过程来改变性能。", "section": "三、填空题", "topic": "热处理基础知识", "id": 244, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "若人工时效的时间过长或温度过高，反而使合金软化， 回火。 后所能达到的 ( ______", "answer": "过时效", "explanation": "铝合金时效强化三阶段：欠时效（低温/短时→GP区析出不充分→硬度未达峰值）→峰值时效（GP区+过渡相细小弥散共格析出→硬度最高）→过时效（温度过高/时间过长→平衡相粗化→失去共格关系→硬度/强度下降软化）。过时效是工艺失控状态，会使合金强度大幅下降。", "section": "三、填空题", "topic": "热处理基础知识", "id": 245, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "fill", "question": "淬硬性是指钢在理想条件下淬火成。低碳钢淬火的最高硬度值低，淬硬性 铁等 43 钢的淬硬性主要取决于______ ；高碳钢淬火的最高硬度值高，淬硬性 生了 N", "answer": "低，碳含量，高", "explanation": "淬硬性指钢在理想淬火条件下能获得的最高硬度，主要取决于**碳含量**（马氏体的含碳量）。**低碳钢**淬火后马氏体含碳低，硬度低（~40HRC）；**高碳钢**淬火后马氏体含碳高，硬度高（~65HRC）。注意区分：淬硬性≠淬透性——淬透性取决于合金元素和奥氏体晶粒度。", "section": "三、填空题", "topic": "热处理基础知识", "id": 246, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "钛合金的热处理方式有： 方式进行的。 本规热处理等；钛合金的热处理强化是通过 和 及化学 等有。（马氏体，少量 保涛 ______", "answer": "退火，淬火，时效", "explanation": "钛合金热处理方式：**退火**（消除应力，稳定组织，最常用）、**淬火（固溶）**（高温β区加热后快冷得到马氏体α'或α''相）、**时效**（淬火后加热到400~600℃使亚稳相分解析出细小α+β混合物，强化合金）。和钢不同，钛合金的淬火+时效强化来源于相变和析出。", "section": "三、填空题", "topic": "热处理基础知识", "id": 247, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "45号钢淬火后的组织为： 和 4残余奥氏体) ______", "answer": "马氏体", "explanation": "45#钢（亚共析钢，C约0.45%）加热Ac3以上全奥氏体化→水淬→过冷奥氏体转变为马氏体（体心正方α'）+少量残余奥氏体（未转变的面心立方γ）。正确的淬火组织中不应出现先共析铁素体——若出现说明加热温度不足（未达到Ac3以上）或冷却速度不够。", "section": "三、填空题", "topic": "热处理基础知识", "id": 248, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "将______采用适当的方式进行 以获得所需要的组织结构与性能的一种工艺称为热处理。 和 4 切", "answer": "热处理", "explanation": "**热处理**定义：将钢/合金采用适当的方式（加热、保温、冷却）进行**热处理**，以获得所需的组织结构与性能的一种工艺。三个基本阶段：加热→保温→冷却，通过控制各阶段参数改变组织→改变性能。", "section": "三、填空题", "topic": "热处理基础知识", "id": 249, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "钢的淬透性与钢的 冷却速度有密切的关系， 速度越低，钢的淬透性越好。 冷却 ______", "answer": "临界冷却，临界冷却", "explanation": "钢的淬透性取决于过冷奥氏体的稳定性，与临界冷却速度Vk成反比：Vk越小→C曲线越右移→过冷奥氏体越稳定→在较慢冷却下也能避开珠光体转变→淬透性越好。合金元素（Cr/Ni/Mn/Mo/Si，除Co外）均使C曲线右移→Vk降低→淬透性提高。碳也有一定提高淬透性的作用。", "section": "三、填空题", "topic": "热处理基础知识", "id": 250, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "退火是钢加热到适当温度，保持一定时间，然后 冷却（一般随炉冷却)的热处理工艺。 ______", "answer": "缓慢", "explanation": "退火的核心特征是缓慢冷却——一般随炉冷却（炉冷速度约30-100℃/h），以获得接近平衡态的稳定组织，消除应力、降低硬度。正火的关键区别是空冷（冷速快于炉冷），因此珠光体片间距更小、硬度更高。", "section": "三、填空题", "topic": "热处理基础知识", "id": 251, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "回火后的冷却对工件的性能影响不大，一般在 中冷却。有时为了消除铬及铬镍钢的回火脆性，可考虑在 中快冷。 ______", "answer": "空气，水或油", "explanation": "回火后冷却一般在**空气**中冷却（性能影响不大，马氏体已分解完毕）。但对含Cr、Cr-Ni的合金钢（第二类回火脆性敏感），应在**水或油**中快冷，避免在450~650℃温度区间缓慢冷却引起脆性。", "section": "三、填空题", "topic": "热处理基础知识", "id": 252, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "不同钢的奥氏体晶粒，加热时长大的倾向也不同。奥氏体晶粒随温度升高而迅速长大的钢，称为 ；奥氏体晶粒随温度升高而大倾 性向小，只有在加热到930~950℃才显著增长的钢，称为 ______", "answer": "本质粗晶粒钢，本质细晶粒钢", "explanation": "按奥氏体晶粒长大倾向将钢分为两类：①本质粗晶粒钢——随温度升高晶粒迅速长大（脱氧不完全，无AlN等钉扎质点），②本质细晶粒钢——930-950℃以下晶粒长大倾向小（含Al/Ti/Nb→AlN/NbC钉扎晶界），超过粗化温度后也会急剧长大。", "section": "三、填空题", "topic": "热处理基础知识", "id": 253, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "fill", "question": "回火缺陷主要指 和 不合格。 ______", "answer": "回火裂纹，回火硬度", "explanation": "回火两大主要缺陷：①回火裂纹——回火加热或冷却速度过快→热应力超过材料强度→开裂（尤其Ms点以下快速加热时，表层先回火收缩→心部未回火→拉应力致裂）；②回火硬度不合格——硬度过高（回火温度低/时间短→碳未充分析出）或硬度不足（温度过高/时间过长→碳化物过度聚集）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 254, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "fill", "question": "第二类回火脆性通常在脆化温度范围内 后缓慢冷却，才出现脆性。出现这类回火脆性后，在再次 时，采取短期 并快速 的方法，可以消除脆性。，铝 围 ______", "answer": "缓慢", "explanation": "第二类回火脆性（450~650℃）需在脆化温度范围内**缓慢**冷却才出现——杂质元素（P、Sb、Sn等）向奥氏体晶界偏聚所致。消除方法：重新加热到原回火温度以上，短期保温后**快速**冷却（水冷或油冷），使偏聚的杂质来不及扩散到晶界。", "section": "三、填空题", "topic": "热处理基础知识", "id": 255, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "硬度过高一般是因回火程度不够造成的，补救办法是 陈为 回火后硬度不足主要是温度过高，补救办法是 ______", "answer": "按正常回火规范补充回火，退火后重新淬火回火", "explanation": "回火硬度问题两类及补救：①硬度过高——回火不充分（温度低/时间短）→马氏体中碳未充分以碳化物形式析出→补救：按正常回火规范补充回火（同温度延长保温）；②硬度不足——回火温度过高→碳化物过分析出聚集长大→补救：必须先退火恢复平衡组织→重新淬火→按正确温度回火（不可直接重淬！）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 256, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "fill", "question": "热处理之所以能使钢等合金材料的性能发生变化，其根本原因是由干铁等金属材料有______ ，从而使钢等合金材料在加热和冷却过程中，发更性 生了组织与结构变化。", "answer": "同素异构转变", "explanation": "热处理能改变钢性能的根本原因是铁等金属具有**同素异构转变**（α↔γ↔δ）——加热到不同温度获得不同组织结构，以不同速度冷却得到不同产物（马氏体、珠光体、贝氏体等），性能各异。无同素异构转变的材料（如纯铝）无法通过热处理相变强化。", "section": "三、填空题", "topic": "热处理基础知识", "id": 257, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "钢的热处理原理主要是利用钢在加热和冷却时 的基本规律，根据这些基本规律和要求来确定 和 学 等有关参数，以达到改善材料性能的目的。 ______", "answer": "内部组织发生转变，加热温度，保温时间，冷却介质", "explanation": "钢的热处理原理：利用加热和冷却时**内部组织发生转变**的基本规律→确定**加热温度**、**保温时间**和**冷却介质**等参数→达到改善材料性能的目的。三个关键工艺参数由相图、C曲线和性能要求共同决定。", "section": "三、填空题", "topic": "热处理基础知识", "id": 258, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "金属抵抗永久变形和断裂的能力，称为 包括 量 和 和", "answer": "强度，塑性", "explanation": "金属抵抗永久变形和断裂的能力称为**强度**（抗拉强度σb、屈服强度σs），产生永久变形而不破坏的能力称为**塑性**（伸长率δ、断面收缩率ψ）。两者是力学性能的核心指标，一般强度↑则塑性↓（强韧矛盾）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 259, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "金属材料的工艺性能包括： 切削加工性能以及热处理性能等。 ______", "answer": "铸造性能，压力加工性能，焊接性能", "explanation": "金属材料工艺性能包括：**铸造性能**（流动性、收缩性）、**压力加工性能**（可锻性）、**焊接性能**（可焊性）、切削加工性能以及热处理性能（淬透性、变形开裂倾向等）。工艺性能决定材料适合哪种加工方法。", "section": "三、填空题", "topic": "热处理基础知识", "id": 260, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "根据铝合金的成分和工艺特点，可将铝合金分为 和两大类。 知 ______", "answer": "铸造铝合金，变形铝合金", "explanation": "铝合金按成分和工艺分为**铸造铝合金**（直接铸造成型，含Si等改善铸造性能的元素，如ZL101）和**变形铝合金**（铸锭经压力加工，如轧制、挤压、锻造，再分为可热处理强化和不可热处理强化两大类）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 261, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "我国将变形铝合金按性能特点和用途分为 和 四种。 ______", "answer": "防锈铝，硬铝，超硬铝，锻铝", "explanation": "变形铝合金按性能和用途分为四类：**防锈铝**（Al-Mn、Al-Mg系，耐蚀好、不可热处理强化）、**硬铝**（Al-Cu-Mg系，可热处理强化，强度较高）、**超硬铝**（Al-Zn-Mg-Cu系，强度最高，如7A04）、**锻铝**（Al-Mg-Si-Cu系，锻造性能好，如2A50）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 262, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "铜合金分为______ 和 三类。", "answer": "黄铜，青铜，白铜", "explanation": "铜合金分三类：**黄铜**（Cu-Zn合金，Zn为主要合金元素）、**青铜**（除Zn和Ni以外的元素为主要合金，如锡青铜Cu-Sn、铝青铜Cu-Al）、**白铜**（Cu-Ni合金，Ni为主要合金元素）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 263, "knowledge_point": "有色金属热处理", "knowledge_point_key": "nonferrous_heat_treatment"}, {"type": "fill", "question": "普通黄铜是 和 的合金。 ______", "answer": "铜、锌", "explanation": "普通黄铜是**铜(Cu)**和**锌(Zn)**的二元合金。含Zn<39%为α单相黄铜（fcc结构，塑性好可冷加工），含Zn 39%~45%为α+β双相黄铜（热加工性好）。常用牌号如H62（含Cu 62%/Zn 38%）。", "section": "三、填空题", "topic": "热处理基础知识", "id": 264, "knowledge_point": "有色金属热处理", "knowledge_point_key": "nonferrous_heat_treatment"}, {"type": "fill", "question": "______ 是用来反映材料抵抗裂纹失稳扩展，即抵抗脆性断裂能力的性能指标。当K K时，裂纹扩展慢或不扩展；当K K时，则材料发生失稳脆断。这是一项重要的判据，可用来分析和计算一些实际问题。", "answer": "断裂韧度，<，≥", "explanation": "**断裂韧度**（K_IC）是反映材料抵抗裂纹失稳扩展（抵抗脆性断裂）能力的指标。当应力强度因子K_I**<**K_IC时，裂纹扩展慢或不扩展（安全）；当K_I**≥**K_IC时，材料发生失稳脆断。这是断裂力学中最重要的判据。", "section": "三、填空题", "topic": "热处理基础知识", "id": 265, "knowledge_point": "变形与开裂", "knowledge_point_key": "deformation_cracking"}, {"type": "fill", "question": "按加热温度的不同，淬火钢的组织转变和性能的变化分为四个阶段：1 ______；2) ______；3)______ ；4)", "answer": "马氏体的分解，残余奥氏体的分解，渗碳体的形成，渗碳体的聚集长大", "explanation": "淬火钢回火四阶段按升温顺序：①马氏体分解（80-200℃）——过饱和碳以ε-碳化物（Fe₂.₄C）析出→回火马氏体；②残余奥氏体分解（200-300℃）——Ar→α+ε-碳化物（下贝氏体型）；③渗碳体形成（250-400℃）——ε-碳化物→Fe₃C渗碳体，马氏体→铁素体→回火屈氏体；④渗碳体聚集长大（400℃以上）——Fe₃C球化粗化→回火索氏体。", "section": "三、填空题", "topic": "热处理基础知识", "id": 266, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "合金钢是指为了______ ，特意加入一种或数种的______钢。", "answer": "改善钢的性能，合金元素", "explanation": "合金钢的定义：为**改善钢的性能**（提高强度、硬度、耐磨性、耐蚀性、热稳定性等），在碳钢基础上特意加入一种或数种**合金元素**（Cr、Ni、Mn、Si、Mo、W、V、Ti等）的钢。合金元素总量<5%为低合金钢，5%~10%为中合金钢，>10%为高合金钢。", "section": "三、填空题", "topic": "热处理基础知识", "id": 267, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "材料的化学性能是指材料抵抗其周围介质 和 等。 相钛合金、______", "answer": "腐蚀", "explanation": "化学性能指标：材料抵抗周围介质**腐蚀**（化学腐蚀和电化学腐蚀）和**氧化**（高温下与氧作用）的能力。不锈钢的耐蚀性、高温合金的抗氧化性都属于化学性能。热处理中需注意保护气氛防止氧化脱碳。", "section": "三、填空题", "topic": "热处理基础知识", "id": 268, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "钛合金根据组织成分不同一般分为： 相钛 合金、 相钛合金等。 ______", "answer": "a，B，a+β", "explanation": "钛合金按退火态组织分为：**α**型（以α相为主，如TA7，不可热处理强化，焊接性好）、**β**型（以β相为主，如TB6，可热处理强化）、**α+β**型（双相，如TC4/Ti-6Al-4V，可热处理强化，应用最广）。合金元素中Al稳定α相，V、Mo稳定β相。", "section": "三、填空题", "topic": "热处理基础知识", "id": 269, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "shortanswer", "question": "简述38CrMoA1A、3Cr3Mo3VNb (HM3)，3Cr13，62036，HP659-1、15MnGCr15、GH3044等材料的牌号的含义。", "answer": "38CrMoA1A：表示平均含碳量为0.38%，主要合金元素铭，钼、铝含量均小于1.5%的高级优质合金钢。 3Cr3Mo3VNb (HM3)：表示平均含碳量为0.30%，主要合金元素铭、钼含量均为3%左右，钒、铌含量小于1.5%的工具钢。 3Gr13：表示平均含碳量为0.3%，合金元素铬含量为13%左右的不锈钢(或马氏体不锈钢)。 GH2036：表示时效强化型铁基高温合金。 HPb59-1：表示含铜量为59%，铅含量为1%，其余为锌的铅黄铜。15Mn：表示平均含碳量为0.15%左右，平均含锰量为1%左右的优质碳素结构钢。 GCr15：表示含铬量为1.5%的滚动轴承钢。 GH3044：表示固溶强化型镍基高温合金。", "explanation": "38CrMoA1A：表示平均含碳量为0.38%，主要合金元素铭，钼、铝含量均小于1.5%的高级优质合金钢。 3Cr3Mo3VNb (HM3)：表示平均含碳量为0.30%，主要合金元素铭、钼含量均为3%左右，钒、铌含量小于1.5%的工具钢。 3Gr13：表示平均含碳量为0.3%，合金元素铬含量为13%左右的不锈钢(或马氏体不锈钢)。 GH2036：表示时效强化型铁基高温合金。 HPb59-1：表示含铜量为59%，铅含量为1%，其余为锌的铅黄铜。15Mn：表示平均含碳量为0.15%左右，平均含锰量为1%左右的优质碳素结构钢。 GCr15：表示含铬量为1.5%的滚动轴承钢。 GH3044：表示固溶强化型镍基高温合金。", "section": "四、简答题", "topic": "热处理基础知识", "id": 270, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "shortanswer", "question": "什么是热应力及相变应力?它们对淬火件的变形有何影响?", "answer": "1)热处理淬火冷却时由于工件表里存在温度差，由热胀冷缩的不一致而产生的内应力；相变应力是由于工件淬火过程中工件表里组织转变不一致而产生的内应力 2)热应力引起工件沿轴向缩缩短，平面凸起，棱角谈谈圆，即使工件趋于球形；相恋应力引起工件变形特性与热应力相反。", "explanation": "1)热处理淬火冷却时由于工件表里存在温度差，由热胀冷缩的不一致而产生的内应力；相变应力是由于工件淬火过程中工件表里组织转变不一致而产生的内应力 2)热应力引起工件沿轴向缩缩短，平面凸起，棱角谈谈圆，即使工件趋于球形；相恋应力引起工件变形特性与热应力相反。", "section": "四、简答题", "topic": "热处理基础知识", "id": 271, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "shortanswer", "question": "钢淬火的主要目的是什么?当炉温升到淬火温度后，为何还需要进行保温?", "answer": "钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 为了使钢件热透，使奥氏体转变彻底并均匀化。所以要进行保温。", "explanation": "钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 为了使钢件热透，使奥氏体转变彻底并均匀化。所以要进行保温。", "section": "四、简答题", "topic": "热处理基础知识", "id": 272, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "shortanswer", "question": "退火的目的是什么?", "answer": "a、降低钢的硬度，提高塑性，以利于切削加工及冷变形加工：b、细化晶粒，均匀钢的组织及成分，改善钢的性能或为以后的热处理作准备：c、消除钢中的残余内应力，以防止变形和开裂", "explanation": "a、降低钢的硬度，提高塑性，以利于切削加工及冷变形加工：b、细化晶粒，均匀钢的组织及成分，改善钢的性能或为以后的热处理作准备：c、消除钢中的残余内应力，以防止变形和开裂", "section": "四、简答题", "topic": "热处理基础知识", "id": 273, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "shortanswer", "question": "回火的目的是什么?", "answer": "a、减少或消除淬火时产生的内应力，防止工件在使用过程中产生变形和开裂：b、通过回火提高钢的韧性，适当调整钢的强度和硬度，使工件达到所要求的力学性能，以满足各种工件的性能需要：c、稳定组织，使工件在使用过程中不发生组织转变，从而保证工件的形状和尺寸不变，保证工件的精度。", "explanation": "a、减少或消除淬火时产生的内应力，防止工件在使用过程中产生变形和开裂：b、通过回火提高钢的韧性，适当调整钢的强度和硬度，使工件达到所要求的力学性能，以满足各种工件的性能需要：c、稳定组织，使工件在使用过程中不发生组织转变，从而保证工件的形状和尺寸不变，保证工件的精度。", "section": "四、简答题", "topic": "热处理基础知识", "id": 274, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "shortanswer", "question": "简述钢的热处理原理。", "answer": "主要是利用钢在加热和冷却时内部组织发生转变的基本规律，根据这些基本规律和要求来确定加热温度、保温时间和冷却介质等有关参数，以达到改善材料性能的目的。", "explanation": "主要是利用钢在加热和冷却时内部组织发生转变的基本规律，根据这些基本规律和要求来确定加热温度、保温时间和冷却介质等有关参数，以达到改善材料性能的目的。", "section": "四、简答题", "topic": "热处理基础知识", "id": 275, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "shortanswer", "question": "合金钢比碳钢的回火稳定性高，是否是有利，请说明原因?", "answer": "合金钢回火稳定性较高，一般是有利的：在达到相同硬度的情况下，合金钢的回火温度应比碳钢高，回火时间也应增长，可进一步消除残余应力，因而合金钢的塑性、韧性较碳钢好；而在同一温度回火时，合金钢的强度、硬度比碳钢高。", "explanation": "合金钢回火稳定性较高，一般是有利的：在达到相同硬度的情况下，合金钢的回火温度应比碳钢高，回火时间也应增长，可进一步消除残余应力，因而合金钢的塑性、韧性较碳钢好；而在同一温度回火时，合金钢的强度、硬度比碳钢高。", "section": "四、简答题", "topic": "热处理基础知识", "id": 276, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "已知某碳钢在退火状态的金相组织中，珠光体含量为45%，其它为铁素体，试计算该钢的含碳量，并指出大概的钢号。", "answer": "解：因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=45%×0.77%=0.45×0.77%=0.3465% 根据碳钢的命名法则，含碳量为0.3465%左右的钢，其牌号应为35钢。答：该钢的含碳量为0.3465%，钢号应为35钢。", "explanation": "解：因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=45%×0.77%=0.45×0.77%=0.3465% 根据碳钢的命名法则，含碳量为0.3465%左右的钢，其牌号应为35钢。答：该钢的含碳量为0.3465%，钢号应为35钢。", "section": "五、计算题", "topic": "热处理基础知识", "id": 277, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "某工装模具，材料为T8A钢，根据其使用条件，要求其硬度为HRC=54~ 60，请确定其回火温度的范围。", "answer": "解：根据经验公式，有 (1)当HRC取54时 回火温度=(60-54)×11+200=266(C)(2)当HRC取60时 回火温度=(60-60)×11+200=200(℃) 故，该模具淬火后的回火温度范围是：200~266℃", "explanation": "解：根据经验公式，有 (1)当HRC取54时 回火温度=(60-54)×11+200=266(C)(2)当HRC取60时 回火温度=(60-60)×11+200=200(℃) 故，该模具淬火后的回火温度范围是：200~266℃", "section": "五、计算题", "topic": "热处理基础知识", "id": 278, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "果须工装件，村料为25，根据其使用条，要求其现度为1c3请确定其回火温度范围。", "answer": "解：根据经验公式， (1)当HRC取35时 回火温度=(60-35)×10+200=450(C) (2)当HRC取40时 回火温度=(60-40)×10+200=400(C) 故，该工装淬火后的回火温度范围是：400~450℃", "explanation": "解：根据经验公式， (1)当HRC取35时 回火温度=(60-35)×10+200=450(C) (2)当HRC取40时 回火温度=(60-40)×10+200=400(C) 故，该工装淬火后的回火温度范围是：400~450℃", "section": "五、计算题", "topic": "热处理基础知识", "id": 279, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "calculation", "question": "有一批45钢，有效厚度为50mm，长为500mm，在箱式炉中加热保温，工件的装炉方式为堆放，求该工件在炉中淬火保温时间。(保温系数取2min/mm，修正系数为1.7)", "answer": "解：依据经验公式 t=α·k·D\n已知：α=1.2 k=1.7 D=50mm 代入得\nt=1.2×1.7×50=102(min)\n答：该工件在炉中的淬火保温时间为102min。", "explanation": "解：依据经验公式 t=α·k·D\n已知：α=1.2 k=1.7 D=50mm 代入得\nt=1.2×1.7×50=102(min)\n答：该工件在炉中的淬火保温时间为102min。", "section": "五、计算题", "topic": "热处理基础知识", "id": 280, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "材料为30CrMnSiA的锻件有效厚度为75mm，现分散均匀单层装炉，请确定其回火保温时间。(已知：有效厚度46~60mm，保温时间为110~120min;有效厚度>60min时，每增加1mm增加的时间1.2min)", "answer": "解：根据已知条件，有 回火保温时间=(110~120)+(75-60)×1.2=(128~138)min 答：取回火保温时间为130min", "explanation": "解：根据已知条件，有 回火保温时间=(110~120)+(75-60)×1.2=(128~138)min 答：取回火保温时间为130min", "section": "五、计算题", "topic": "热处理基础知识", "id": 281, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "calculation", "question": "有一批某种材料的环形锻件，尺寸为中455±3×φ305±3×52±3，该批锻件按炉次组批，根据生产实际情况，生产班组决定用3号炉分两个炉次进行生产，第一炉次平装两层，第二炉次平装单层。请确定每一炉次的淬火保温时间。(已知：有效厚度46~60mm，保温时间为150~160min；有效厚度>60min时，每增加1mm增加的时间2min)", "answer": "解：根据题意及已知条件，得该环形锻件的壁厚为：外径最大尺寸-内径最小尺寸 (455+3)-(305-3)=78(mm) 锻件的高度为：52+3=55(mm) (1)第一炉次的保温时间为： 单件环件的有效厚度为55mm，高度方向叠装两层的有效厚度为：(1+(2-1)×0.6)×55=88 (mm) 根据热透有效厚度确定规则，产品的壁厚78mm小于88mm，则取双层叠装时的有效厚度为78mm 故保温时间为=(150~160)+(78-60)×2=(186~196)min (2)第二炉次的保温时间为： 单层装炉时，产品的有效厚度为高度尺寸55mm，则保温时间为(150~160)min。", "explanation": "解：根据题意及已知条件，得该环形锻件的壁厚为：外径最大尺寸-内径最小尺寸 (455+3)-(305-3)=78(mm) 锻件的高度为：52+3=55(mm) (1)第一炉次的保温时间为： 单件环件的有效厚度为55mm，高度方向叠装两层的有效厚度为：(1+(2-1)×0.6)×55=88 (mm) 根据热透有效厚度确定规则，产品的壁厚78mm小于88mm，则取双层叠装时的有效厚度为78mm 故保温时间为=(150~160)+(78-60)×2=(186~196)min (2)第二炉次的保温时间为： 单层装炉时，产品的有效厚度为高度尺寸55mm，则保温时间为(150~160)min。", "section": "五、计算题", "topic": "热处理基础知识", "id": 282, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "热处理分厂目前没有的设备是：（ ）", "options": ["加热电炉", "冰冷处理炉", "真空除氢炉", "燃气炉"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。分厂现有设备包括加热电炉、冰冷处理炉（冷处理用）、真空除氢炉等电加热设备，目前没有**燃气炉**（以天然气/煤气为燃料的炉子）。电炉控温精度高、环境友好，适用于航空锻件热处理。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 283, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "井式炉中变频器的作用是（ ）。", "options": ["保护循环风机电机及调速", "控制加热元件输出大小", "控制台车行走方向和速度", "对炉门开关状态的安全保护"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。井式炉中变频器的作用是**保护循环风机电机及调速**——通过变频调节风机转速（实现软启动减少冲击、调节搅拌强度），同时具有过流/过压/缺相保护功能，延长电机寿命。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 284, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "真空炉在加热保温过程中如果出现停电的情况，应当立即进行（ ）", "options": ["打开手动放气阀放气", "放掉循环管路中循环水", "关闭循环水箱的进水阀", "什么都不用做"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。真空炉加热保温中停电→应立即**放掉循环管路中循环水**——停电后真空泵和水泵停止工作，若循环水仍留在管路中可能因温度变化产生压力、损坏管路，或在恢复供电后因水质问题堵塞水路。不可随意打开放气阀破坏真空。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 285, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "为了保障人身安全，在正常情况下，电气设备的安全电压规定为（ ）。", "options": ["380V以下", "36V以下", "220V以下", "1000KV以下"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。国家标准规定安全电压为**36V以下**（干燥环境，50V以下；潮湿环境24V/12V），超过36V的电压对人体有触电危险。380V/220V为动力和照明电压，1000kV为特高压输电等级。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 286, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "配电柜内功率控制器、变频器等电器显示有“E”开头的字母表示检测到（ ）。", "options": ["正常运行", "未工作状态", "正在远程通讯", "故障指示"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。配电柜内控制器/变频器显示\"E\"开头表示**故障指示**（Error/Error代码），如E-01过流故障、E-02过压故障等。数字具体指明故障类型，需查设备说明书对应排查处理。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 287, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "热处理分厂哪种炉型的加热电炉有使用到触头结构（ ）。", "options": ["箱式电炉", "井式电炉", "台车式电炉", "高架式电炉"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。**台车式电炉**使用触头结构——台车与炉体之间通过滑动触头（大电流铜触头）连接加热电源，台车进出时触头自动断开/闭合。箱式炉和井式炉加热元件直接接线无需可分离触头。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 288, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "221A进出料机械手地基处齿条的作用是（ ）。", "options": ["大车行走轨道校正", "进出料机械手供电", "编码器行走记录", "通讯线路走线"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。221A机械手地基处齿条作用是**编码器行走记录**——齿轮齿条机构将机械手直线行走位移转换为编码器旋转信号，精确记录机械手位置，实现自动定位控制。不是轨道、供电或通讯功能。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 289, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "属于分厂有限空间的区域是（ ）。", "options": ["井式炉地坑", "炉膛内部空间", "胀形机油箱地坑", "油槽内部空间"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "A正确。**井式炉地坑**属于有限空间——深度>1.2m，通风不良、存在缺氧/有害气体积聚风险。进入前需检测氧气含量和有害气体浓度，强制通风并有人监护。炉膛内部、油槽内部虽也有风险但地坑是典型受限空间。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 290, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "炉门下限位是与其中哪个动作或状态互锁（ ）。", "options": ["加热运行", "炉门上限位", "台车前限位", "仪表电源开"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。炉门下限位（炉门关闭到位信号）与**加热运行**互锁——炉门未关闭到位时加热电路不接通，防止热量散失和操作人员烫伤。炉门开则加热停，这是基本安全联锁。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 291, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "真空除氢炉在无生产任务时应进行哪些操作（ ）。", "options": ["无须理会", "关闭炉门", "关闭炉门并抽真空至80Pa以下", "关闭炉门并抽真空至80Pa以下后再关停设备"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。真空除氢炉闲置时应：关闭炉门→抽真空至80Pa以下（保持真空状态防潮防氧化）→**关闭设备**（切断电源和真空泵）。只关炉门不抽真空会导致炉内重新吸潮，影响下次使用。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 292, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "炉子在加热过程中三个区突然同时断电，可能的原因有（ ）。", "options": ["炉门下限位开关失效", "控制柜塑壳断路器跳闸", "风机故障", "以上皆有可能"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。三个区同时断电可能原因：炉门限位失效→互锁切断加热；塑壳断路器跳闸→总电源保护断开；风机故障→联锁保护断电。三种原因**均有可能**，需逐一排查确定。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 293, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "仪表出现故障时应该（ ）。", "options": ["汇报分厂领导", "找设备室处理", "找机修班处理", "找仪表工处理"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。仪表出现故障→找**仪表工**处理——仪表工是专门负责仪器仪表维护、校准和修理的专业人员。领导负责协调决策、设备室负责设备管理、机修班负责机械设备维修，仪表工作为专业分工应由仪表工主导。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 294, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "炉子循环风机出现异响后检查，发现固定螺杆松动应该（ ）。", "options": ["班组自行紧固", "找机修处理", "如班组无法自行紧固再通知机修", "报告领导"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。循环风机异响→固定螺杆松动，处理流程：**先试自行紧固**（如工具和技能可行），若无法自行处理（如需要专用工具或螺杆断裂）→再通知机修班处理。TPM理念强调\"能自己修的绝不推给维修\"。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 295, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "221a-2#、3#炉加热区的分区方式是（ ）。", "options": ["上中下", "前中后", "左中右", "里外"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。221a-2#/3#井式炉加热区按**前中后**分区（沿炉膛深度方向），每个区独立控温、独立配置热电偶和加热元件。井式炉的上中下分区是另一种常见分区方式，取决于炉子设计。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 296, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "在自主维护活动中，需要参与的室组有（ ）", "options": ["机修班", "设备室", "现场班组", "以上全是"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。自主维护活动需全员参与：机修班（专业维护支持）、设备室（技术管理）、现场班组（日常点检清扫紧固）**全部都要参与**，各自承担不同层面的维护职责，形成\"操作者—专业维修—设备管理\"三位一体。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 297, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "OPL的作用是（ ）。", "options": ["TPM文件资料收集分类", "相互学习，共同提高", "提高写作能力", "与班组成员培养感情"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。OPL（单点课/点滴教育）的核心作用是**相互学习，共同提高**——通过简短（5~10分钟）的点滴知识分享，让班组成员之间交流经验、传递技能、改进操作方法，提升团队整体水平。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 298, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "在班组自主维护活动时，发现设备故障时应及时联系（ ） (×A、设备室", "options": ["设备室", "机修班", "分厂领导", "调度室 (× (×"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。自主维护中发现问题处理流程：一般问题（清扫、紧固）→班组自行处理；发现设备故障→联系**机修班**（专业的设备维修人员）进行检修。设备室负责技术管理，领导负责决策协调，直接维修由机修班执行。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 299, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "TPM看板上自主维护活动应与哪个表格相对应（ ） (×", "options": ["FMEA表", "OPL点滴教育 ()", "不合理事项记录表", "故障推移图 （"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。TPM看板上的自主维护活动与**不合理事项记录表**对应——记录发现的不合理/异常事项（如松动、漏油、异响等），\"发现→记录→整改→确认\"形成闭环管理。FMEA是失效分析、OPL是知识分享、故障推移图是趋势分析。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 300, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "TPM的根本目标是（ ） 可", "options": ["通过重复的小组活动，提高员工素质", "从总经理到第一线生产工作人员全体参与", "追求零缺陷，提高企业素质", "延长生产设备的生命周期"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。TPM（全员生产维护）的根本目标是**追求零缺陷，提高企业素质**——零故障、零不良、零灾害。通过全员参与的预防维护体系，持续改进设备管理和人员素养。延长设备寿命、提高员工素质是实现零缺陷的手段而非根本目标。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 301, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "设备线路接头出现接触不良发生打火的情况，如不影响生产，可 继续安排生产。", "answer": "×", "explanation": "错误。设备线路接头打火（接触不良产生火花）**必须**立即停电处理——打火会产生高温、可能引燃周围可燃物→引发火灾，也会烧损接头导致更严重故障。\"带病作业\"是严重安全违章。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 302, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "221A进出料机械手在冬天运行时，应提前开启电机油泵对液压油 进行预热。", "answer": "√", "explanation": "正确。冬季液压油黏度增大流动性变差→直接影响机械手动作响应速度和精度。运行前应先开启电机油泵循环预热液压油至正常工作温度（通常20~50℃），保证系统正常工作。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 303, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "装炉作业中，只要保证产品放在炉内不接触加热元件，就可以进行生产。", "answer": "×", "explanation": "错误。装炉要求不限于不接触加热元件：还要保证工件在炉膛**有效加热区**内（炉温均匀性合格区域），按规定装炉方式（间距、叠装层数、负载偶位置等）摆放，确保加热均匀和工艺质量。非有效加热区温度可能偏差超出工艺允差。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 304, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "设备出故障时，机修班对其进行修理，生产班组无需对待修设备做警示。", "answer": "×", "explanation": "错误。设备待修时必须由**生产班组**设置警示标识（如\"设备待修 禁止合闸\"挂牌），防止不知情人员误操作→造成人身伤害或设备二次损坏。安全警示是设备使用者（操作班组）的责任。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 305, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "热处理分厂厂房内自来水管道是涂装为黄色的管道。", "answer": "×", "explanation": "错误。厂房内管道涂色有标准规范：自来水通常为绿色、消防管为红色、压缩空气为蓝色/灰色、蒸汽管为红色。**黄色**管道通常是天然气/燃气管道标识色（按GB 7231-2003管道标识标准）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 306, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "加热电炉上安装有循环风机的炉子都可以进行定速降温流程。", "answer": "×", "explanation": "错误。不是所有带循环风机的电炉都能定速降温——定速降温需要特殊设计的降温系统（如可控的排风/进风系统、降温开关旋钮等）。普通循环风机只能搅拌炉内气氛保持均匀性，不具可控降溫能力。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 307, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "分厂吊车由维保单位进行保养修理，班组可不对其进行保养管理。", "answer": "×", "explanation": "错误。TPM体系要求全员参与维护——班组对吊车同样有日常点检和保养责任（检查钢丝绳磨损、吊钩变形、限位器功能等），维保单位负责计划性专业维修。操作者是设备第一责任人。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 308, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "吊车在作业完成后，吊具仍悬挂在吊钩上。", "answer": "×", "explanation": "错误。吊车作业完成后吊具**必须**从吊钩上取下——悬挂吊具存在坠落伤人/损坏设备风险（吊具可能滑脱），且长期悬挂使吊钩受力可能产生变形。吊具应存放在专用架上。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 309, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "厂房内自然光照充足的情况下开启照明灯。", "answer": "×", "explanation": "错误。自然光照充足时开启照明灯浪费能源——应根据实际需要开关照明，充分利用自然采光。\"人走灯灭、随手关灯\"是节能基本要求。只有光照度不足时才开启补充照明。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 310, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "221a厂房10T机械手启动时操作者无须在现场，在班组休息室里即可启动。", "answer": "×", "explanation": "错误。10T机械手启动时操作者**必须**在现场——大型设备启动存在安全风险（挤压、碰撞），操作者需确认设备周围无人、无障碍物、各联锁装置正常，才能启动。远程或不在现场启动是严重违章。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 311, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "锻件在油淬后进炉烘干时应将炉门关死，防止油烟外泄。", "answer": "×", "explanation": "错误。锻件油淬后表面残留淬火油，进炉烘干时油汽化产生大量油烟（含油雾和裂解产物）。若将炉门关死→油烟浓度急剧升高→有爆炸风险+炉内结焦污染工件/炉膛。正确做法：烘干时炉门留缝隙排烟，或先晾干再进炉，或使用带排烟装置的清洗烘干联机设备。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 312, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "打磨修伤时应佩戴防尘口罩和护目镜。", "answer": "√", "explanation": "正确。打磨修伤（去除表面缺陷、修磨飞边等）产生金属粉尘和飞溅→必须佩戴防尘口罩（防止吸入金属粉尘引发尘肺）和护目镜（防止飞屑射入眼睛造成伤害）。这是基本劳动防护要求。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 313, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "出炉后应立即关停循环风机的冷却循环。", "answer": "×", "explanation": "错误。出炉后不应立即关停循环风机冷却循环——炉温仍较高时风机需继续运行一段时间，帮助炉膛均匀降温、保护加热元件和炉衬不被急冷损坏。应待炉温降至安全温度以下再停风机。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 314, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "炉子控制柜门不允许常开。", "answer": "√", "explanation": "正确。控制柜门不允许常开——常开会：①灰尘进入导致电器故障；②人员误触带电部件→触电风险；③柜内冷却风道破坏→电器过热。巡检后应及时关门。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 315, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "302淬火水槽在水温满足工艺要求时应及时关闭进水", "answer": "√", "explanation": "正确。淬火水槽水温是淬火效果的关键参数：水温过高→蒸汽膜阶段延长→最大冷却速度降低→可能导致淬不硬/软点/硬度不均。操作规程：水温应在工艺规定范围（通常<40℃），满足要求时关闭进水以节约用水，但需持续监测→水温超标时及时开启进水冷却。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 316, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "设备出现故障时只要不影响生产可继续带病作业，无须上报", "answer": "×", "explanation": "错误。设备出现故障即使暂时不影响生产也**必须上报**——\"带病作业\"可能：①小故障演变成大故障（如轻微异响→轴承卡死→电机烧毁）；②产品质量受影响（如温控不稳定）；③存在安全隐患（如漏电/漏气）。必须记录并安排维修计划。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 317, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "应随时注意调整炉底板位置以防错位，并及时清理氧化皮。", "answer": "√", "explanation": "正确。炉底板长期使用会偏移（因热胀冷缩和装出炉碰撞），偏移过大→工件可能接触加热元件或掉落。氧化皮积聚→影响炉膛有效空间和传热效率。需随时调整炉底板位置、及时清理氧化皮。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 318, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "油槽淬火时不必开启厂房排烟装置", "answer": "×", "explanation": "错误。油槽淬火时赤热工件入油→淬火油局部高温汽化→产生大量油烟（含油雾、多环芳烃等有害物）→对操作人员呼吸系统危害极大→必须开启厂房排烟装置。此外，油烟积聚有燃爆风险，排烟是安全生产强制要求，不可因任何理由关闭。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 319, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "点检的重点就是要找出设备的不正常现象。", "answer": "√", "explanation": "正确。点检（日常检查）的核心目的就是找出设备的异常/不正常现象（异响、松动、发热、漏油、异味、振动等），及早发现问题→及早处理→防止发展为大故障。这是预防性维护的基础。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 320, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "清扫的目的是一边发现不合理，一边清除污垢。", "answer": "√", "explanation": "正确。清扫（TPM自主维护第一步）的目的不仅是清洁表面——更重要的是在清扫过程中**发现不合理/异常**（漏油、松动、裂纹、磨损等），一边清除污垢一边检查隐患。清扫即检查。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 321, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "自主维护保养体系是以维修人员为主，对设备进行检查、维护，并对小故障进行修理。", "answer": "×", "explanation": "错误。自主维护（AM）体系是以**操作人员为主**，对设备进行日常检查、清扫、润滑、紧固和简单维护——\"自己使用的设备自己维护\"。维修人员负责更专业和复杂的计划性维修，两者分工不同。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 322, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "在自主维护活动中不需要检查紧固件是否松动。", "answer": "×", "explanation": "错误。紧固件检查是自主维护的基本工作之一——螺栓松动是设备最常见问题之一（因振动、热胀冷缩），可能导致连接失效、漏油、异响甚至安全事故。必须定期检查紧固。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 323, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"id": 324, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "操作者只负责操作设备，不需要对设备进行检查维护。 三填空题", "answer": "√", "explanation": "错误。设备操作者是设备的第一责任人，不仅负责操作，还必须进行日常检查、点检和维护（TPM体系基本要求）。专业人员负责计划性维修，但日常维护（清洁、润滑、紧固、调整）由操作者完成。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 325, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "真空炉生产结束后，待炉膛内温度低于______行出炉作业。", "answer": "200度", "explanation": "真空炉生产结束后，需待炉膛温度降至**200℃**以下方可出炉作业——防止高温出炉导致工件氧化变色（真空炉虽有保护但高温下残余氧仍可氧化）、防止烫伤操作人员、防止炉内加热元件急冷损坏。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 326, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "定速降温炉在进行非定速降温工艺生产时，应先检查______保证其置于关闭档，方可进行正常生产。", "answer": "降温开关旋钮", "explanation": "定速降温炉在进行非定速降温工艺时，需先检查**降温开关旋钮**是否置于关闭档位，否则炉子可能按预设降温曲线运行而非所需工艺，导致产品质量事故。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 327, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "铝合金、空气淬火炉在出炉时必须保证______灯亮和______灯亮，方可打开炉门进行下降作业。", "answer": "料框升，穿销位", "explanation": "铝合金空气淬火炉出炉安全联锁：**料框升**灯亮确认料框在上升到位位置，**穿销位**灯亮确认安全销已插入，两个条件同时满足才能打开炉门下降作业，防止料框坠落造成安全事故。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 328, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "目前热处理分厂井式炉上有______台循环风机。", "answer": "三台", "explanation": "井式炉上一般配置**3台**循环风机（顶部、中部、底部或按炉膛分区），通过强制对流使炉内气氛和温度均匀分布，保证炉温均匀性（通常<±10℃甚至<±5℃）。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 329, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "10T机械手装出炉位有两种，分别是______、______。", "answer": "全炉位，半桥", "explanation": "10T机械手装出炉位包括**全炉位**（整炉料一次装入/取出）和**半桥**（可使用桥式夹具只装出半个炉膛的料），两种方式适应不同批量和规格的生产需求。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 330, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "分厂电炉的加热元件主要有两种，分别是______、______。", "answer": "电阻带，电炉丝", "explanation": "分厂电炉加热元件主要有**电阻带**（波纹状或蛇形金属带，表面积大、辐射效率高，用于中温炉）和**电炉丝**（螺旋状电阻丝，常用Cr20Ni80或0Cr25Al5材料，用于管式炉和箱式炉）。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 331, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "分厂蒸汽发生器主要是给水槽进行______。", "answer": "加热", "explanation": "蒸汽发生器给水槽进行**加热**——用蒸汽加热水槽中的淬火液（水或水溶液），保持淬火介质温度在工艺要求范围（通常20~60℃），保证淬火冷却速度稳定。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 332, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "炉子循环风机主要作用是为了保证炉温______。", "answer": "均匀性", "explanation": "循环风机主要作用是保证炉温**均匀性**。通过强制对流搅拌炉内气氛，消除自然对流形成的温度分层（上高下低），使炉内各处温差控制在工艺允差范围内，确保工件加热均匀。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 333, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "自主维护活动的基本工作______、清扫、加润滑油、整理和整顿、简单维修和更换。", "answer": "点检、紧固", "explanation": "自主维护活动的基本工作包括**点检**（检查设备状态和异常）、清扫、加润滑油、整理和整顿、简单维修和更换。此外，**紧固**（螺栓、连接件检查紧固）也是基础工作之一，防止松动导致故障。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 334, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "在自主维护活动中应按照______对设备进行清扫。", "answer": "清扫标准", "explanation": "自主维护活动中应按照**清扫标准**（规定清扫部位、方法、频次、工具、判定标准）对设备进行清扫，保证清扫质量一致、可检查、可持续，而非随意清扫。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 335, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "根据导规管理规定，绿色表示______导线，黄色表示______导线，红色表示______导线。", "answer": "1级，2级，3级", "explanation": "导线颜色管理规定：**1级**导线绿色（安全电压/信号线）、**2级**导线黄色（控制线路）、**3级**导线红色（动力/主回路），分级颜色标识便于快速识别线路功能和排查故障。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 336, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "在自主维护活动时应对______进行着重检查。", "answer": "近期故障频发点", "explanation": "自主维护活动时应对**近期故障频发点**着重检查。TPM核心思想是预防为主，通过统计设备故障历史，识别薄弱环节并优先检查和改善，减少非计划停机。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 337, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "班组应在______对设备一保内容一一对应进行检查。", "answer": "设备使用前", "explanation": "班组应在**设备使用前**对设备的一级保养（一保）内容逐项检查确认，确保设备处于完好状态方可使用，将问题消灭在萌芽中，贯彻\"预防为主\"的设备管理理念。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 338, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "TPM的三大思想是______、零缺陷、小组活动。", "answer": "预防", "explanation": "TPM（全员生产维护）三大思想：**预防**（预防为主，消灭于萌芽）、零缺陷（追求零故障、零不良、零灾害）、小组活动（全员参与，自主管理）。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 339, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "现场班组应定期对设备进行______查找问题，发现隐患并及时解决。", "answer": "自主维护活动", "explanation": "现场班组应定期开展**自主维护活动**（清扫、点检、润滑、紧固），通过日常维护查找设备隐患和微缺陷，发现并及时解决，形成预防性维护体系。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 340, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "OPL的编号规则是：______。", "answer": "单位+年份月份+小组名称+当月篇数", "explanation": "OPL（One Point Lesson，单点课）编号规则：**单位+年份月份+小组名称+当月篇数**。例如\"锻造-202607-甲班-05\"表示锻造分厂2026年7月甲班第5篇OPL。编号便于归档管理和检索。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 341, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "设备水箱水位不能低于总水位的______。", "answer": "一半", "explanation": "设备水箱水位不能低于总水位的**一半（1/2）**。水位过低会导致水泵抽空、冷却能力不足、甚至烧毁加热器（电热元件露出水面干烧），必须定期检查和补水。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"id": 342, "type": "fill", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "定期使用压缩空气对配电柜内______进行清扫，防止设备因过热导致断电停机。", "answer": "调功器散热片", "explanation": "定期用压缩空气清扫配电柜内**调功器散热片**上的灰尘——灰尘积聚影响散热效果，导致调功器（晶闸管功率控制器）过热保护跳闸或烧毁，造成设备断电停机。", "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "生产中所说的水淬油冷属于（ ）。", "options": ["双液淬火", "分级淬火", "延时淬火"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "生产中\"水淬油冷\"即双液淬火法：先在冷却能力强的水中快冷至Ms点稍上（约300-400℃）→迅速转入油中缓冷通过马氏体转变区。优势：水中快速避开珠光体→保证淬硬，油中缓慢通过Ms点→减小组织应力→防开裂。是最实用的兼顾淬硬和减变形的方法，适用于中高碳钢和合金钢工件。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 343, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "钢淬火后所形成的残余应力为（ ）。", "options": ["使表层处于受压状态", "随钢中和冷却方法而变", "为表面拉应力", "使表层处于受拉状态"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "淬火残余应力最终状态=热应力+组织应力综合作用的结果。热应力使表面受压（表面先冷收缩被心部拉→心部后冷→表面反受压），组织应力使表面受拉（表面先转变马氏体膨胀→心部后转变膨胀将表层撑拉）。哪一方占主导取决于钢种（含碳量/合金元素）、截面尺寸和冷却方法→应力状态随之变化（B）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 344, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "工件在淬火过程中，导致尺寸变化的根本原因是（ ）。", "options": ["组织转变（相变）", "热应力和组织应力", "工件形状设计不合理"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "工件淬火尺寸变化的根本原因是相变导致的比容（单位质量体积）变化：奥氏体（面心立方，原子排列最密→比容最小）→马氏体（体心正方，碳过饱和→晶格畸变→比容最大），体积膨胀率约1-4%。比容差是尺寸变化的本质驱动力，热应力/组织应力（B）影响的是形状和附加变形而非根本原因。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 345, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "工件淬火回火的目的是（ ）。", "options": ["获得优良的综合机械性能", "提高合金元素在固溶体中的溶解度", "通过淬火使表层处于受压状态，再通过回火消除内层的拉应力", "获得强度很高的淬火马氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。淬火+回火（调质处理）的目的是获得**优良的综合机械性能**——强度、塑性、韧韧良好匹配。淬火获得马氏体（硬而脆），回火调整硬度/强度/塑韧比例。选项D片面（淬火马氏体不是最终目的），选项B是固溶处理的目的，选项C描述不准确。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 346, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "盐水溶液在碳钢过冷奥氏体不稳定区(500~600℃)的冷却能力比水大的原因是（ ）。", "options": ["在红热工件表面析出的盐立即爆炸，将蒸气膜破坏的缘故", "在水中加入氯化钠后便不会形成蒸气膜", "淬火时由于盐的爆炸加快了对流"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。盐水在500~600℃高温区冷却能力比水强，原因是红热工件表面析出的盐晶体受热爆炸，机械性地破坏蒸气膜（蒸气膜是冷却瓶颈，阻碍热传导），使冷却介质直接接触工件，大大加快冷却速度。选项B错误：盐水中仍会形成蒸气膜，只是被破坏得更快。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 347, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "钢中的奥氏体和索氏体，从合金结构角度来看（ ）。", "options": ["奥氏体是固溶体，索氏体是机械混合物", "奥氏体是固溶体，索氏体是金属化合物", "两者都是固溶体", "两者都是机械混合物"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。奥氏体是碳在γ-Fe中的间隙固溶体（溶质碳溶入溶剂γ-Fe的fcc晶格中），保持γ-Fe的晶体结构。索氏体是铁素体+渗碳体的细片层状机械混合物（片间距~0.25μm，比珠光体更细），两种相保持各自结构和性能。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 348, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "本质细晶粒钢是指（ ）。", "options": ["在任何加热温度下都具有细小奥氏体晶粒的钢", "在某个规定温度下加热时，奥氏体晶粒长大的倾向较小的钢", "原材料晶粒较小的钢，淬火加热时晶粒细小的钢"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "本质细晶粒钢的确定义：在规定试验温度（通常930±10℃）下加热，奥氏体晶粒长大倾向较小的钢，与其原材料晶粒大小无关（C错）。含Al/Ti/Nb等元素的钢中形成AlN/NbC等细小弥散质点钉扎晶界→阻碍晶粒长大→属本质细晶粒钢。但超过晶粒粗化温度（质点溶解）后也会迅速长大（A错，不是\"任何温度\"）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 349, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "热作模具淬火加热后冷却前，应预先冷至淬火温度而后再淬火，预冷温度范围是（ ）。", "options": ["720~750℃", "750~780℃", "780~810℃"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "热作模具淬火加热温度高（1000-1100℃），直接淬入介质温差极大→热应力过大→变形开裂风险高。预冷（延迟淬火）=表面从加热温度降至750-780℃（仍>Ar3，不会析出先共析铁素体→不影响淬火硬度）再淬火→减小热冲击温差→降低热应力。720℃（A）太低→可能落入两相区析出铁素体，810℃（C）温差仍偏大。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 350, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "亚共析钢加热到AC3点时", "options": ["铁素体开始自奥氏体中析出", "开始发生奥氏体转变", "奥氏体开始转变为珠光体", "铁素体全部溶入奥氏体中"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "亚共析钢加热过程中：Ac1→铁素体开始转变为奥氏体（共析转变）；Ac1→Ac3→铁素体逐渐溶入奥氏体中减少；Ac3→铁素体全部溶入奥氏体→全奥氏体。Ac3点是铁素体完全消失/全奥氏体化的温度。A/B/C描述的是其他温度区间的情况。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 351, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "某钢在淬火后进行冷处理，若淬火后钢件在室温停留的时间愈大，则（ ）。", "options": ["奥氏体稳定化愈弱，冷处理效果愈好", "奥氏体稳定化愈弱，冷处理效果愈差 不合理", "奥氏体稳定化愈强，冷处理效果愈好", "奥氏体稳定化愈强，冷处理效果愈差"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "淬火后室温停留时间越长→残余奥氏体陈化稳定化效应越强→位错与溶质原子（碳）钉扎奥氏体/马氏体界面→后续冷处理时马氏体转变阻力越大→冷处理效果越差。因此冷处理应在淬火后立即进行（间隔<30分钟效果最佳）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 352, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "正火T8钢与完全退火T8钢相比（ ）。", "options": ["前者珠光体更细密，故0b要高些", "前者珠光体更细密，故0b要低些 大的", "前者珠光体更粗大，故0b要低些", "前者珠光体更粗大，故0b要高些"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。正火冷却速度（空冷）大于完全退火（炉冷），因此正火T8钢的珠光体片间距更细密（索氏体型珠光体），强度（σb）和硬度更高。完全退火获得粗片状珠光体，强度较低但塑性更好。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 353, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "纯铁的最低再结晶温度为(纯铁熔点1535℃)：（ ）。", "options": ["约614℃", "约450℃", "约650~700℃", "约723℃"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。再结晶温度T_再≈0.35~0.4 T_m（绝对温度）。纯铁熔点1535+273=1808K，T_再≈0.35×1808=633K=360℃~0.4×1808=723K=**450℃**。所以纯铁最低再结晶温度约450℃。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 354, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "choice", "question": "珠光体的形成过程是（ ）。", "options": ["渗碳体在铁素体晶界生核和长大的过程", "铁素体和渗碳体同时生核和长大的过程", "铁素体和渗碳体基体中生核和长大的过程", "铁素体和渗碳体交替生核和长大的过程"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。珠光体形成过程：铁素体和渗碳体**交替生核和长大**——先在晶界生核一个铁素体片，其旁侧奥氏体中碳富集→渗碳体在其侧面生核→如此交替推进形成层片状共析组织。不是两者同时生核，而是交替领先。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 355, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "钢的热硬性主要取决于（ ）。", "options": ["钢的含碳量", "马氏体的含碳量", "残余奥氏体量", "马氏体回火稳定性"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "钢的热硬性（红硬性）=在高温下保持高硬度的能力。其根本取决于回火稳定性——淬火钢在回火时抵抗硬度下降的能力。强碳化物形成元素（W/Mo/V/Cr）阻碍碳扩散和碳化物聚集→提高回火稳定性→热硬性好（如高速钢W18Cr4V可在600℃下保持HRC60+）。含碳量（A/B）决定淬硬性而非热硬性。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 356, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "高碳钢制工具，若提高其硬度和耐磨性，常进行（ ）。", "options": ["渗碳，淬火和低温回火", "加热到ACcm以上温度淬火和低温回", "加热到AC1+(30~50℃)温度淬火和低温回火", "表面淬火"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。高碳工具钢提高硬度和耐磨性的方法：加热到Accm以上温度完全奥氏体化，使全部碳化物溶解，淬火后获得高碳马氏体（硬度最高），再低温回火（150~200℃）消除应力、保留高硬度。选项C（Ac1+30~50℃）是不完全淬火，适用于过共析钢保留颗粒状碳化物。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 357, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "把经淬火时效的铝合金，迅速加热到200~300℃或略高一些的温度，保温2~3min，在清水中冷却，使其恢复到淬火状态，这种工艺叫做（ ），D、稳定化回火", "options": ["低温回火", "再结晶退火", "高温回火", "稳定化回火"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "C正确。铝合金回归处理：将经淬火时效的铝合金加热到200~300℃保温2~3min（短时间），在清水中冷却→时效析出物重新溶解→恢复到淬火状态（过饱和固溶体）。该现象是可逆的，但重复次数有限（析出物重新溶解速度>再析出速度）。此处理也称\"回归处理\"（reversion）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 358, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "珠光体向奥氏体转变时，第一批晶核是在（ ）产生的。", "options": ["铁素体和渗碳体的界面处", "铁素体片中", "渗碳体片中"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。珠光体→奥氏体转变时，奥氏体晶核优先在**铁素体和渗碳体的界面处**产生——界面处原子排列不规则、能量高、扩散容易、成分起伏大→形核功最低→优先形核。铁素体片内和渗碳体片内成分均匀、形核困难。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 359, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "防白点热处理时，为使氢尽快地扩散逸出钢表面，处理温度应取：（ ）", "options": ["Y-Fe稳定存在的最高温度", "γ-Fe稳定存在的最低温度", "a-Fe稳定存在的最高温度", "a-Fe稳定存在的最低温度"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。防白点热处理（脱氢退火）目的是使氢从钢中扩散逸出。氢在α-Fe（体心立方）中的扩散速度远大于在γ-Fe（面心立方）中→应在**α-Fe稳定存在的最高温度**（紧靠Ac1以下的α区接近727℃）进行，既保证扩散速度快，又避免进入γ区。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 360, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "上、下贝氏体的机械性能是（ ）。", "options": ["两者均具有较高的强度和韧性", "两者具有很低的强度和韧性", "上贝氏体具有较高的强度和韧性", "下贝氏体具有较高的强度和韧性"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。**下贝氏体**具有较高的强度和韧性（强韧性匹配好），因为碳化物在铁素体片内弥散分布。上贝氏体因碳化物沿铁素体条间析出导致脆性大、强韧韧差。等温淬火的目的就是得到下贝氏体组织。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 361, "knowledge_point": "珠光体与贝氏体转变", "knowledge_point_key": "pearlite_bainite"}, {"type": "choice", "question": "合金进行相变时的过冷过热现象是（ ）。", "options": ["一种热处理缺陷", "一种人为现象", "促进相变的动力"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "同ID=59。相变需满足热力学条件——新旧相自由能差ΔG<0。过冷（冷到平衡温度以下）或过热（热到平衡温度以上）使ΔG增大→相变驱动力增大。是促进相变的动力（C），不是缺陷（A），也不仅是人为现象（B）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 362, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "把冷塑性变形后的碳钢加热到大约650~700℃，保温1~3h，随后炉冷或出炉缓冷，这种工艺叫做（ ）。", "options": ["再结晶退火", "球化退火", "去应力退火", "扩散退火"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。冷塑性变形后加热到650~700℃（高于再结晶温度），保温1~3h后缓冷，此工艺为**再结晶退火**。目的：使变形拉长的晶粒重新形核长大为等轴晶粒，消除加工硬化、恢复塑性。去应力退火温度低（500~650℃），不改变组织仅消除应力。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 363, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "将冷变形加工后的黄铜加热到500~700℃保温1~2小时后空冷或水冷这种处理叫做（ ）。", "options": ["防季裂退火", "再结晶退火", "高温回火", "稳定化回火"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "黄铜冷变形后加热500-700℃→变形晶粒被无畸变的新等轴晶粒取代（再结晶），消除加工硬化、恢复塑性，称为再结晶退火。黄铜再结晶温度约300-400℃，500-700℃确保完全再结晶。注意区别于防季裂退火（200-300℃去应力，不发生再结晶）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 364, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "钢的耐磨性（ ）。", "options": ["只与钢淬火后的硬度有关", "决定于钢淬火后的晶粒度", "与钢淬火回火后的硬度和碳化物弥散程度关系极大", "随钢的热稳定性的增高而增加"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "钢的耐磨性是综合性能，取决于：①硬度（提供抗压入能力）；②碳化物类型/数量/形态/分布（弥散细小硬质碳化物抵抗磨粒磨损）。淬火+回火后高硬度+弥散碳化物=最佳耐磨性（C）。仅靠硬度（A）不全面，晶粒度（B）影响韧性而非主要耐磨性，热稳定性（D）影响高温耐磨性而非常温。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 365, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "马氏体的硬度主要取决于：（ ）。", "options": ["马氏体的合金元素含量", "获得马氏体的冷却速度", "马氏体的含碳量", "奥氏体的晶粒度"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。马氏体硬度主要取决于其**含碳量**——碳越多→马氏体正方度（c/a）越大→晶格畸变越大→硬度越高。碳对马氏体硬度的贡献远大于合金元素。合金元素主要通过影响淬透性间接影响硬度，而非直接决定马氏体硬度。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 366, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "工件加热时温度过高，奥氏体晶粒粗大，淬火后马氏体粗大，工件断口很粗，这种缺陷称为（ ）。", "options": ["过热", "过烧", "腐蚀", "茶状断口"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "过热=加热温度过高或保温时间过长，奥氏体晶粒异常粗大（晶粒度1-3级），淬火后马氏体针粗大，断口呈粗晶粒状光泽（茶状/闪亮）。与过烧（B）的区别：过烧晶界氧化/局部熔化→不可挽救，过热可通过重新正火细化晶粒挽救。茶状断口（D）可作为过热特征的描述但非缺陷名称。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 367, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "某种淬火介质具有良好的冷却特性，是因为它存在逆溶性，这种淬火介质是（ ）。", "options": ["聚醚水溶液", "食盐水溶液", "三硝水溶液", "聚乙烯醇水溶液"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "聚醚水溶液（PAG）具有逆溶性——温度升高时聚醚从水中析出形成聚合物膜包裹工件（降低冷速、蒸汽膜阶段延长→减小热冲击），温度降低时重新溶解。这种特性使其冷速介于水和油之间，可通过浓度调节，是理想的淬火介质。食盐水（B）和三硝水（C）无逆溶性，聚乙烯醇（D）有一定逆溶性但不如聚醚常用。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 368, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "轴承钢进行预备热处理的目的是得到（ ）。", "options": ["均匀细小的片状珠光体", "均匀细小的索氏体", "均匀细小的托氏体", "均匀细小的球状珠光体"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。轴承钢（如GCr15）预备热处理的目的是获得**均匀细小的球状珠光体**（球化退火）。球状珠光体硬度低（HB180~210），切削加工性好，淬火加热时碳化物溶解均匀，不易过热，最终淬火+回火后获得最佳耐磨性和接触疲劳寿命。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 369, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "为避免精密量具在使用过程中的塑性变形，采取的措施是：（ ）", "options": ["人工时效", "加工硬化", "松弛处理"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。精密量具（如块规、千分尺）为避免长期使用中发生塑性变形（尺寸变化），采取松弛处理——在低于回火温度下长时间保温，使残余奥氏体稳定化、消除微应力，稳定尺寸。人工时效用于铝合金，加工硬化是冷变形产生的。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 370, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "较高精度，不淬硬丝杆的材料为T10~T12A，热处理为（ ）。", "options": ["正火、淬火", "普通退火，调质", "球化退火，调质"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。T10~T12A为高碳工具钢，不淬硬丝杆要求精度高、加工性好。球化退火获得球状珠光体降低硬度便于机加工，调质（淬火+高温回火）获得回火索氏体，综合力学性能好、尺寸稳定性高。正火组织较硬不利于精密加工。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 371, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "A1、A3和Acm三者的关系是（ ）。", "options": ["A1>A3>Acm", "A1<A3<Acm", "A3>A1 Acm>A1", "A3>Acm"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。临界温度关系：A3（亚共析钢的γ→α开始温度）在A1之上；Acm（过共析钢的γ→Fe₃C开始析出温度）在A1之上。A1=727℃是共析转变线。A3和Acm都大于A1，但A3与Acm的相对大小依含碳量而定（在S点相遇）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 372, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "第一类回火脆性的特点是（ ）。", "options": ["具有可逆性", "只有合金钢才有这种脆性或", "与回火后的冷却速度无关", "上述说法都不对"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。**第一类回火脆性**（250~400℃回火出现，又称低温回火脆性）特点是：①在所有钢中（碳钢和合金钢）都可能出现；②具有不可逆性（一旦出现，重新加热到此温度范围仍出现）；③**与回火后冷却速度无关**（快冷也避免不了）。只能避开此温度范围回火。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 373, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "碳素工具(T10A)刃具的最终热处理工艺是：（ ）。", "options": ["淬火（不必回火）", "淬火+低温回火(150~200℃)", "淬火+中温回火(350~450℃)", "淬火+高温回火(500~650℃)"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。T10A为碳素工具钢，制作刃具的最终热处理为**淬火+低温回火（150~200℃）**。淬火获得高碳马氏体（高硬度），低温回火保留高硬度（≥60HRC）的同时消除淬火应力、提高韧韧性和耐磨性。刃具不需要中温/高温回火，那会导致硬度大幅下降。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 374, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "用轴承GCr15制造轴承零件，若在热压成型后有粗大网状碳化物，应采用如下预备热处理方法。（ ）", "options": ["完全退火", "球化退火", "完全退火+球化退火", "正火+球化退火"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。GCr15轴承钢热压成型后有粗大网状碳化物——网状碳化物无法通过球化退火消除。必须先**正火**（加热到Accm以上使网状碳化物全部溶解，空冷后抑制网状再析出），再**球化退火**获得均匀球状珠光体。完全退火不能消除网状碳化物。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 375, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "为使过共析钢形成单相奥氏体，应将其加热到（ ）。", "options": ["AC3点以上", "A1点以上", "Acm点以上", "Arcm点以上"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "过共析钢要获得单相奥氏体理论上需加热到Acm以上（渗碳体全部溶入奥氏体），Acm是加热时的上临界温度。Arcm是冷却时渗碳体开始从奥氏体析出的温度，属于冷却参数而非加热参数。但实际生产中过共析钢通常不加热到Acm以上（晶粒粗大+氧化脱碳严重），而是在Ac1-Acm之间（保留部分粒状渗碳体以细化晶粒）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 376, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "合金进行相变时的过冷和过热现象是（ ）。", "options": ["一种热处理缺陷", "一种人为现象", "促进相变的动力。"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "同ID=59和ID=362。过冷和过热为相变提供热力学驱动力（自由能差ΔG），是相变发生的必要条件，不是缺陷（A）。人为现象（B）不准确——这是热力学客观规律。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 377, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "回火时残余奥氏体的转变是在（ ）。", "options": ["升温过程中进行的", "保温过程中进行的", "冷却过程中进行的", "冷却后的放置过程中进行的。"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "残余奥氏体在回火冷却过程中发生转变（200-300℃区间→Ar→α+碳化物/下贝氏体）。加热和保温阶段残余奥氏体处于热稳定化状态（碳原子进一步富集→更稳定），冷却过程中过冷驱动力增大→Ar分解。注意与淬火时马氏体转变不同——回火冷却时的Ar转变产物含碳化物。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 378, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "合金工具钢进行预备热处理时，通常采用（ ）工艺。", "options": ["完全退火", "正火", "球化退火", "扩散退火"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。合金工具钢（如Cr12、W18Cr4V等）含碳量高且含合金碳化物形成元素，预备热处理通常采用**球化退火**——加热到Ac1+20~30℃保温后缓冷，使碳化物球化。硬度适中（HB200~250），便于切削加工并为最终热处理准备良好组织。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 379, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "要使合金具有时效硬化能力，将合金加热至高温单相区并保持足够时间后，应使其（ ）。", "options": ["先快后慢地冷却", "缓冷", "先慢后快地冷却", "快冷。"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "要使合金具有时效硬化能力，必须获得过饱和固溶体。加热到高温单相区→溶质全部固溶→快冷（淬火）抑制第二相析出→室温获得过饱和固溶体（亚稳态）→后续时效时溶质以细小弥散第二相析出→强化。缓冷（B）会在冷却过程中析出粗大平衡相→丧失时效驱动力。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 380, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "钢的热稳定性愈高，则其( ()。", "options": ["硬度愈高", "组织愈均匀", "回火稳定性愈好", "强度和韧性愈好。"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "钢的热稳定性=在高温长期运行中保持组织和性能稳定的能力。热稳定性越高→回火稳定性越好（抵抗高温回火软化的能力越强）。热稳定性与回火稳定性本质上是同一概念的不同表述角度，均受合金元素（Cr/Mo/W/V）控制。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 381, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "二次硬化法在生产中较少使用的原因是（ ）。", "options": ["处理后钢的硬度较低", "处理后钢的韧性较差，热处理变形较大", "这种工艺的生产效率低", "所获得的硬度不如一次硬化法高。"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "二次硬化法=淬火后在500-600℃回火，利用合金碳化物（Mo₂C/W₂C/V₄C₃等）弥散析出产生硬度回升。缺点：①高温回火变形大（温度高+碳化物析出体积效应）；②韧性较差（碳化物沿晶界析出→晶界弱化）。一次硬化法（低温回火）变形小、韧性好、工艺简单→更常用。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 382, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "choice", "question": "相变是导致工件尺寸变化的（ ）。", "options": ["主要原因", "次要原因", "原因", "根本原因"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。相变是导致工件尺寸变化的**根本原因**——马氏体转变时体积膨胀（bct结构c/a>1导致比容增大，约4%）、热胀冷缩的热应力是次要的。根本原因意味着从物理本质上相变决定了尺寸变化，其他因素都是叠加效应。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 383, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "用高碳钢和某些合金钢制锻坯件，加工时发现硬度过高，为使其容易加工，可进行（ ）处理。", "options": ["退火", "正火", "淬火", "淬火和低温回火"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。高碳钢和合金钢锻坯硬度过高不利于机加工→应进行**退火**降低硬度。完全退火（亚共析钢）或球化退火（过共析工具钢）可将硬度降至HB180~220。正火冷却较快硬度仍偏高。淬火会使硬度更高更无法加工。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 384, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "为改善T10钢的机械性能和组织状态，一般预先热处理方法为（ ）。", "options": ["正火", "完全退火", "扩散退火", "球化退火"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。T10为过共析碳素工具钢（C≈1.0%），最佳预备热处理为**球化退火**（加热至Ac1+20~30℃，保温后缓冷），得到球状珠光体，硬度低（HB≤197）利于切削，淬火加热时碳化物不易长大、组织均匀。完全退火不适用于过共析钢（会产生网状渗碳体）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 385, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "第二类回火脆性的特点是（ ）。", "options": ["主要在含Cr、Ni等元素的合金钢中出现", "与回火后的冷速无关", "具有不可逆性", "上述都不是"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。**第二类回火脆性**（450~650℃回火后慢冷出现）特点：①**主要在含Cr、Ni、Mn等合金元素的合金钢中出现**；②与回火后冷却速度有关（快冷可防止，慢冷出现）；③具有可逆性（重新加热到原回火温度后快冷可消除）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 386, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "马氏体的硬度和强度（ ）。", "options": ["决定于钢的含碳量", "决定于残余奥氏体量的多少", "与碳化物形成元素的含量有关", "决定于原始奥氏体的含碳量。"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "马氏体的硬度和强度主要取决于钢的含碳量——碳是马氏体固溶强化的核心元素。含碳量↑→马氏体正方度(c/a)↑→晶格畸变程度↑→硬度强度显著↑。残余奥氏体量（B）增多会降低整体硬度但非硬度的本质决定因素；合金碳化物（C）主要在回火时析出影响二次硬化。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 387, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "对于同一种钢来讲，二次硬化程度主要决定于（ ）。", "options": ["回火时间的长短", "球化组织的好坏", "淬火加热温度的高低", "回火冷却速度的快慢。"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "二次硬化程度主要取决于淬火加热温度——淬火温度越高→合金元素（W/Mo/V/Cr等）固溶于奥氏体越多→淬火马氏体中合金过饱和度越大→高温回火时合金碳化物析出量越多、越弥散→二次硬化程度越高。回火时间（A）影响析出充分程度但不决定最大硬化量，球化组织（B）是退火的事，回火冷速（D）影响韧性而非硬化程度。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 388, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "奥氏体型不锈钢固溶处理的主要目的在于（ ）。", "options": ["提高钢的强度", "改善钢的切削加工性", "提高钢的韧性", "提高钢的耐蚀性"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "D正确。奥氏体不锈钢（如1Cr18Ni9Ti）固溶处理的主要目的是**提高耐蚀性**——加热到1050~1100℃使碳化物全部溶入奥氏体，快冷（水冷）后将碳\"冻结\"在固溶体中，避免Cr₂₃C₆沿晶界析出导致晶间腐蚀。强度变化不大，切削加工性改善是副产品。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 389, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "弹簧工作时最大内应力往往出现在它的（ ）。", "options": ["表面", "心部", "两端", "中间"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "A正确。弹簧工作时最大内应力出现在其**表面**——弹簧受弯曲和扭转应力时表面处应力最大（弯曲时表面距中性轴最远，σmax=My/I）。这就是为什么弹簧需要表面强化（喷丸处理）——在表面引入残余压应力可显著提高疲劳寿命。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 390, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "钢淬火后所形成的残余应力（ ）。", "options": ["使表层处于受压状态", "随钢种和冷却方法而变", "为表面拉应力", "使表层处于受拉状态 随淬火加热温度提高，高速钢淬火回火后(A)。"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。淬火后残余应力状态**随钢种（含碳量、合金元素）和冷却方法（水冷、油冷、空冷）而变**。一般情况下，热应力主导时表层受压、心部受拉；相变应力（马氏体膨胀）可能逆转应力状态。低碳钢水淬通常表层压应力，高碳钢因相变应力大可能表层拉应力。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 391, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "A、强度增高，韧性降低", "options": ["强度增高，韧性降低", "强度降低，韧性增高", "强度和韧性无明显变化", "强度有所增高而韧性无变化"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。这是加工硬化的典型表现——冷塑性变形后，位错密度增大、位错缠结→滑移困难→**强度增高，韧塑性降低**。这是金属材料冷加工后的普遍规律，也是加工硬化现象的定义。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 392, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "高锰钢特别耐磨的原因在于（ ）。", "options": ["钢中碳化物数量很高", "铁素体开始自奥氏体中析出", "它比同硬度的其他钢种的加工硬化能力高得多", "开始发生奥氏体转变", "它对各种磨损过程都表现出优良的耐磨性", "奥氏体开始转变为珠光体", "锰所形成的碳化物具有很高的硬度", "铁素体全部溶入奥氏体中"], "option_labels": ["A", "B", "C", "D", "E", "F", "G", "H"], "answer": "C", "explanation": "高锰钢（Mn13，1.0-1.4%C+11-14%Mn，又称Hadfield钢）特别耐磨的根本原因是其极高的加工硬化能力（C）。水韧处理后室温为单相奥氏体（HB≈200），受冲击/挤压→表面奥氏体→形变马氏体+大量形变孪晶→表面硬度急剧升至HB550+→形成自強化耐磨层，心部仍保持韧性奥氏体。A（碳化物）、B（铁素体析出）、G（碳化物硬度）均非高锰钢耐磨主因——高锰钢的碳化物很少。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 393, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "每热处理炉次锻件出炉后，记录纸应保持记录至出炉后下一组采集的数据清晰打印完成，但最短不得少于（ ）分钟。", "options": ["5", "10", "15", "30"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。记录纸在出炉后应继续记录**至少15分钟**，确保出炉后下一组采集数据完整打印（验证炉子状态、冷却过程等），这是产品质量可追溯性的要求。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 394, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "锻件生产过程中操作人员(含热处理工、仪表工、检验员)必须进行巡检，巡检时间为每（ ）分钟不少于一次。", "options": ["20", "10", "15", "60"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。锻件生产巡检间隔为每**20分钟**不少于一次——操作人员（热处理工、仪表工、检验员）每20分钟内至少巡检一次，检查温度、电流、走纸、设备状态等并记录，确保热处理过程的连续监控。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 395, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "不是退火的目的是（ ）", "options": ["降低钢的硬度，提高塑性，便于机加工和冷变形加工", "均匀钢的化学成分及组织，细化晶粒，改善钢的性能或为淬火作组织准备", "消除内应力和加工硬化，以防变形和开裂", "获得更好的组织与性能"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。退火目的不包括\"获得更好的组织与性能\"——那是淬火+回火的范畴。退火目的：降低硬度便于加工（A）、均匀化组织细化晶粒（B）、消除内应力防止变形开裂（C）、为后续淬火做准备。退火是软化处理，通常不是最终的强化热处理。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 396, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "下列材料锻件可通过热处理强化的是（ ）", "options": ["5A03", "1Cr18Ni9Ti", "LF6", "2D70"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "可热处理强化的铝合金需具备时效强化能力（有固态溶解度变化）。2D70（D）是Al-Cu-Mg系硬铝合金（2xxx系），可通过固溶+时效强化。5A03（A）和LF6（C）是Al-Mg防锈铝合金（5xxx系）→不可热处理强化（仅加工硬化）。1Cr18Ni9Ti（B）是不锈钢→奥氏体型，不可通过淬火强化（仅固溶处理）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 397, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "45#钢锻件正火后的组织是（ ）", "options": ["珠光体+铁素体", "珠光体", "马氏体", "奥氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "45#钢含碳0.45%，属亚共析钢。正火加热至Ac3以上（约780℃）全奥氏体化后空冷——冷却速度高于退火但仍低于临界冷却速度Vk，过冷奥氏体在高温区发生扩散型转变→先共析铁素体沿原奥氏体晶界析出+剩余奥氏体转变为珠光体，室温组织=珠光体+铁素体（A）。马氏体需淬火快冷才能获得，奥氏体是高温相（室温不保留）。本题选项已从OCR乱码中重建还原。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 398, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "choice", "question": "对耐火材料性能要求是（ ）。", "options": ["足够的耐火度，一定的高温强度", "良好的稳定性", "足够的耐火度，一定的高温强度、良好的稳定性"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。耐火材料（热处理炉衬）性能要求：①足够的耐火度（高温不软化熔融）；②一定的高温强度（高温下承受载荷不坍塌）；③良好的热稳定性（耐急冷急热不开裂剥落）。三者缺一不可。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 399, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "TA7钛合金锻件通常只进行（ ）热处理", "options": ["固溶", "双重退火", "退火", "去应力退火", "供应状态"], "option_labels": ["A", "B", "C", "D", "E"], "answer": "C", "explanation": "C正确。TA7（Ti-5Al-2.5Sn）是α型钛合金，不可热处理强化（α钛合金无同素异构转变），通常只进行**退火**处理——消除锻造应力、稳定α组织。α钛合金不能固溶强化（无相变），也不存在时效强化。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 400, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "在借工艺资料时，一定要仔细核对（ ）、图号、材料。", "options": ["工艺编号", "用户（厂家）", "工序号"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。借工艺资料需核对**用户（厂家）**、图号、材料三个关键信息——不同用户对同一图号可能有不同工艺要求，必须确认是哪个用户的工艺才能借到正确资料。工艺编号和工序号是内部管理信息。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 401, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "下列不属于回火目的的是（ ）。", "options": ["稳定组织", "消除应力", "削除马氏体", "降低硬度"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "回火四大目的：①稳定组织（消除残余奥氏体、稳定尺寸）；②消除淬火应力（防开裂）；③调整硬度/强度/塑性（获得所需力学性能）；④改善切削加工性。\"削除马氏体\"不是回火目的——回火恰恰是利用马氏体分解析出碳化物来获得回火组织（回火马氏体→屈氏体→索氏体）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 402, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "9SiCr刃具钢的回火脆性区温度范围为（ ）。", "options": ["200~240℃", "200~250℃", "250~300℃", "400~450℃"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。9SiCr（含Si~1.4%、Cr~1%）刃具钢的第一类回火脆性区温度范围为**200~250℃**（低温回火脆性区）。刃具通常低温回火（150~200℃），需避开200~250℃脆化区间。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 403, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "将冷变形加工后的黄钢加热到500~700℃保温1~2小时后空冷或水冷这种处理叫做（ ）。", "options": ["防季裂退火", "再结晶退火", "高温回火", "稳定化回火"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "冷变形黄铜（原题\"黄钢\"系OCR识别错误，应为黄铜）加热500-700℃发生再结晶，消除加工硬化、恢复塑性，为再结晶退火。该温度高于黄铜再结晶温度（~300-400℃），确保晶粒充分再结晶。防季裂退火温度仅200-300℃，目的为去应力而非再结晶。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 404, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "珠光体向奥氏体转变时，第一批晶核是在（ ）产生的。", "options": ["铁素体和渗碳体的界面处", "铁素体片中", "渗碳体片中", "晶界面处"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "同359题——A正确。奥氏体形核优先在铁素体/渗碳体界面处：界面能量高+碳浓度梯度大→满足形核的成分和能量条件。晶界面也是潜在形核点（界面能高），但优先在两相界面。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 405, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "为了提高渗碳件的耐磨性，对渗层碳化物的要求是（ ）。", "options": ["弥散分布的粒状碳化物", "均匀分布的块状碳化物", "均匀分布的网状碳化物", "均匀分布的大粒状碳化物"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。渗碳件渗层碳化物理想形态：**弥散分布的粒状碳化物**——细小均匀分布的颗粒状碳化物既提供高硬度耐磨性，又不割裂基体导致脆化。网状碳化物（沿晶界分布）→严重脆性；大块状碳化物→应力集中源。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 406, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "合金中几个相共存彼此不发生转变的现象称为（ ）", "options": ["平衡", "相平衡", "相静止", "相稳定"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。合金中几个相共存彼此不发生转变/反应的现象称为**相平衡**——在一定温度和成分下各相的相对数量和成分保持恒定（系统Gibbs自由能最低状态）。平衡是动态的（原子仍在扩散交换但宏观统计不变）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 407, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "TC11双得退火工艺也可以看作（ ）。", "options": ["固溶+时效", "固溶+稳定化", "两次固溶", "两次时效"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "TC11钛合金双重退火=高温退火（~970℃近β区，α→β→空冷得α马氏体）+低温退火（~530℃，α→α+β细弥散析出），本质上相当于固溶（高温加热→快冷得过饱和固溶体）+时效（低温加热→强化相弥散析出），与铝合金固溶+时效原理相似。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 408, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "1Cr11Ni2W2MoV不锈钢按其基体组织的分类方法属于（ ）不锈钢。", "options": ["马氏体", "奥氏体", "铁素体", "珠光体"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。1Cr11Ni2W2MoV含Cr~11%、Ni~2%，按组织分类为**马氏体**不锈钢——高温奥氏体化后空冷即可获得马氏体组织。1Cr18Ni9Ti含Cr~18%、Ni~9%则为奥氏体不锈钢（Ni含量高使奥氏体区扩大至室温）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 409, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "奥氏体不锈钢在高温时是奥氏体组织，冷却到室温时是（ ）组织。", "options": ["马氏体", "奥氏体", "铁素体", "珠光体"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。奥氏体不锈钢（含Ni≥8%时）由于Ni是扩大奥氏体区元素，使γ相区扩大到室温以下，高温奥氏体冷却至室温后仍保持**奥氏体**组织（不发生γ→α转变）。这也是为什么奥氏体不锈钢不能通过淬火强化。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 410, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "锻件热处理使用的是（ ）。", "options": ["锻造工艺", "锻件图", "产品规范", "热处理工艺"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。锻件热处理使用**热处理工艺**文件——规定加热温度、保温时间、冷却方式、装炉要求等参数。锻造工艺用于锻造过程，锻件图是锻造尺寸依据，产品规范是质量验收标准，都不是热处理操作的直接指导文件。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 411, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "锻件通常油冷转移时间（ ）。", "options": ["<40秒", "<60秒", "≤90秒", "<150秒"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。锻件油冷转移时间≤**90秒**（即炉门打开→工件全部浸入油中≤90s）。时间过长→工件在空气中降温过多→油冷前温度已降到临界温度以下→淬火效果差甚至得不到马氏体。这个要求比水冷/固溶处理（通常≤15~45s）宽松。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 412, "knowledge_point": "冷却介质与淬透性", "knowledge_point_key": "cooling_quenchants"}, {"type": "choice", "question": "沸水淬火是指水（ ）。", "options": ["≥70℃", "≥80℃", "≥85℃", "≥95℃"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "沸水淬火=水温≥85℃时的淬火。此温度下水的冷却特性：蒸汽膜阶段极长→冷却速度极低→适合某些高合金钢/高速钢的淬火（需要极慢冷却）。注意此时冷却速度远低于常温水淬，一般用于特殊材料的分级/等温淬火。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 413, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "AMS2750 标准中规定的B型仪表配置是（ ）。", "options": ["在D型仪表的基础上每炉带一负载电偶", "在D型仪表的基础上每装载区带一负载电偶", "在D型仪表的基础上每控制区带一负载电偶", "在C型仪表的基础上每炉带一负载电偶"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "AMS2750（航空材料规范-高温测量）B型仪表配置：在D型仪表（每控制区带温度传感器）的基础上，每装载区增加一个负载热电偶（跟踪工件实际温度）。负载热电偶贴在工件/模拟件上→真实反映工件温度而非仅是炉膛气氛温度。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 414, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "choice", "question": "用302-6号电炉生产，880℃×2.5h空冷的产品，升温时时（ ）C开始计算到温时间。", "options": ["880", "870", "875", "866"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。到温计时从炉温达到设定温度的容差下限开始计算——880℃工艺温度，容差通常±5℃或-5℃。温度达到**875℃**（880-5）即视为到温，开始计算保温时间。选880℃忽略了容差允许范围。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 415, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "仪表纸上热处理需工填写信息包含图号、材料牌号、炉号、数量、锭节号(按需)、热处理工艺名称、热处理炉批(次)号、（ ）、卡片号(按需)", "options": ["仪表记录纸号", "生产设备号（如4-9）", "装炉时最低温度", "电偶编号"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。仪表纸上热处理工需填写信息包含：图号、材料牌号、炉号、数量、锭节号、热处理工艺名称、热处理炉批次号、**生产设备号（如4-9）**、卡片号。设备号是追溯产品质量的重要信息。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 416, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "通常情况下，钛合金锻件热处理，加热温度在相变以下时，相变点选取原则是（ ）", "options": ["我厂复验的相变点的低值", "钛厂提供相变点的低值", "钛厂提供与 我厂相变点的最低值", "钛厂提供与 我厂相变点的均值"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。钛合金低温热处理（相变点以下）选取原则：取钛厂提供相变点与我厂复验相变点中的**最低值**作为工艺温度设计依据，确保加热温度不超过相变点（保守原则，防止进入β区出现过热组织）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 417, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "通常情况下，钛合金锻件热处理，加热温度在相变以上时，相变点选取原则是（ ）", "options": ["我厂复验的相变点的高值", "钛厂提供相变点的高值我厂相变点的均值", "钛厂提供与 我厂相变点的最高值", "钛厂提供与"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。钛合金高温热处理（相变点以上）选取原则：取钛厂提供相变点与我厂复验相变点中的**最高值**作为工艺温度设计依据，确保加热温度一定能超过相变点（保证进入所需相区）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 418, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "钛合金锻件热处理保温过程中设备故障，降温超出工艺下限要求时应（ ）", "options": ["锻件出炉空冷，设备修复后，按工艺生产", "设备修复，降温不超过30℃时，升温后补足工艺的保温时间即可", "锻件出炉空冷，设备修复后，按工艺生产时补足保温时间"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。钛合金锻件保温过程中设备故障降温超出工艺下限→已无法保证工艺质量→应**锻件出炉空冷**（避免在炉内长时间处于不确定低温），设备修复后按原工艺重新热处理。不能简单补足保温时间——因为降温已破坏了工艺条件。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 419, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "锻件不能通过产品(ABC)进行明显区分的，禁止同时在同一场地进行生产，防止产生错混料。", "options": ["形状", "大小", "标识", "密度"], "option_labels": ["A", "B", "C", "D"], "answer": "ABC", "explanation": "ABC全选。若锻件无法通过**形状**、**大小**、**标识**进行明显区分→禁止同时同场地生产——极易发生混料（无法区分不同材料/批次的相似锻件）。密度差异难以肉眼判断且需专用设备测量。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 420, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "choice", "question": "锻件生产过程中，操作人员巡检内容主要包括( ABC)设备有无异常。", "options": ["控温表记录表显示温度", "电流表指示", "记录表走纸是否正常"], "option_labels": ["A", "B", "C"], "answer": "ABC", "explanation": "ABC全选。巡检内容：A.控温表记录表显示温度（是否在工艺允差内）；B.电流表指示（加热元件是否正常通电）；C.记录表走纸是否正常（记录功能是否正常）。设备有无异常是概括性项目，三个具体检查点是可操作化的巡检内容。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 421, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "choice", "question": "等厚试块是指有效厚度在锻件名义厚度（ ）范围内的同材料大类的试块。", "options": ["±5mm", "±15mm", "±30mm", "±25mm"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。等厚试块有效厚度在锻件名义厚度**±5mm**范围内——即试块厚度与锻件名义厚度差不超5mm。这是为了保证试块能真实代表锻件的热处理效果。超出5mm差异→试块和锻件加热冷却行为不一致→试验结果不可靠。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 422, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "AMS2750 标准中规定的4级的精度是（ ）。", "options": ["±5", "±8", "±10", "±14"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "AMS2750标准中炉温均匀性精度等级：1级±3℃，2级±6℃，3级±8℃，4级±10℃，5级±14℃，6级±28℃。4级对应±10℃。精度等级越小→炉温均匀性要求越严格（航空航天关键件→1-2级，一般工件→4-6级）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 423, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "choice", "question": "AMS2750 标准中规定的2级的精度是（ ）。", "options": ["±5", "±8", "±10", "±6"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "AMS2750标准炉温均匀性2级精度=±6℃。2级属较高精度要求，适用于航空发动机热端部件等关键零件的热处理——温度偏差直接影响组织与性能（γ'相析出/晶粒度等）。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 424, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "choice", "question": "不建议用作热处理炉次号的字母是( ABD)。", "options": ["I", "0", "F", "S"], "option_labels": ["A", "B", "C", "D"], "answer": "ABD", "explanation": "ABD正确。不推荐用作炉次号的字母：**I**（与数字1混淆）、**O**（与数字0混淆）、**S**（可能与其他特殊编号冲突）。通常使用A~H、J~N、P~R、T~Z等不易混淆的大写字母。F可以正常使用。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 425, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "水、油槽的搅拌装置应在锻件淬火前（ ）分钟开启", "options": ["5", "2", "1", "30"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "水、油槽搅拌装置应在淬火前5分钟开启，确保：①淬火介质温度均匀（消除局部过热）；②介质成分均匀（消除浓度分层）；③流动状态稳定（保证淬火冷却均匀性）。提前开启可使介质达到稳定的流动和温度场，避免淬火瞬间局部冷却不均导致变形/软点。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 426, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "禁止将锻件装入电炉内长时间（ ）停放等待送电的情况。", "options": ["大于等于1.5小时", "大于等于0.5小时", "大于等于5小时", "大于等于3小时"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。禁止将锻件装入电炉长时间等待送电——**≥1.5小时**的等待会导致：①工件在炉内氧化（空气炉）、②炉温变化不确定→工艺质量无法保证、③存在安全隐患。需送电时再装炉或按工艺规程处理。", "section": "一、选择题", "topic": "热处理设备与工艺", "id": 427, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "可热处理强化和不可热处理强化变形铝合金，塑性变形后均可利用再结晶作用使其软化。", "answer": "√", "explanation": "正确。可和不可热处理强化变形铝合金，塑性变形（冷加工）后均可通过再结晶退火软化——加热至再结晶温度以上使变形晶粒→等轴新晶粒，消除加工硬化、恢复塑性。区别在于可热处理强化铝合金在退火后还可通过固溶+时效重新强化。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 428, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "奥氏体转变结束时，所形成的晶粒较粗大、并有少量铁素体存在。", "answer": "×", "explanation": "错误。奥氏体转变（珠光体→奥氏体重结晶）刚结束时，新形成的奥氏体晶粒通常细小而非粗大（高密度形核+低长大速率→起始晶粒细小），且完全奥氏体化后不应有残余铁素体（铁素体应全部溶入奥氏体）。该描述（晶粒粗大+残余铁素体）对应的是不完全奥氏体化或过热的不良组织。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 429, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "时效可消除残余应力，因此这种工艺实际就是去应力退火。", "answer": "√", "explanation": "正确。去应力时效的实质是在较低温度下长时间保温，通过微塑性变形（蠕变松弛）消除残余应力，原理与去应力退火相同。对铝合金而言时效同时有析出强化效果，但消除应力是去应力时效的主要目的之一，因此可以视为去应力退火的一种形式。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 430, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "在淬火钢中，渗碳体的分散程度最高物界面积最大，最有利于奥氏体生核和长大，故奥氏体转变进行最快。", "answer": "√", "explanation": "正确。淬火钢中马氏体→回火时分解，渗碳体以极细小弥散状态析出→相界面积最大（单位体积内渗碳体/铁素体界面极多）→为奥氏体形核提供大量优先位置（界面能降低形核功）→奥氏体转变速率最快。这是淬火钢回火后再加热奥氏体化速度远快于退火态的原理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 431, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "工件冷却速度很高时容易产生淬火裂纹。", "answer": "√", "explanation": "正确。工件冷却速度很高时容易产生淬火裂纹。马氏体转变伴随体积膨胀（约4%），快冷使表面先发生马氏体转变而心部后转变→表面受拉应力+组织应力叠加→极易开裂。这也是淬火介质选择需兼顾冷却速度与开裂风险的原因——分级淬火和等温淬火正是为了降低这种风险。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 432, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "可以说调质是以获得索氏体组织为目的加工工艺。", "answer": "√", "explanation": "正确。调质的标准定义=淬火+高温回火（500-650℃），目的即获得回火索氏体组织——粒状渗碳体均匀弥散分布在铁素体基体上，兼具高强度与良好塑韧性，是最重要的结构钢最终热处理工艺。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 433, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "淬火裂纹最可能在红热工件投入冷却介质的瞬间形成，裂纹的分布则有一定规律性。", "answer": "×", "explanation": "错误。淬火裂纹最可能在马氏体转变区（Ms点以下约300-150℃）形成，而非红热工件入液瞬间。红热状态（>800℃）时工件处于奥氏体状态塑性好→热应力易通过塑性变形释放→不易开裂。Ms点以下马氏体转变→硬度高塑性差+体积膨胀→组织应力急剧增大→裂纹萌生和扩展的高危阶段。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 434, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "不发生相变的钢只能通过冷加工变形使其强化。", "answer": "√", "explanation": "正确。不发生相变的钢（如奥氏体不锈钢，室温仍为γ相）只能通过冷加工变形（位错增殖→加工硬化）来强化。不能像马氏体钢那样通过淬火+回火强化。此外还有固溶强化和晶粒细化。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 435, "knowledge_point": "变形与开裂", "knowledge_point_key": "deformation_cracking"}, {"type": "truefalse", "question": "钢进行连续加热时，加热速度愈大完成奥氏体转变所需要的时间愈长。", "answer": "√", "explanation": "正确。连续加热时加热速度越大→奥氏体转变的实际温度越高（过热度越大→形核驱动力越大），但完成转变的时间（从Ac1到全奥氏体化）反而延长——因为快速加热→碳原子来不及充分扩散→奥氏体化推迟到更高温度才完成→所需总加热时间增加。这是加热动力学的反直觉规律。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 436, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "工件在不同介质中加热所需要的升温时间，由长到短的排列顺序为气体介质、熔盐、熔融金属。", "answer": "√", "explanation": "正确。不同介质加热效率：气体介质（空气/保护气氛，导热最慢）>熔盐（液态盐浴传热快+对流传热）>熔融金属（液态金属，导热系数极高）。升温时间由长到短排序：气体>熔盐>熔融金属。这也是盐浴炉和铅浴炉加热快的原理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 437, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "truefalse", "question": "一般不希望调质件完全淬透，以使心部保持足够的韧性。", "answer": "×", "explanation": "错误。调质件应尽量淬透——使整个截面获得马氏体→高温回火后全截面均为回火索氏体→力学性能沿截面均匀分布。若未淬透→心部为非马氏体组织（珠光体/贝氏体）→回火后心部强度不足→影响整体承载能力。希望不完全淬透的是某些特定耐磨件（表面硬心部韧）才对。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 438, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "淬火裂纹指淬火后发现的裂纹。", "answer": "×", "explanation": "错误。淬火裂纹可能在淬火冷却过程中产生，也可能在淬火后放置数小时甚至数天才出现（延迟裂纹）。淬火后残余应力+氢的作用→延迟断裂。有些淬火裂纹在回火加热时暴露。因此\"淬火裂纹=淬火后发现的裂纹\"定义不准确。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 439, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "金属或合金的新鲜表面一但能在氧化初期形成致密的保护膜，氧化过程便会受到抑制，因而具有良好的耐蚀性。", "answer": "√", "explanation": "正确。金属表面在氧化初期若能形成致密的保护膜（如Al的Al₂O₃、Cr的Cr₂O₃、不锈钢的钝化膜）→该膜隔绝了金属与氧化介质的直接接触→抑制进一步氧化→材料具有良好耐蚀性/抗氧化性。这是不锈钢和高温合金抗氧化的基本原理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 440, "knowledge_point": "气氛控制", "knowledge_point_key": "atmosphere_control"}, {"type": "truefalse", "question": "贝氏体转变是介于扩散型相变和无扩散型相变之间的过渡型相变，这种转变所需要的冷却速度比马氏体时也能获得贝氏体。", "answer": "×", "explanation": "错误。贝氏体转变是介于扩散型（珠光体）和无扩散型（马氏体）之间的过渡型相变——铁原子不扩散（切变），碳原子发生扩散（短程扩散→碳化物析出）。但\"所需冷却速度比马氏体时也能获得贝氏体\"说法错误——贝氏体转变需要比马氏体慢的冷却速度（C曲线上的贝氏体转变区），快冷到Ms以下是得马氏体而非贝氏体。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 441, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "工件在水中淬火冷却时对流阶段的冷却速度最快。", "answer": "×", "explanation": "错误。水中淬火冷却三阶段：①蒸汽膜阶段（表面形成稳定蒸汽膜，冷速最慢）→②沸腾阶段（蒸汽膜破裂→水直接接触工件→沸腾传热→冷速最快）→③对流阶段（表面温度降至沸点以下→对流换热→冷速下降）。冷速最快的是沸腾阶段（B阶段），而非对流阶段。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 442, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "合金中几个相共存彼此不发生的现象称为相平衡。", "answer": "√", "explanation": "同407题——合金中几个相共存彼此不发生变化的现象称为**相平衡**（热力学概念）。题中\"彼此不发生的现象\"应是\"彼此不发生转变的现象\"（OCR漏字）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 443, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "合金钢奥氏体化时应采用比碳素钢更高的加热温度和更长的保温时间。", "answer": "√", "explanation": "正确。同141题——合金钢中合金碳化物溶解温度高、合金元素扩散慢，需要比碳素钢更高的加热温度和更长的保温时间才能获得均匀奥氏体。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 444, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "奥氏体型不锈钢的耐蚀性随奥氏体过饱和度的提高而增强。", "answer": "√", "explanation": "正确。奥氏体不锈钢经固溶处理获得过饱和的奥氏体（碳和合金元素全部固溶），避免了碳化物沿晶界析出（晶间腐蚀的根源），耐蚀性随过饱和度的提高而增强。固溶后需快冷以防在冷却过程中析出碳化物。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 445, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "在过冷奥氏体转变图上，孕育期最短的那一段转变开始曲线叫做“鼻子”。", "answer": "×", "explanation": "错误。在过冷奥氏体转变图上，孕育期**最短**（转变开始曲线最靠左/最靠温度轴）的那一段叫\"鼻子\"（nose）——对应转变最快的温度区间（通常~550℃，对碳钢）。孕育期最长（最靠右）处才是转变最慢的温度。题目说孕育期最短那段叫\"鼻子\"是正确的，题干不完整。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 446, "knowledge_point": "C曲线与TTT图", "knowledge_point_key": "ttt_cct_diagram"}, {"type": "truefalse", "question": "水中加入氯化钠、碳酸钠等添加剂后几乎不出现沸腾阶段。", "answer": "×", "explanation": "错误。水中加入NaCl、Na₂CO₃等添加剂后**仍会出现**沸腾阶段——盐水降低了蒸气膜的稳定性（因盐结晶爆炸破坏蒸气膜），使蒸气膜阶段缩短→更快进入沸腾阶段，从而整体冷却能力增强。不是\"几乎不出现\"而是\"蒸气泡阶段缩短\"。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 447, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "只要将奥氏体冷却到M。点以下，奥氏体便会转变为马氏体", "answer": "√", "explanation": "正确。马氏体转变的条件：①冷却到Ms点以下；②有足够过冷度。当冷却到Ms点→开始发生γ→α'马氏体转变（切变）。但需注意马氏体转变有Ms和Mf温度区间→Ms以下并非所有奥氏体都立即转变→转变随温度继续降低而持续进行→到Mf时转变基本完成（但总有少量残余奥氏体Ar）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 448, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "工件的奥氏体化温度就是工件进入冷却介质那一刻所需要的淬火急冷温度，所以工件出炉后应尽可能快地投入冷却介质中。", "answer": "×", "explanation": "错误。对于形状复杂或高碳高合金钢工件，出炉后应先预冷（延迟淬火）——让表面温度从加热温度（如1000+℃）降至略高于Ar3（750-780℃）再入液→减小热冲击→降低热应力。直接急入介质温差过大→热应力巨大→变形开裂。热作模具必须预冷。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 449, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "把钢处理成粒状珠光体目的之一，是改善其切削加工性。", "answer": "√", "explanation": "正确。球状珠光体（球化处理产物）硬度低（HB180~210），切削加工性优良——切削时碳化物颗粒易被刀具\"拔除\"，刀具磨损小、加工表面质量好。片状珠光体较硬且层片割裂基体，切削时阻力大。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 450, "knowledge_point": "珠光体与贝氏体转变", "knowledge_point_key": "pearlite_bainite"}, {"type": "truefalse", "question": "分级淬火和等温淬火的相似之处是都需在Ms点以上作短时停留，", "answer": "×", "explanation": "错误。分级淬火在Ms点稍上（盐浴~200℃）作短时停留→内外均温后空冷；等温淬火在贝氏体转变温度（250-400℃）长时间等温→获得贝氏体组织。两者差别：①温度不同（Ms以上 vs 贝氏体区）；②停留时间不同（短时 vs 长时等温）；③目的不同（减少变形 vs 获得贝氏体）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 451, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "本质粗晶粒钢渗碳后应采用直接淬火进行热处理。", "answer": "×", "explanation": "错误。本质粗晶粒钢渗碳后长时间高温加热→晶粒已粗大→若直接淬火→马氏体粗大→脆性大、变形大。应渗碳后缓冷→重新加热到稍高于Ac1的较低温度（细化晶粒）→再淬火+低温回火。本质细晶粒钢渗碳后可直接淬火（晶粒未粗化）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 452, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "当钢中存在网状碳化物或粗大晶粒时，往往可以通过控制其奥氏体化加热过程来加以消除。", "answer": "×", "explanation": "正确（答案×=判\"可消除\"为错）。网状碳化物和粗大晶粒不能仅通过控制奥氏体化来消除——网状碳化物需先行正火消除（加热到Acm以上溶解→空冷析出细片状碳化物），粗大晶粒需重新正火/退火重结晶细化。单凭控制奥氏体化参数（降低温度/缩短时间）无法消除已存在的网状碳化物和粗大晶粒遗传。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 453, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "truefalse", "question": "真空炉的处理环境并不是真正的真空。", "answer": "√", "explanation": "正确。真空炉的工作环境并非真正的绝对真空——通常工作真空度在10⁻¹~10⁻³Pa（低真空/中真空范围），仍有微量残余气体（O₂、N₂、H₂O等）。\"真空\"是相对大气压的概念，不是完全无气体的空间。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 454, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "晶粒越粗大金属材料的机械性能越差。", "answer": "√", "explanation": "正确。晶粒越粗大，单位体积内晶界面越少→位错运动障碍越少→强度硬度越低。同时粗晶粒塑性变形不均匀→应力集中严重→裂纹易萌生扩展→韧韧也降低。细晶粒的强度和韧韧均优于粗晶粒。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 455, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "条状马氏体是高碳钢淬火后的典型组织。 件", "answer": "×", "explanation": "错误。条状（板条）马氏体是**低碳钢**（<0.2%C）淬火后的典型组织，其亚结构为高密度位错。**高碳钢**淬火后的典型组织是针状（片状/孪晶）马氏体，其亚结构为微细孪晶。两者形态和性能差异很大——条状马氏体韧韧好，针状马氏体硬而脆。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 456, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "当介质的冷却速度大于钢的临界冷速时工件整个截面上都能发生 马氏体转变。", "answer": "×", "explanation": "错误。介质冷速>临界冷速Vk只能保证工件表面获得马氏体。整个截面是否全淬透取决于：①截面尺寸（心部实际冷速是否>Vk）；②钢的淬透性（Vk的大小）。对大截面工件→表面冷速>Vk但心部冷速<Vk→表面马氏体+心部非马氏体→未全淬透。\"整个截面都能发生马氏体转变\"需要淬透性足够好。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 457, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "空气和水的传热方式以传导传热为主。", "answer": "×", "explanation": "错误。空气和水的传热方式以**对流**为主，不是传导。空气（气体）和水的热传导系数很低，但通过流体的宏观流动（自然对流或强制对流）可高效传递热量。传导仅在固体接触时为主导。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 458, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "合金的机械性能取决于构成它的物质的种类、数量和分布特点。", "answer": "√", "explanation": "正确。同190题——合金机械性能取决于：①相的种类（铁素体软韧、渗碳体硬脆）；②各相相对数量（含碳量决定珠光体量）；③分布特点（片状vs球状，沿晶界析出vs弥散分布）。组织决定性能是热处理的理论基础。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 459, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "无法用光学金相显微镜分辨的马氏体叫做隐晶马氏体。", "answer": "√", "explanation": "正确。隐晶马氏体（隐针马氏体）=光学显微镜下无法分辨其针状形态的马氏体，呈均匀浅色区域。形成条件：奥氏体晶粒极细→马氏体针极细→低于光学显微镜分辨极限（~0.2μm）。高碳钢低温淬火或细晶粒钢中常见。需借助电子显微镜（TEM/SEM）才能分辨其板条/针状形态。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 460, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "低碳钢只有通过中温回火才能获得优良的综合机械性能。", "answer": "×", "explanation": "错误。低碳钢获得优良综合力学性能的正确途径是**淬火+高温回火**（调质处理），获得回火索氏体组织，强度、塑性、韧韧匹配良好。中温回火（350~500℃）获得回火托氏体，弹性极限高但塑性韧韧较差。低碳钢不能通过中温回火获得最佳综合性能。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 461, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "加热温度太高因而造成晶界氧化和开始部分熔化的现象叫做过烧。", "answer": "√", "explanation": "正确。过烧=加热温度过高（接近固相线）→晶界氧化甚至局部熔化→晶界出现氧化物和熔化痕迹→晶粒间结合力丧失→不可挽救只能报废。与过热的区别：过热（仅晶粒粗大，可正火挽救）vs 过烧（晶界氧化/熔化，不可挽救）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 462, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "再结晶过程是无相的结晶过程", "answer": "√", "explanation": "同211题——合法。再结晶是无相变的结晶过程：新晶粒晶格类型不变，只消除加工硬化、恢复塑性组织。区别于\"再结晶退火\"——这就是利用再结晶现象实现软化。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 463, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "再结晶也是相变过程。 (—", "answer": "×", "explanation": "同172题——正确。再结晶不是相变过程（无晶格类型改变），题目说\"也是相变过程\"错误。再结晶只是消除形变组织→形成无畸变新晶粒，是回复再结晶的后续阶段。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 464, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "再结晶过程没有恒定的转变温度。", "answer": "√", "explanation": "同197题——正确。再结晶没有恒定的转变温度，转变温度范围受变形程度、原始晶粒度、保温时间、杂质含量等多种因素影响，不是一个固定临界点。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 465, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "再结晶并不能够使变形金属的组织和性能回到冷塑性变形前的状 组", "answer": "×", "explanation": "错误。同209题——再结晶能够使变形金属的组织和性能回到冷塑性变形前的状态：拉长的晶粒→等轴晶粒，加工硬化消除→强度降低、塑性恢复。回复阶段仅消除应力而不改变组织，再结晶阶段才改变组织和性能。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 466, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "第I类回火脆性是可逆的。", "answer": "×", "explanation": "错误。第一类回火脆性（250~400℃）是**不可逆**的——一旦出现后无法通过热处理方法消除（重新加热到此温度范围仍会脆化）。唯一方法是避开此温度区间回火。第二类回火脆性（450~650℃）才是可逆的（重新加热后快冷可消除）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 467, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "回火时的组织转变一般是非扩散性的。", "answer": "×", "explanation": "错误。回火时的组织转变是扩散型转变。碳原子从马氏体中析出（形成碳化物）、碳化物聚集长大、残余奥氏体分解都需要碳和合金元素的扩散。只是回火温度较低（<650℃），扩散速度比奥氏体化时慢。淬火时的马氏体转变才是非扩散型（切变机制）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 468, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "钢的回火硬度除与回火嗣度和保温时间有关外，还与冷却速度有。", "answer": "×", "explanation": "错误。钢的回火硬度主要取决于回火温度和保温时间——决定碳化物析出量、类型和聚集程度。回火后冷却速度对硬度影响极小（碳化物在回火保温时已形成，冷却只是物理降温），但对某些合金钢的回火脆性有影响（快冷可抑制第二类回火脆性）。标准教材认为回火硬度与冷却速度基本无关。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 469, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "TC4钛合金的固溶热处理会有马氏体组织形成所也可叫淬火处理。", "answer": "√", "explanation": "正确。TC4（Ti-6Al-4V）属于α+β型钛合金，从β区（~1000℃）快冷→β→α'（马氏体相，钛合金马氏体是过饱和α固溶体），组织变化类似钢的淬火→所以也称\"淬火处理\"。但与钢不同，钛合金马氏体硬度不高（α'相，无明显强化效果），强化靠后续时效。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 470, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "在钢的各种组织中，奥氏体的比容最大，马氏体的比容最小。", "answer": "×", "explanation": "错误。正确答案反了：在钢的各种组织中，马氏体比容最大（体心正方结构+碳过饱和→晶格畸变→原子间距大→比容最大），奥氏体比容最小（面心立方，原子堆积最密致→比容最小）。淬火时γ→α'体积膨胀约1-4%，这是产生淬火组织应力的根本原因。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 471, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "调质处理的主要目的在于提高结构零件的综合机械性能。", "answer": "√", "explanation": "正确。调质=淬火+高温回火→回火索氏体→强度与塑韧性的最佳配合→综合力学性能（强度+塑性+韧性+疲劳性能）最优。这是轴/齿轮/连杆/螺栓等承受交变载荷结构件的标准最终热处理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 472, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "可以说调质是以获得回火索氏体组织为目的的热处理工艺。", "answer": "√", "explanation": "正确。同ID=433。调质以回火索氏体为目的组织——粒状渗碳体均匀弥散分布+铁素体基体，为淬火+高温回火的产物，综合力学性能最佳。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 473, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "truefalse", "question": "亚共析钢淬火不充分时，组织中会存在铁素体或铁素体十托氏体。", "answer": "√", "explanation": "正确。亚共析钢淬火不充分（冷却速度不足或加热温度偏低/时间不足→未完全奥氏体化）：未溶铁素体保留下来+奥氏体中碳含量不均匀→淬火组织中存在先共析铁素体（白色）+托氏体（极细珠光体，黑色团状）+马氏体的混合组织。正常全奥氏体化+充分淬火应只有马氏体+少量Ar。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 474, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "回火是对淬火的调整和补充，两序紧密联系在一起，构成最终热处理。", "answer": "√", "explanation": "正确。淬火（获得马氏体高硬度但脆）+回火（消除脆性、调整性能）=最终热处理。两者是前因后果的有机整体：淬火后的组织处于亚稳态，回火通过碳化物析出和基体恢复来获得稳定的使用性能。调质=淬火+高温回火即是最典型的最终热处理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 475, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "truefalse", "question": "钢淬火时，理想淬火速度是从高温到室温始终保持快速冷却。", "answer": "×", "explanation": "正确观点（同ID=147）。理想淬火冷却曲线应分段而非恒速：高温区（650-550℃）需快冷→避开珠光体鼻部→获得马氏体；低温区（Ms以下）需慢冷→减小组织应力→防开裂。全程快冷（如答案所述）导致巨大淬火应力变形开裂→错误。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 476, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "只有把亚共析钢和过共析钢加热到A3以上温度才能获得单相奥氏体。", "answer": "×", "explanation": "错误。亚共析钢需加热到A3以上→全奥氏体化；但过共析钢在工程实践中不要求全奥氏体化——通常只加热到Ac1-Acm之间（保留部分粒状渗碳体）→淬火得马氏体+粒状碳化物+少量Ar。加热到Acm以上虽得全奥氏体化但晶粒粗大+脱碳严重→不实用。因此\"过共析钢加热到A3以上才能获得单相奥氏体\"即技术上错（应到Acm以上），实践中也不推荐。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 477, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "把钢处理成粒状珠光体的目的之一，是改善其切削加工性。", "answer": "√", "explanation": "同450题——正确。球化珠光体改善切削加工性。特别是高碳工具钢（T8~T12）通过球化退火→硬度降至HB200以下→才能正常切削加工。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 478, "knowledge_point": "珠光体与贝氏体转变", "knowledge_point_key": "pearlite_bainite"}, {"type": "truefalse", "question": "工件在盐水及碱水中冷却后，应清洗干净，否则会造成工件腐蚀。", "answer": "√", "explanation": "正确。盐水（NaCl水溶液）和碱水（NaOH水溶液）冷却后→盐/碱残留在工件表面→吸潮后形成电解质溶液→引起电化学腐蚀→工件生锈。所以冷却后必须立即用清水充分清洗干净再进入下道工序。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 479, "knowledge_point": "冷却介质与淬透性", "knowledge_point_key": "cooling_quenchants"}, {"type": "truefalse", "question": "TA7钛合金锻件退火处理时，加快锻件的冷却速度有利于提高锻件的理化强度。", "answer": "×", "explanation": "错误。TA7是α型钛合金（不可热处理强化），退火后冷却速度对力学性能影响很小（α相无相变）。加快冷却不能提高强度，反而可能因冷却不均匀引入残余应力。TA7退火后通常空冷即可，无需快冷。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 480, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "镁合金锻件转热处理后应及时进行热处理后转下道工序，防止工件在现场受潮腐蚀。", "answer": "√", "explanation": "正确。镁合金化学活性高、极易腐蚀（特别是电化学腐蚀），锻后应及时热处理后及时转下道工序→减少在潮湿现场存放时间→防止吸潮腐蚀。若不能及时热处理，应采取防锈措施（涂防锈油/干燥保存）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 481, "knowledge_point": "有色金属热处理", "knowledge_point_key": "nonferrous_heat_treatment"}, {"type": "truefalse", "question": "条状马氏体是低碳钢淬火后的典型组织。", "answer": "√", "explanation": "正确。条状（板条）马氏体是低碳钢（<0.2%C）淬火的典型组织。低碳马氏体的Ms点高、亚结构为高密度位错，马氏体条大致平行排列成束，具有较高的强度和良好的韧韧。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 482, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "当介质的冷却速度大于钢的临界冷速时工件整个截面上都能发生马氏体转变。", "answer": "×", "explanation": "错误（同ID=457）。介质冷速>Vk是获得马氏体的必要条件，但\"整个截面\"都获得马氏体还需截面尺寸+淬透性配合。冷速沿截面递减→表面>Vk≠心部>Vk。全截面淬透需钢的淬透性与截面尺寸匹配。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 483, "knowledge_point": "马氏体转变", "knowledge_point_key": "martensite_transformation"}, {"type": "truefalse", "question": "针状马氏体是高碳钢淬火后的典型组织。", "answer": "√", "explanation": "正确。针状（片状/孪晶）马氏体是高碳钢（>0.6%C）淬火的典型组织。因Ms点低、转变时铁原子难以扩散，亚结构为微细孪晶，马氏体片呈双凸透镜状，片与片之间不平行，硬度高但脆性大。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 484, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "铝合金锻件固溶处理后获得过饱和固溶体。", "answer": "√", "explanation": "正确。铝合金锻件固溶处理（~520℃保温→水冷）后获得过饱和固溶体——溶质原子（Cu、Mg、Si等）在α-Al固溶体中处于过饱和状态，为后续时效析出提供\"驱动力\"。时效时析出的细小弥散第二相（如Al₂Cu）产生强化效果。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 485, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "当钢质锻件的较粗时，可以通过增加正火的方式来调整锻件的组织(细化晶粒)。", "answer": "×", "explanation": "错误。正火可以细化晶粒，但题中\"当钢质锻件的较粗时\"应该是\"当钢质锻件的晶粒较粗时\"——正火通过重结晶细化晶粒是正确的。如果答案是\"错误\"则可能是因为：当晶粒极粗时（如严重过热），普通正火不足以完全消除，需要多次正火或高温扩散退火。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 486, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "钛合金锻件出现过热组织时，不能通过热处理的方式来调整组织。", "answer": "√", "explanation": "正确。钛合金过热组织（如粗大β晶粒、魏氏组织）一旦产生，**不能通过热处理消除**——钛合金无同素异构转变、没有重结晶细化机制。只能通过重新锻造（变形+再结晶）来细化过热组织。因此钛合金加热温度控制极为重要。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 487, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "钛合金锻件退火热处理仅仅是削除锻件的锻造应力，调整锻件的组织形态。", "answer": "√", "explanation": "正确。钛合金锻件退火热处理的作用：①消除锻造产生的残余应力（防止后续加工和使用中变形开裂）；②调整/稳定组织（使亚稳相分解为平衡态组织，稳定尺寸和性能）。钛合金退火不加相变，主要靠回复和再结晶。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 488, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"id": 489, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "热处理冷却水槽通常使用温度为10℃~40℃ (J", "answer": "√", "explanation": "正确。热处理冷却水槽通常使用温度**10~40℃**——水温过低（<10℃）冷却速度过快→可能导致变形开裂；水温过高（>40℃）冷却能力不足→可能淬不硬。需控制在此范围内保证冷却工艺稳定。", "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"id": 490, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "热处理冷却油槽通常使用温度为20℃~100℃ (J", "answer": "√", "explanation": "正确。热处理油槽通常使用温度**20~100℃**——油温过低黏度大冷却慢且不均；油温过高闪点风险且老化加速。快速淬火油一般控制在60~80℃效果最佳。水温范围和油温范围区别很大（油温可到100℃）。", "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"id": 491, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "每热处理炉次锻件出炉后，记录纸应保持记录至出炉后下一组采有 集的数据清晰打印完成，但最短不得少于15分钟。", "answer": "√", "explanation": "正确。同394题——记录纸出炉后最少保持**15分钟**打印完下一组数据，是质量记录的基本要求，保证炉温数据和工艺过程完全可追溯。", "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "借工艺资料时应仔细核对所借资料的图号、材料牌号与质量记录卡上的图号、材料牌号是否一致，只有两方一致时方能用于生产。", "answer": "×", "explanation": "错误。借工艺资料时核对图号和材料牌号是必要的，但仅核对这两项是**不够的**——还需核对质量记录卡和工艺文件上的其他关键信息（如热处理制度、炉批号、数量等），确保全方位一致后方能用于生产。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 492, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "锻件不能通过产品形状、大小、标识进行明显区分的，禁止同时在同一场地进行生产，防止产生错混料。", "answer": "√", "explanation": "同420题——正确。无法通过形状、大小、标识明显区分的不同产品禁止同时同场地生产，防混料是现场管理底线要求。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 493, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "将金属或合金加热到适当温度，保温一定时间，然后缓慢冷却(一般为随炉冷却)，的热处理工艺叫做退火。", "answer": "√", "explanation": "正确。这是退火的完整标准定义：①加热到适当温度（根据材料和目的选择Ac1以下或以上）；②保温一定时间（组织均匀化）；③随炉缓慢冷却（核心特征——区别于正火的空冷和淬火的快冷）。目的为获得接近平衡态的组织，降低硬度，消除应力。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 494, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "锻件在热处理过程中需要加装负载热电偶时，负载热电偶加装的具体位置必须在产品装炉位置图上进行标识。", "answer": "√", "explanation": "正确。负载热电偶加装位置必须在装炉位置图上标识——这是质量追溯和工艺审查的重要依据。后续出现问题时可以确定负载偶对应的是哪个工件哪个位置，分析温度偏差原因。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 495, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "按“三对照”要求对来料进行数量、标识、锻件尺寸等项目核对，当产品不满足要求时，应与上道工序及时联系，并办理相关手续", "answer": "√", "explanation": "正确。来料接收时按\"三对照\"（工艺文件vs质量记录vs实物）核对数量、标识、尺寸等，发现问题及时与上道工序联系并办理相关手续（不合格品审理/退料等），不接收不符合要求的来料。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 496, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "热处理生产过程中记录的时间都用24时制。", "answer": "√", "explanation": "正确。热处理生产中所有记录时间均使用**24时制**（如14:30而非2:30 PM），避免AM/PM混淆造成工艺出错。管理文件和企业标准中明确要求用24时制。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 497, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "生产过程中，操作人员(含热处理工、仪表工、检验员)应坚守工作岗位，加强对温度、保温时间、冷却方式等重要工艺参数的监控。", "answer": "√", "explanation": "正确。生产过程中热处理工、仪表工、检验员必须坚守岗位，持续监控温度、保温时间、冷却方式等关键工艺参数——热处理参数偏差超出允差将直接影响产品质量甚至报废。坚守岗位是工艺纪律的底线要求。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 498, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "锻件在生产过程中出现故障时应按 《热处理加热、冷却发生故障时现场产品的处理措施》(文件编号Q/16GJBn0-23)相关规定做应急处理。", "answer": "×", "explanation": "错误。锻件生产故障应按**Q/16G JBn0-23**文件处理，不是\"Q/16GJBn0-23\"。文件编号中JBn0-23是标准格式，题中拼接错误（漏了空格或多了G）。正确文件号为Q/16G JBn0-23《热处理加热、冷却发生故障时现场产品的处理措施》。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 499, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "truefalse", "question": "锻件油冷时，应在锻件入油后立即开启油槽的搅拌，迅速带走锻件的热量。", "answer": "×", "explanation": "错误。锻件油冷时应**先入油→后开搅拌**。先开搅拌会将油面搅动形成涡流、可能导致工件入油时产生气泡包裹（冷却不均）、或油液飞溅。正确顺序：工件平稳入油→确认到位→再开启搅拌。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 500, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "锻件油冷结束时，应在立即盖好油槽槽盖。", "answer": "×", "explanation": "错误。锻件油冷结束后**不应立即**盖槽盖——高温工件入油后油温升高，油表面可能产生油雾/少量挥发物，需通风散逸后再盖盖。另外油温高时盖盖可能导致冷凝水回滴影响油质。应待油温降至安全温度后再盖。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 501, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "锻件转到分厂后，应及时带质量量记录卡到分厂资料室借相关的工艺资料，并按要求做好三对照，为锻件热处理做好准备。", "answer": "√", "explanation": "正确。锻件转入分厂后应立即带质量记录卡到资料室借工艺资料并完成\"三对照\"：工艺文件 vs 质量记录 vs 实物（核对图号、材料牌号、数量、尺寸等），确认一致后才能装炉生产。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 502, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "马氏体不锈钢锻件在正火保温过程中，电炉故障(炉丝断)，可将锻件闭电炉冷至600℃以下出炉空冷，设备修复后按工艺重新进行正火。", "answer": "√", "explanation": "正确。马氏体不锈钢正火保温过程中电炉故障（炉丝断），可将锻件随炉冷至600℃以下再出炉空冷，避免工件在高温下直接暴露于空气导致氧化和变形。设备修复后需按原工艺重新正火（因为随炉缓冷没有得到正火组织）。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 503, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "高温合金锻件固溶升温过程，设备故障(固态继电品烧毁)，可将锻件出炉空冷，设备修复后按工艺重新进行固溶。", "answer": "×", "explanation": "错误。高温合金固溶升温中设备故障→断电后温度下降，固溶工艺已破坏（不是保温阶段故障，是升温阶段）。出炉空冷可能导致温度梯度大、组织不均。应视情况评估——温度已到多少，若刚升温不久可以等设备修复后重新加热固溶处理。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 504, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "高温合金锻件固溶保温结束，准备出炉水冷时，吊车故障(无动作)，可关闭电炉记录开关，组织人员立即抢修吊车，吊车修复后立即将锻件出炉水冷。", "answer": "×", "explanation": "错误。固溶保温结束→应立即出炉水冷（转移时间有严格要求，通常<15~45秒）。吊车故障不能等修好再处理——应紧急采取替代方案（如手动葫芦、备用吊车等）尽快出炉。\"关记录开关等待抢修\"违反了固溶处理转移时间要求，会导致组织变化、性能不合格。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 505, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "铝合金锻件时效保温过程中设备故障不能继续生产时，可将锻件出炉空冷，设备修复后按工艺补足剩余的保温时间即可。", "answer": "√", "explanation": "正确。铝合金锻件时效保温中断→出炉空冷（中断保温），设备修复后按工艺**补足剩余保温时间**——时效是扩散控制过程，累积保温时间起决定作用，可分段累加。但前提是中断后快冷、避免缓冷过程中额外析出影响组织。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 506, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "班组人对工艺、图纸理解有疑义时，应请求班长，并按班长的要求继续组织生产。", "answer": "×", "explanation": "错误。班组对工艺/图纸有疑问→应**向上级技术部门**（工艺室/技术科）请示，而非原则上服从班长的个人理解。班长不一定是该工艺的编制者，技术人员才能提供准确的技术解释和处置意见。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 507, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"id": 508, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "钢件正火的目的是削除锻件的锻造应力，降低锻件硬度，为后续机械加工做准备。", "answer": "√", "explanation": "正确。正火（Ac3/Accm以上→空冷）可细化锻造造成的粗大晶粒、消除魏氏组织、降低锻造应力，为后续切削加工或最终热处理做好组织准备。对低碳钢来说正火硬度适中利于切削（退火太软反而粘刀）。注意本题归入退火知识点可能是分类误差——正火应有独立知识点分类。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 509, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "钢的淬透性是指钢在泽火时获得马氏体的能力", "answer": "√", "explanation": "正确。淬透性指钢在淬火时获得马氏体的能力，具体衡量指标为\"淬硬层深度\"——从表面到半马氏体区（50%马氏体+50%屈氏体）的距离。淬透性决定于过冷奥氏体的稳定性（C曲线位置），主要受合金元素（Cr/Ni/Mn/Mo等使C曲线右移）和奥氏体化条件影响。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 510, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "钢的淬硬性是指钢在淬火时的硬化能力。", "answer": "√", "explanation": "正确。淬硬性指钢在理想淬火条件下表面能达到的最高硬度，主要取决于马氏体中碳的过饱和度（即固溶于马氏体的碳含量）。含碳量越高→马氏体正方度（c/a）越大→晶格畸变越严重→硬度越高。合金元素（除Co外）对淬硬性影响远小于碳含量。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 511, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "钢的淬硬性好说明其淬透性一定好。", "answer": "×", "explanation": "错误。淬硬性与淬透性是两个完全不同的概念。淬硬性指钢淬火后表面能达到的最高硬度，主要取决于含碳量（碳↑→马氏体硬度↑）。淬透性指钢接受淬火获得马氏体层深度的能力，主要取决于合金元素（Cr/Ni/Mn/Mo↑→C曲线右移→临界冷却速度↓→淬透深度↑）。高碳工具钢淬硬性极好但淬透性差（仅表层几mm），低碳合金钢淬硬性一般但淬透性优异（全截面硬化）。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 512, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "提高TC11合金锻件第一次退火的温度，减少初生a相的含量，可提高锻件的强度和塑性。", "answer": "×", "explanation": "错误。TC11钛合金为α+β型，初生等轴α相是塑性的主要贡献者。提高第一次退火温度会使更多α→β转变，减少初生α相含量，这反而会降低塑性。最佳初生α含量约10-30%，过高的退火温度会破坏强度与塑性的最佳配合。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 513, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "大型模具热处理加热过程中的预热台阶是防止模具升温过程内外较大引起开裂。", "answer": "√", "explanation": "正确。大型模具尺寸大、形状复杂，加热时表面升温快心部升温慢（热传导滞后），内外温差产生巨大热应力（表面受压→心部受拉）。增加预热台阶（如550℃、850℃各保温一定时间）使内外温度梯度减小、热应力松弛，是防止大型件加热开裂的关键措施。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 514, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "钢件空气气分炉内热处理后，表面碳含量低心部的现象称为脱碳。", "answer": "√", "explanation": "正确。脱碳是钢在氧化性气氛（空气炉中含O₂/CO₂/H₂O）中加热时，表面碳与氧反应（C+O₂→CO₂或C+H₂O→CO+H₂）导致表面碳含量低于心部的现象。脱碳使表面硬度下降、疲劳强度降低。防止措施：盐浴炉加热、保护气氛、真空热处理、表面涂层保护。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 515, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "锻件加热时间长或温度较高，组织粗化的现象称为过热。", "answer": "√", "explanation": "正确。过热是加热温度过高或保温时间过长导致奥氏体晶粒异常粗大（晶粒度1-3级）的现象。过热件可通过重新正火（重新加热到Ac3以上→重结晶→细化晶粒）来挽救。与过烧的关键区别：过烧是晶界氧化或局部熔化，不可挽救只能报废。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"id": 516, "type": "truefalse", "topic": "热处理设备与工艺", "section": "二、判断题", "question": "热处理工艺中的升温、降温速率均是指平均速率。", "answer": "×", "explanation": "错误。热处理工艺中的升温速率和降温速率通常指分段控制的实际瞬时速率（℃/h或℃/min），而非整个过程的简单算术平均。不同温度区间允许的速率不同（低温段可较快→高温段需缓慢），必须严格控制各段瞬时速率以防热应力超标导致变形或开裂。", "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "影响奥氏体形成的主要因素有： 和 ______", "answer": "原始组织、化学成分、加热条件", "explanation": "影响奥氏体形成的三大因素：①原始组织（珠光体片间距→相界面面积→形核位置；粒状vs片状→转变速度不同）；②化学成分（碳含量和合金元素→碳扩散速度+相变驱动力）；③加热条件（温度+时间→温度是最主要因素，决定扩散速率和过热度）。三者综合决定奥氏体化速度和均匀性。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 517, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "fill", "question": "退火的目的在于 和 组织， 硬度，提高 ______，改善切削加工性能，消除铸、锻、焊、轧、冷加工等所产生的内应力。", "answer": "软化，改善，降低，塑性", "explanation": "退火四大核心目的：软化（降低硬度利于切削和冷变形）→改善组织（细化晶粒、均匀化成分）→提高塑性（恢复冷变形能力）→消除内应力（防止变形开裂）。这四项紧密关联：硬度降低与塑性提高互为因果，组织改善是性能改善的基础，应力消除是尺寸稳定性的前提。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 518, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "临界温度以上的相变重结晶退火： 可称 ；临界温度以下的退火： ______", "answer": "完全退火、扩散退火、不完全退之球化退火、再结晶退火、去应力退火", "explanation": "按加热温度是否超过临界温度（Ac1/Ac3）分为两大类：临界温度以上为相变重结晶退火（完全退火→全奥氏体化后重结晶；扩散退火→高温长时消除偏析；球化退火→Ac1附近粒化；不完全退火→部分奥氏体化）。临界温度以下为非相变退火（再结晶退火→冷变形晶粒重组；去应力退火→应力松弛），加热时无相变发生。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 519, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "、淬火钢在 温度范围内回火出现的脆性称为高温回火脆性，又叫第二类回火脆性 ______", "answer": "500-650℃", "explanation": "第二类回火脆性（高温回火脆性）温度范围：**500~650℃**。含Cr、Ni、Mn的合金钢在此温度回火后慢冷→出现室温冲击韧度大幅下降。机制：P、Sb、Sn等杂质元素向原奥氏体晶界偏聚。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 520, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "淬火钢在温度范围内回火出现的脆性称为低温回火脆性，也叫第一类回火脆性。 ______", "answer": "250~400℃", "explanation": "第一类回火脆性（低温回火脆性）温度范围：**250~400℃**。在此温度回火→室温冲击韧度下降。特点：不可逆（无法消除只能避开），所有钢都可能出现（碳钢和合金钢都有），与回火后冷速无关。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 521, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "低温回火的目的是 保证淬火后的高硬度和高耐磨性。 ______", "answer": "降低淬火应力、提高工件韧性", "explanation": "低温回火（150-250℃）目的：①降低淬火应力（马氏体中过饱和碳以ε-碳化物形式析出→体积变化减小）；②提高工件韧性（消除部分脆性）；同时保持淬火后的高硬度（HRC58-64）和高耐磨性。用于刀具/量具/模具/滚动轴承等要求高硬度高耐磨的零件。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 522, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "热处理工在表盘记录纸上写被加热锻件信息包括： 、产材料牌号、数量、 锭节号 、热处理炉批或炉次或炉批次、 ______、锻件质量记录卡代号。", "answer": "产品图号、类别、熔炼炉号、工序名称、热处理炉编号", "explanation": "热处理工在表盘记录纸上需填写被加热锻件信息：**产品图号**、材料牌号、数量、锭节号、**熔炼炉号**、**工序名称**、**热处理炉编号**（或炉批次号）、锻件质量记录卡代号。完整记录用于产品质量追溯。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 523, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "锻件不能通过产品 进行明显区分的，禁止同时在同一场地进行生产，防止产生错混料。 ______", "answer": "形状、大小、标识", "explanation": "同420/493题——锻件不能通过产品**形状、大小、标识**进行明显区分的，禁止同时在同一场地生产。本质是物理防错法：用外显特征区分产品避免混料。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 524, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "fill", "question": "锻件生产过程中，操作人员巡检内容主要包括 ，设备有无异常。 ______", "answer": "控温表记录表显示温\n\n度、电流表指示、记录表走纸是否正常", "explanation": "锻件生产中巡检内容：**控温表记录表显示温度**（温度是否在工艺范围内）、**电流表指示**（加热元件通电状态是否正常）、**记录表走纸是否正常**（记录功能是否完整）、设备有无异常。是巡检的核心检查项。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 525, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "所有的原始记录要用 或蓝黑色墨水钢笔认真填写且书写整洁、明了、正确、真实、详细、有效。 ______", "answer": "黑色、\n\n整洁、明了、正确、真实、详细", "explanation": "原始记录填写要求：用**黑色**或蓝黑色墨水钢笔认真填写，书写**整洁、明了、正确、真实、详细**。不允许用铅笔（可擦改、不持久）、红笔（通常用于特殊标记），必须真实完整可长期保存。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 526, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "所有的记录不得随意更改，属笔误情况需更改时，必须采用 方式修改，不准采用______、______或其它方式进行更改，且必须作更改者签名认可。", "answer": "杠改、刮改、涂改、更改标记", "explanation": "记录修改规范：笔误采用**杠改**方式（画斜杠划掉原字，在旁边写正确内容），不准采用**刮改**（用刀片刮去原字）、**涂改**（用涂改液覆盖）或其他方式——这些方式会掩盖原始记录痕迹、丧失可追溯性。修改处做**更改标记**并签名。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 527, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "fill", "question": "在锻件按工艺要求完成各段保温前分钟，由操作人员 共同确认无误后，到点方可进行下列操作。 ______", "answer": "5、热处理工、仪表工", "explanation": "在锻件保温完成前**5分钟**，操作人员**热处理工**和**仪表工**共同确认工艺参数无误、到温时间正确，到点后方可按工艺执行出炉/降温等操作。双人确认是为了确保工艺时间准确。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 528, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "对于空冷锻件：在出炉前必须按工艺要求的冷却方式准备好冷却场地，锻件出炉时迅速将锻件全部转移至冷却场地进行空冷，禁止锻件放或______ 冷却。 锻件出完炉后，热处理工应持该炉的《热处理生产工艺参数设定表》核对出炉锻件的数量，防止掉落在炉膛或水油槽内", "answer": "锻件、试环、试块", "explanation": "空冷锻件出炉要求：准备好冷却场地，迅速将**锻件、试环、试块**全部转移至冷却场地分散空冷（禁止堆放），确保各件均匀冷却。出炉后核对《热处理生产工艺参数设定表》确认数量，防止锻件掉落在炉膛或槽内。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 529, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "装炉要求：锻件装炉前______与一起将锻件图、工艺规程、产品质量记录卡、关键、重要件控制表与产品的实物进行 、熔炼炉（批）号、 、锻件尺寸及热处理工艺参数的对照，双方确认无误后，才能将锻件装入对应的加热炉有效工作区内。", "answer": "热处理工、工序检验、图号、材料牌号、数量、锭节号", "explanation": "装炉前**热处理工**与**工序检验**共同核对：锻件图、工艺规程、产品记录卡、关键件控制表与实物**图号**、**材料牌号**、**数量**、熔炼炉号、**锭节号**、锻件尺寸及工艺参数对照，双方确认后装炉。双人核对制度保障质量。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 530, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "淬火水油槽准备，操作者在生产前应检查槽内介质是否有、等异物，如有应及时清理排除。 ______", "answer": "污物、悬浮杂质", "explanation": "淬火水油槽准备是质量控制的基础环节。操作者生产前必须检查槽内介质是否有污物、悬浮杂质（氧化皮/铁屑/油泥等异物）→如有及时清理排除。污染物影响：①改变冷却特性（悬浮物→蒸汽膜不稳定→冷却不均→软点）；②污染工件表面（结垢/变色）。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 531, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "淬火水油槽准备，操作者在生产前应检查水油槽的 等装置的运行情况是否满足生产需求，并在锻件出炉前提开启搅拌系统。 ______", "answer": "加热、搅拌、给排、温度显示、5分钟", "explanation": "淬火水油槽生产前检查清单：加热系统（如冬季需预热油降低粘度）、搅拌装置（保证介质均匀）、给排系统（水位/油位正常）、温度显示（仪表正常）。锻件出炉前5分钟开启搅拌→确保淬火瞬间介质流动均匀→冷却均匀性→硬度均匀性。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 532, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "锻件若需要多个炉次组批生产时，应提前做好生产策划，避免在连续产过程中出现 以及 等可预知原因而造成生产中断的情况发生。 ______", "answer": "更换仪表、更换电偶、设备到期、放假", "explanation": "多炉次组批生产应提前策划，避免连续生产中出现**更换仪表**、**更换电偶**、**设备到期检定**、**法定节假日**等可预知原因造成生产中断。提前规划保证工艺连续性，避免因设备/人员因素导致产品质量问题。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 533, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "等温淬火可以使工件获得良好的 ，并具有较高的 和 ，组织为______", "answer": "韧性、硬度、强度、贝氏体", "explanation": "等温淬火=工件奥氏体化后淬入贝氏体转变温度范围（250-400℃）的盐浴中等温保持→奥氏体转变为下贝氏体。获得的组织：贝氏体（下贝氏体为主），性能特征：良好的韧性（贝氏体板条间无大碳化物→裂纹扩展阻力大）+较高的硬度和强度（贝氏体中碳化物弥散）+变形极小（等温过程无马氏体转变体积突变）。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 534, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "fill", "question": "常用的球化退火工艺有 和 ______", "answer": "普通球化退火、周期球化退火、等温球化退火", "explanation": "球化退火的核心是使层片状渗碳体→粒状渗碳体，改善切削加工性和冷变形塑性。三种常用工艺：①普通球化退火（Ac1稍上保温→极慢冷至Ar1以下→粒状珠光体）；②周期球化退火（Ac1上下反复加热冷却→多次形核→球化充分）；③等温球化退火（Ac1以上→快冷至Ar1以下等温→时间短效率高）。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 535, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "fill", "question": "公司钛合金锻件常用的工艺有 和。 ______", "answer": "退火、双重退火、固溶、时效、均匀化", "explanation": "钛合金锻件常用热处理工艺：**退火**（消除应力、稳定组织，各种钛合金都可用）、**双重退火**（α+β型钛合金，先β区退火后α+β区退火，优化组织）、**固溶**（高于α→β转变温度加热后快冷，获得亚稳组织）、**时效**（固溶后加热到400~600℃使亚稳相分解强化）、**均匀化**（减少成分偏析）。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 536, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "正火的目的在于 和 组织，硬度，改善。 ______", "answer": "细化晶粒、均匀化，降低，切削加工性能", "explanation": "正火四大目的：①细化晶粒（空冷冷速>炉冷→过冷度大→形核率高→晶粒更细）；②均匀化组织（消除网状碳化物、魏氏组织等缺陷）；③适当降低硬度（比退火硬度略高——对低碳钢反而改善切削性，避免太软粘刀）；④为后续热处理（淬火）做组织准备。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 537, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "fill", "question": "影响奥氏体形成的主要因素有； 和。 ______", "answer": "原始组织、化学成分、加热条件", "explanation": "同ID=517。影响奥氏体形成的三大因素：原始组织、化学成分、加热条件。原始组织越细散（片状珠光体>粒状）→相界面越多→形核越快；碳含量高→碳扩散快；加热温度高→扩散系数指数增长→奥氏体化加速。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 538, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "fill", "question": "淬火后回火的目的是为了获得要求的 削除 工件尺寸） ______；稳定", "answer": "强度、硬度、塑性和韧性、内应力、\n\n》 25、回火按温可分为 （低温回火、\n\n中温回火、高温回火", "explanation": "淬火后回火四大目的：①获得要求的力学性能（强度/硬度/塑性/韧性的目标配合）；②消除淬火内应力（防止变形开裂和延迟断裂）；③稳定工件尺寸（残余奥氏体转变+马氏体正方度降低→尺寸稳定）；④改善切削加工性。回火是淬火必不可少的后续工序。", "section": "三、填空题", "topic": "热处理设备与工艺", "id": 539, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "shortanswer", "question": "校正淬火变形的方法有哪些?", "answer": "(1)冷压校正法：(2)热校直法：(3)热点校正法；(4)反击法：(5)计算法；(6)喷砂校直法：(7)淬火校直法；(8)回火校直法。", "explanation": "(1)冷压校正法：(2)热校直法：(3)热点校正法；(4)反击法：(5)计算法；(6)喷砂校直法：(7)淬火校直法；(8)回火校直法。", "section": "四、简答题", "topic": "热处理设备与工艺", "id": 540, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "calculation", "question": "现有A、B、C项产品等待热处理，其中A产品12件，B产品9件，C品18件，且三项产品的热处理参数一致。分厂仅有一台电空闲，该电炉A产品装炉量25件，B产品装炉量20件，C产品装炉量≤30件。能用该电炉同时生产A、B、C三项产品吗?", "answer": "解：A产品占12/25 B产品占9/20 C产品占18/30 A+B+C=12/25+9/20+18/30=0.48+0.45+0.6=1.53>1 所以不能用该电炉同时生产A、B、C项产品。", "explanation": "解：A产品占12/25 B产品占9/20 C产品占18/30 A+B+C=12/25+9/20+18/30=0.48+0.45+0.6=1.53>1 所以不能用该电炉同时生产A、B、C项产品。", "section": "五、计算题", "topic": "热处理设备与工艺", "id": 541, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "calculation", "question": "现有某不锈钢产品结构如下图所示，请计算其正火与回火的保温时间?(注该材料正火基础保温时间取(10~30)min；热透时取2.5min/mm；回火基础保温时间取(60~80)min，热透时取3min/mm) 中140±5 242 48±5 中234±5", "answer": "解：锻件高=48+5=53 锻件壁厚=(239-135)/2=52 因为 锻件高≥锻件壁厚 所以 锻件有效厚度取锻件锻件壁厚52 该锻件正火保温时间=(10~30) min+2.5min/mm*有效厚度=(10~30)min+2.5min/mm*52 =140 min~160 min:该锻件回火保温时间=(60~80)min+3min/mm*有效厚度=(60~80)min+3min/mm*52 =226 min~246 min。", "explanation": "解：锻件高=48+5=53 锻件壁厚=(239-135)/2=52 因为 锻件高≥锻件壁厚 所以 锻件有效厚度取锻件锻件壁厚52 该锻件正火保温时间=(10~30) min+2.5min/mm*有效厚度=(10~30)min+2.5min/mm*52 =140 min~160 min:该锻件回火保温时间=(60~80)min+3min/mm*有效厚度=(60~80)min+3min/mm*52 =226 min~246 min。", "section": "五、计算题", "topic": "热处理设备与工艺", "id": 542, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "在热处理某项锻件(含试环，专用试块)时，工艺要求保温时是锻件(1535 ±5)min；试环(835±5)min；专用试块(1425±5)min，仪表到时间是4： 43，假设出试环、试块后升温时为15min，请计算出试环、试块、锻件的出炉时间。", "answer": "解：试环保温时间=835/60=13h:55min 试环出炉时间=4：43+13h+55min=18:38出炉 试块剩余保温时间=(1425-835)/60=9h:50min 试块出炉时间=18：38+15min+9h+55min=次日4:48 锻件剩余保温时间=(1535-1425)/60=1h：50min 锻件出炉时间=次日4：48 +15min+1h+50min=次日6：53", "explanation": "解：试环保温时间=835/60=13h:55min 试环出炉时间=4：43+13h+55min=18:38出炉 试块剩余保温时间=(1425-835)/60=9h:50min 试块出炉时间=18：38+15min+9h+55min=次日4:48 锻件剩余保温时间=(1535-1425)/60=1h：50min 锻件出炉时间=次日4：48 +15min+1h+50min=次日6：53", "section": "五、计算题", "topic": "热处理设备与工艺", "id": 543, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "calculation", "question": "试计算Fe-C合金在共析转变刚结束时，珠光体中铁素体和渗碳体的相对量。", "answer": "解：F%=(6.69-0.77)/(6.69-0)=88.5% Fe3C%=1-F%=11.5% 答：铁素体含量为88.5%，渗碳体为11.5%。", "explanation": "解：F%=(6.69-0.77)/(6.69-0)=88.5% Fe3C%=1-F%=11.5% 答：铁素体含量为88.5%，渗碳体为11.5%。", "section": "五、计算题", "topic": "热处理设备与工艺", "id": 544, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "“零缺陷行动”的关键原则是指", "options": ["质量意味着对图纸规范的完全符合。", "质量的标准就是“零缺陷”。", "质量的关注点应该是“预防缺陷”而不是检验。", "质量应该通过“不合格品成本”来衡量。"], "option_labels": ["A", "B", "C", "D"], "answer": "ABCD", "explanation": "ABCD全选。\"零缺陷行动\"四项关键原则：A.质量=完全符合图纸规范（不是\"差不多就行\"）；B.质量标准就是零缺陷（不是\"可接受质量水平\"）；C.关注预防缺陷而非事后检验；D.通过\"不合格品成本\"（PONC）衡量质量水平。", "section": "一、选择题", "topic": "质量管理", "id": 545, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "下列属于操作类的低层次质量问题有", "options": ["违反或指挥他人违反工艺规定、操作规程、管理程序操作。", "生产现场无工艺文件或使用无效工艺文件用于生产、检验或试验。", "不具有资格而操作设备设施。", "错检、漏检、标识错误、产品磕碰伤。"], "option_labels": ["A", "B", "C", "D"], "answer": "ABCD", "explanation": "ABCD全选。操作类低层次质量问题包括：A.违反或指使他人违反工艺规程（人的因素最严重）；B.无工艺文件或使用无效工艺文件生产；C.无资格操作设备（非授权操作）；D.错检/漏检/标识错误/磕碰伤（可通过责任心避免）。这些都属于\"不应该发生\"的问题。", "section": "一、选择题", "topic": "质量管理", "id": 546, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "QC小组选题时常用的方法", "options": ["调查表", "排列图", "鱼骨图", "关联图"], "option_labels": ["A", "B", "C", "D"], "answer": "AB", "explanation": "AB正确。QC选题常用方法：调查表（收集数据、归纳问题）和排列图（帕累托图，找主要问题，\"关键的少数、次要的多数\"）。鱼骨图和关联图是原因分析方法（选题后用），不是选题时用的方法。", "section": "一、选择题", "topic": "质量管理", "id": 547, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "丧失诚信的行为包括", "options": ["伪造产品记录，冒用他人印章", "质量记录卡填写错误", "篡改或指挥他人篡改各类记录、报告", "隐瞒或指挥他人隐瞒质量问题信息。"], "option_labels": ["A", "B", "C", "D"], "answer": "ACD", "explanation": "ACD正确。丧失诚信行为包括：A.伪造记录和冒用他人印章（严重诚信违规）；C.篡改或指使篡改记录（蓄意造假）；D.隐瞒质量问题（故意不报）。B选项\"记录卡填写错误\"如属无意笔误不属于丧失诚信（但应规范修改和纠正）。", "section": "一、选择题", "topic": "质量管理", "id": 548, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "下列情形中属于公司级质量问题的是指", "options": ["产品或材料被确认为过烧或由于加热超温造成产品整批报废。", "批量产品被确认为人为原因造成成批性报废的。", "由于技术文件编制错误或更改不到位，造成整批报废的。", "产品或材料被确认为混料、混状态、错料的。"], "option_labels": ["A", "B", "C", "D"], "answer": "ABCD", "explanation": "多选ABCD。公司级质量问题的四种情形：①过烧或加热超温整批报废（严重工艺失控）；②人为原因批量报废（操作/管理失误）；③技术文件错误批量报废（技术管理缺陷）；④混料/混状态/错料（材料管理混乱）。四者均属严重质量事故→触发公司级质量处理流程。", "section": "一、选择题", "topic": "质量管理", "id": 549, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "下列“QC”小组选题名称正确的是（ ）", "options": ["加强设备管理，减少电炉故障。", "改进炉衬结构，降低能源消耗。", "提高人才队伍建设水平。", "降低循环水消耗。"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。QC课题命名要求具体可量化——\"降低循环水消耗\"明确具体指标和方向，可测量可考核。\"加强设备管理\"、\"改进炉衬结构\"、\"提高人才队伍建设\"过于笼统，缺乏具体可衡量目标。", "section": "一、选择题", "topic": "质量管理", "id": 550, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "当加热炉发生故障时，需按照（ ）文件进处理。", "options": ["Q/16G GZ4-1", "Q/16G GZ25-1002", "Q/16G JBn0-23", "Q/16G GZ4-2"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。加热炉故障处理按**Q/16G JBn0-23**文件执行——这是企业内部标准编号体系。不同文件分管不同业务（设备运行、工艺管理、质量控制等），设备故障有专门的应急预案和处理流程。", "section": "一、选择题", "topic": "质量管理", "id": 551, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "需（ ）对热处理电炉进行日常点检，并将点检结果记录在点检表上。", "options": ["每日", "每周", "每月", "每炉次生产前"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。热处理电炉应**每日**进行日常点检（外观、仪表、阀门、风机运行状态等），并将点检结果记录存档。每日点检能及时发现异常、防微杜渐。周/月检查更深入全面但不能替代每日点检。", "section": "一、选择题", "topic": "质量管理", "id": 552, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "等厚试块是指有效厚度在锻件名义厚度（ ）范围内的试块。", "options": ["士10mm", "士3mm", "士6mm", "士5mm"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。同422题——等厚试块有效厚度在锻件名义厚度**±5mm**范围内。±10mm/±6mm/±3mm都不对。5mm是保证试块代表性的容差上限。", "section": "一、选择题", "topic": "质量管理", "id": 553, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "对于集渣网沉在槽底的水、油槽，班长负责组织班组 对其中的集渣网至少进行了一次清渣处理； 对其至少进行一次排空后的清渣处理，清理时要彻底清除集渣网中及槽内的杂物。（ ）", "options": ["每月：每半年", "每月：每季度", "每季度；每半年", "每季度：每一年"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。集渣网清理频率：**每月**至少一次不排空清渣（打捞浮渣），**每半年**至少一次彻底排空后清渣（清除槽底沉积物和杂物）。每月保基础清洁、每半年深度清洁，保证淬火介质洁净度。", "section": "一、选择题", "topic": "质量管理", "id": 554, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "根据真空除氢炉安全操作规程规定，真空炉超过（ ）天未生产时，生产前需对设备及料框进行烘烧。", "options": ["14天", "10天", "7天", "5天"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。真空除氢炉超过**7天**未生产→再次生产前必须对设备及料框进行烘炉处理（加热到一定温度保温），排除炉衬和料框吸附的水分，防止装炉生产时水分蒸发影响真空度和产品质量。", "section": "一、选择题", "topic": "质量管理", "id": 555, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "Q/16G GZ25-1002规定，如无特殊规定，负载试块应放置在锻件外侧距锻件（ ）位置。", "options": ["50mm", "100mm", "80mm", "越近越好"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。按Q/16G GZ25-1002规定，负载试块应放在锻件外侧距锻件**100mm**位置——距离过近试块受锻件热传导影响测温不准，过远则温度代表性差。100mm是经验确定的合理距离。", "section": "一、选择题", "topic": "质量管理", "id": 556, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "choice", "question": "在介质中淬火时，MPP未规定时，锻件在介质中冷却时间不少于（ ）分钟。", "options": ["10分钟", "20分钟", "15分钟", "30分钟"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "淬火介质中冷却时间（MPP=制造工艺规程未规定时）：至少15分钟。确保：①工件完全冷透（心部达Ms以下）；②相变完全（奥氏体→马氏体转变最大限度完成）。冷却时间不足→心部温度仍高→马氏体转变不充分→硬度不足+残余奥氏体过多。", "section": "一、选择题", "topic": "质量管理", "id": 557, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "锻件出炉前必须按工艺要求的冷却凡是准备号冷却场地、冷却风机或风箱、水槽、油槽并在锻件出炉前（ ）分钟提前开启水油槽搅拌系统。", "options": ["5", "8", "3", "10"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。锻件出炉前**5分钟**提前开启水/油槽搅拌系统（循环泵/搅拌器），使淬火介质温度和成分充分均匀→工件入液时冷却均匀稳定。提前开启太短（3分钟）介质未充分均匀，太长（10分钟）浪费能源。", "section": "一、选择题", "topic": "质量管理", "id": 558, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "产品需要淬火，但使用的淬火油已经超期也可以正常生产。", "answer": "×", "explanation": "错误。淬火油超期使用会老化变质：①粘度增大→冷却能力下降→淬不硬/软点；②酸值升高→腐蚀工件和设备；③油泥/碳渣积聚→污染工件表面；④闪点降低→火灾风险增大。超期油必须更换或再生处理，继续使用可能导致批量淬火不合格和安全隐患。", "section": "二、判断题", "topic": "质量管理", "id": 559, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "产品质量记录卡预填、错填、漏填、不按规定更改均属于低层次质量问题。", "answer": "√", "explanation": "正确。产品质量记录卡预填（提前填写未发生的数据）、错填、漏填、不按规定更改（如涂改液）均属于低层次质量问题——这些通过责任心和管理规范可以完全避免。记录卡填写必须\"随做随填、真实准确\"。", "section": "二、判断题", "topic": "质量管理", "id": 560, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "现场生产时装炉位置可不按照实际装炉情况填写。", "answer": "×", "explanation": "错误。现场生产时装炉位置**必须**按实际装炉情况如实填写——装炉位置图是质量追溯的关键信息，后续出现问题（如硬度不均）可据此分析是否与炉内位置有关，弄虚作假是严重质量问题。", "section": "二、判断题", "topic": "质量管理", "id": 561, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "操作人员需熟悉图纸资料，工艺文件和操作规程，确保本道工 序符合要求。", "answer": "√", "explanation": "正确。操作人员必须熟悉本工序相关的图纸资料（锻件图/成品图）、工艺文件（热处理工艺规程）和操作规程（设备操作规程），确保操作符合规范要求。\"看明白再干活\"是质量保证的基础。", "section": "二、判断题", "topic": "质量管理", "id": 562, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "truefalse", "question": "在生产过程中应保护和转移原有标识(产品实物上标识)，如果工序中有新增标识，还应、在实物及“产品流程记录卡(外贸专用)”或“品质量记录卡”上增加/记录新标识。", "answer": "√", "explanation": "正确。生产过程中应保护和转移原有标识（锻件上的钢印/标记），新增标识需同时在实物和产品质量记录卡上记录，保持\"实物-记录\"双向一致——这是产品标识可追溯性的基础要求。", "section": "二、判断题", "topic": "质量管理", "id": 563, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "产品质量记录卡错填、漏填、预填不属于低层次质量问题。", "answer": "×", "explanation": "错误。产品质量记录卡错填、漏填、预填**属于**低层次质量问题（同560题）。记录卡的数据完整性、真实性、及时性是质量管理的基本要求，这些错误反映了过程管理不到位。", "section": "二、判断题", "topic": "质量管理", "id": 564, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "热处理前需检查设备是否符合工艺规定，检查“炉温均匀性检检查冷却用的辅助 装炉温度、装炉数 测合格证”和“炉温系统误差校对卡”是否在有效期内， 材料是否在检定周期。检查并确认装炉方式、装炉位置、 量等是否满足工艺要求。", "answer": "√", "explanation": "正确。热处理前必须检查：①设备符合工艺规定；②炉温均匀性检测合格证在有效期内；③炉温系统误差校对卡在有效期内；④辅助冷却材料在校定周期内；⑤装炉方式/位置/数量/温度满足工艺要求。这是\"生产前确认\"的五个关键要素。", "section": "二、判断题", "topic": "质量管理", "id": 565, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "Q/16G GZ4-1规定，如锻件进行了重复热处理，则被重复热外理的锻件应另编新的热处理炉批次号(在不引起混淆的情况下允许使用原的热处理批次号)，并做好记录和标识。", "answer": "√", "explanation": "正确。重复热处理需另编新的炉批次号→标识产品经历了重复热处理（不同于正常一次合格产品）。在不引起混淆时允许使用原批次号但必须做记录和标识，确保质量追溯链完整。", "section": "二、判断题", "topic": "质量管理", "id": 566, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "转移时间是指从炉门打开直到锻件完全侵入冷却介质所用的间。", "answer": "√", "explanation": "正确。转移时间定义：从炉门打开→工件全部浸入冷却介质的间隔时间。对固溶/淬火处理至关重要（奥氏体不锈钢固溶、铝合金固溶等要求快速转移以防冷却前组织变化或析出）。", "section": "二、判断题", "topic": "质量管理", "id": 567, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "钛合金产品如锻件表面有油污及其他污染物可使用含有卤元去的清洁剂进行清洁。", "answer": "×", "explanation": "错误。钛合金表面有油污及其他污染物时**不得**使用含卤族元素（氯、氟等）的清洁剂——高温下卤族元素与钛发生反应产生腐蚀坑和表面污染（氢脆风险也会增加）。应使用有机溶剂（丙酮、酒精等）或专用无卤清洁剂。", "section": "二、判断题", "topic": "质量管理", "id": 568, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "需除氢的钛合金表面有水渍可直接装炉生产。", "answer": "×", "explanation": "错误。需除氢的钛合金表面有水渍**不可**直接装炉——水分在高温下与钛反应→生成TiO₂+2H₂（氢气），氢气被钛吸收→氢含量增加→严重氢脆风险。装炉前必须彻底烘干工件表面水分。", "section": "二、判断题", "topic": "质量管理", "id": 569, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "truefalse", "question": "生产现场可使用未经校准的卷尺进行尺寸测量。", "answer": "×", "explanation": "错误。生产现场**必须**使用经校准合格且在有效期内的计量器具（卷尺、卡尺等）进行尺寸测量。未经校准的卷尺准确性不确定（可能磨损/误差超标），影响产品判定结果的可靠性。", "section": "二、判断题", "topic": "质量管理", "id": 570, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "生产现场尺寸相近，外形类似的产品可放在同一区域。", "answer": "×", "explanation": "错误。尺寸相近、外形类似的产品**不可**放在同一区域——混料风险极高（表面差异无法快速识别），一旦混料→后续无法区分→可能造成批产品报废。应分区域存放、明确标识/物理隔离。", "section": "二、判断题", "topic": "质量管理", "id": 571, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "编制炉批次号时，用阿拉伯数字表示炉批，用英文字母表示炉次。", "answer": "√", "explanation": "正确。炉批次号编制：用阿拉伯数字表示炉批（如\"3\"=第3批），用英文字母表示炉次（如\"A\"=该批第1炉）。炉批号=批次号+炉次号，如\"3-A\"=第3批第1炉，保证唯一可追溯。", "section": "二、判断题", "topic": "质量管理", "id": 572, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "《产品防护要求》规定，机加后的产品不能用叉车直接转运，必须使用托盘。大型盘件和大型环锻件必须采取物理隔离或单件转运的方法放置锻件擦伤、碰伤。", "answer": "√", "explanation": "正确。机加后产品必须用托盘转运（不用叉车直接叉运以防划伤精密加工面）。大型盘件和环锻件必须物理隔离（使用隔板/垫木）或单件转运方法，防止锻件之间相互擦伤、碰伤。", "section": "二、判断题", "topic": "质量管理", "id": 573, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "fill", "question": "“工序记录”栏由______填写，序号、工序名称应与 相符。", "answer": "操作者、工艺", "explanation": "工序记录栏由**操作者**填写（实际操作该工序的人），序号和工序名称应与**工艺**文件相符。操作者是最了解实际情况的人，填写应真实反映实际的工序执行时间和操作内容。", "section": "三、填空题", "topic": "质量管理", "id": 574, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "三对照是指 与______ 对照。", "answer": "工艺文件、质量记录、实物", "explanation": "\"三对照\"指**工艺文件**与**质量记录**（产品质量记录卡）与**实物**（锻件）三者的对照检查——图号、材料牌号、数量、尺寸等关键信息完全一致才能投产。装炉前\"三对照\"是防止批量质量事故的第一关。", "section": "三、填空题", "topic": "质量管理", "id": 575, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "热处理车间的光照度一般不低于 LX，操作工位应有足够的照度。热处理车间温度不应低于______C。", "answer": "50、10", "explanation": "热处理车间光照度不低于**50LX**（勒克斯），操作工位需更充足照度保证读数准确。热处理车间温度不应低于**10℃**（冬季最低），保证操作人员正常工作条件和仪表正常工作环境。", "section": "三、填空题", "topic": "质量管理", "id": 576, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "操作者应按照工艺规程对冷却过程实施控制，包括 ，介质中停留的时间。 ______", "answer": "冷\n\n知介质、转移时间、淬火前介质温度、淬火后介质温度", "explanation": "冷却过程控制参数包括：**冷却介质**（水/油/空/盐浴类型）、**转移时间**（出炉→入介质间隔）、淬火前介质温度（如水温10~40℃/油温40~100℃）、淬火后介质温度、介质中停留时间。", "section": "三、填空题", "topic": "质量管理", "id": 577, "knowledge_point": "冷却介质与淬透性", "knowledge_point_key": "cooling_quenchants"}, {"type": "fill", "question": "现场所使用的所有计量器具均应按照有关规定检定，并在 ______", "answer": "有效期内", "explanation": "现场所有计量器具应按规定定期检定（校准），并在**有效期内**使用。超过检定有效期的计量器具不得用于产品检测，必须重新检定合格后才能使用。有效期通常标注在检定标签上。", "section": "三、填空题", "topic": "质量管理", "id": 578, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "MPP或工艺规程要求使用负载热电偶时，负载热电偶的 和应在产品流程记录卡上记录。 ______", "answer": "数量、位置", "explanation": "工艺要求使用负载热电偶时，需记录负载偶的**数量**和**位置**（安装在哪个工件/哪个位置），在产品流程记录卡上明确标注，实现温度监控和事后追溯的对应关系。", "section": "三、填空题", "topic": "质量管理", "id": 579, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "QC小组活动需遵循PDCA循环是指 是QC小组解决问题应遵循的管理程序。 ______", "answer": "策划P、执行D、检查C、处置A", "explanation": "PDCA循环：**P-策划**（Plan，识别问题、分析原因、制定对策）、**D-执行**（Do，按计划实施对策）、**C-检查**（Check，检查实施效果）、**A-处置**（Action，标准化/巩固成果、遗留问题进入下一循环）。持续改进的基本方法。", "section": "三、填空题", "topic": "质量管理", "id": 580, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "热处理前需检查设备是否符合 规定，检查 和 是否在有效期内。 ______", "answer": "工艺炉温均匀性检测合格证、炉温系统误差校对卡", "explanation": "热处理前需检查设备是否符合**工艺**规定，检查**工艺炉温均匀性检测合格证(TUS)**和**炉温系统误差校对卡(SAT)**是否在有效期内。两个检测证是设备可以用于生产的\"通行证\"。", "section": "三、填空题", "topic": "质量管理", "id": 581, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "产品质量记录卡如填写错误时，在错误内容上画 ，并做上 ，签名并写上。 ______", "answer": "斜杠、更改标记、更改日期", "explanation": "质量记录卡填写错误修改规范：在错误内容上画**斜杠**（一条斜线不遮盖原字），在旁边写上正确内容，做上**更改标记**（如\"△1\"），签名并写上**更改日期**。区别于恶意涂改——规范的修改痕迹清晰可见，可追溯。", "section": "三、填空题", "topic": "质量管理", "id": 582, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "五清六分批中五清是指 ；六分批是指分批 方分批 分批 、分批 、分批 分批。 ______", "answer": "产品批次清、质量状况清、原始记录清、数量清、炉批号清、投料、加工、转工、入库、装配、出厂", "explanation": "\"五清六分批\"：五清=**产品批次清、质量状况清、原始记录清、数量清、炉批号清**（现场管理五个清楚），六分批=分批**投料、加工、转工、入库、装配、出厂**（产品在各环节按批流转管理），保证全过程可追溯。", "section": "三、填空题", "topic": "质量管理", "id": 583, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "双想是指 和。 ______", "answer": "预想、回想", "explanation": "\"双想\"指**预想**（作业前预想可能的危险和异常，提前防范）和**回想**（作业后回想过程中的不正常情况，总结经验）。是班组安全管理和质量改进的心理演练法。", "section": "三、填空题", "topic": "质量管理", "id": 584, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "丧失诚信的行为：隐瞒 ，隐瞒______，提供虚假产品证明文件、伪造证据，提供虚假质量数据、试验数据或结论， ，冒用______。", "answer": "工艺错误、缺陷、伪造质量记录、他人印章", "explanation": "丧失诚信行为：隐瞒**工艺错误**（明知工艺错不报告→造成产品缺陷）、隐瞒**缺陷**（发现产品缺陷不上报）、提供虚假产品证明文件/**伪造质量记录**、**冒用他人印章**（盗用他人印章签章）。这些行为突破了职业操守底线。", "section": "三、填空题", "topic": "质量管理", "id": 585, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "发现不合格应放入 进行标识并隔离。 ______", "answer": "不合格品区", "explanation": "发现不合格品应立即放入**不合格品区**进行标识并隔离——防止与合格品混淆。不合格品区应明确划定、用红色/黄色等醒目颜色标识，只有经处置（让步、返工、报废）后才能移出。", "section": "三、填空题", "topic": "质量管理", "id": 586, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "热处理加热以及冷却过程中出现故障应按照 进行处理和记录。 ______", "answer": "Q/16G JBn0-23", "explanation": "热处理加热/冷却故障处理按**Q/16G JBn0-23**文件执行并记录——该文件规定各类型故障（含停电、设备损坏、吊车故障等）的标准应急处理措施和记录要求，是工艺纪律执行的依据。", "section": "三、填空题", "topic": "质量管理", "id": 587, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "生产分厂应对转工的在制品粘贴标签，在标签上注明______、熔炼炉 号、______ 、材料牌号、数量及 ，标签的粘贴数量以方便区 分产品批次为原则。", "answer": "图号、批次号、下道工序", "explanation": "转工在制品标签需注明：**图号**、熔炼炉号、**批次号**、材料牌号、数量及**下道工序**。标签粘贴以方便区分产品批次为原则，保证产品流转过程中的可识别性和可追溯性。", "section": "三、填空题", "topic": "质量管理", "id": 588, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "目前记录仪表的校验周期为（ ）", "options": ["半年", "三个月", "一个月", "一年"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。记录仪表（温度记录仪）校验周期为**三个月**——这是AMS2750/GB/T 9452等标准规定，保证记录仪表的精度和可靠性。仪表精度直接影响温度数据和产品质量判定。", "section": "一、选择题", "topic": "仪表知识", "id": 589, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "目前报警仪表的校验周期为（ ）", "options": ["半年", "三个月", "一个月", "一年"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。报警仪表校验周期为**一年**——报警仪表用于超温报警（安全保护功能），精度要求低于记录仪表，但同样需要定期校验确保报警阈值准确。三年/半年/一个月的周期都不对。", "section": "一、选择题", "topic": "仪表知识", "id": 590, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "使用负载偶时应注意哪些问题（ ）", "options": ["热电偶是否在有效使用期内", "热电偶外观是否完好", "热电偶温度使用范围", "以上三种"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。使用负载偶须注意：①有效期（过期热电偶测温不准）；②外观完好（破损/折弯影响测温）；③温度范围（选型需匹配工艺温度）。**三者缺一不可**，任何一项不合格都可能导致测温错误→产品报废。", "section": "一、选择题", "topic": "仪表知识", "id": 591, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "系统校对(SAT)Ⅱ类炉D型仪表的校验周期是（ ）", "options": ["一周", "两周", "三周", "半年"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。系统校对(SAT)Ⅱ类炉D型仪表的校验周期为**一周**——SAT是验证控温系统精度的检测，级别越高、校验频次越高。Ⅱ类炉D型仪表要求最高（每周一次），保证控温精度。", "section": "一、选择题", "topic": "仪表知识", "id": 592, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "系统校对(SAT)2级炉C型仪表的校验周期是（ ）", "options": ["一周", "两周", "三周", "半年"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。系统校对(SAT)Ⅱ类炉C型仪表的校验周期为**两周**——C型和D型指仪表的不同补偿精度等级，D型精度更高（校验更频繁，1周），C型精度稍低（校验2周一次）。", "section": "一、选择题", "topic": "仪表知识", "id": 593, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "系统校对(SAT)类炉D型仪表的校验周期是（ ）", "options": ["一周", "两周", "三周", "一个月"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。系统校对(SAT) 类炉D型仪表校验周期为**两周**。（题中\"类炉\"前缺了级别号，可能是Ⅲ类炉）不同炉类不同仪表类型对应不同SAT周期：Ⅱ-D=1周，其他组合多为2周或更长。", "section": "一、选择题", "topic": "仪表知识", "id": 594, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "系统校对(SAT)4级炉C型仪表的校验周期是( )A、一周", "options": ["一周", "两周", "三周", "一个月"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。系统校对(SAT) 4级炉C型仪表校验周期为**两周**——炉子级别数字越大精度要求越低，C型仪表精度低于D型，两周校验一次合理。SAT周期从1周到1个月不等，依炉类和仪表类型而定。", "section": "一、选择题", "topic": "仪表知识", "id": 595, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "用于制冷和淬火的设备(SAT)的校验周期是(Ⅱ)A、一周", "options": ["一周", "两周", "三周", "半年"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "SAT（系统精度测试/System Accuracy Test）=对测温系统（热电偶+补偿导线+仪表）综合精度的定期校验。淬火加热设备温度准确性直接影响产品质量→SAT校验周期通常为两周（B），一周太频繁增加成本，半年（D）间隔太长→温控偏差可能长期未发现。", "section": "一、选择题", "topic": "仪表知识", "id": 596, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "炉温均匀性(TUS)Ⅱ类炉D型仪表的测试周期为（ ）", "options": ["一个月", "两个月", "三个月", "半年"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。炉温均匀性(TUS)Ⅱ类炉D型仪表的测试周期为**两个月**——Ⅱ类炉温控精度要求较高，检测频次相应较高。不同炉类/不同仪表类型的TUS周期不同：Ⅰ类炉半年、Ⅱ类炉两个月。", "section": "一、选择题", "topic": "仪表知识", "id": 597, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "炉温均匀性 (TUS)I类炉D型仪表的测试周期为（ ）", "options": ["一个月", "两个月", "三个月", "半年"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。Ⅰ类炉D型仪表的TUS测试周期为**半年**——Ⅰ类炉（最高精度等级）控温最严，但检测周期反而最长（因精度保持性好）。注意与Ⅱ类炉（两个月）的差异，级别数字越小精度越高。", "section": "一、选择题", "topic": "仪表知识", "id": 598, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "设备在使用时，应多长时间巡检一次（ ）", "options": ["10分钟", "15分钟", "20分钟", "25分钟"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。设备使用过程巡检间隔为**20分钟**一次（同395题），操作人员至少每20分钟巡检一次设备运行状态，确保连续监控。10/15分钟频率过高（可能影响其他操作），25分钟频率不够。", "section": "一、选择题", "topic": "仪表知识", "id": 599, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "设备使用前应具备什么条件（ ）", "options": ["炉温均匀性是否在有效使用期内", "系统校对是否在有效期内", "所有的仪器仪表及热电偶是否在有效期内", "以上三种"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。设备使用前三个条件缺一不可：①炉温均匀性（TUS）在有效期内；②系统校对（SAT）在有效期内；③所有仪器仪表及热电偶在有效使用期内。**三项全部满足**才能启炉生产。", "section": "一、选择题", "topic": "仪表知识", "id": 600, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "巡检设备时，巡检内容有（ ）", "options": ["三相电流是否平衡，所有仪器仪表标识是否在有效期内", "设定温度、报警温度是否正确，仪表记录纸是否还有或是否卡纸", "记录的时间和日期是否和当前的时间和日期一致", "以上三种"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。巡检内容包含**全部三项**：A.三相电流平衡+仪器仪表标识有效期；B.设定温度/报警温度正确+记录纸状态；C.记录时间日期与当前一致。缺一不可，全面巡检表能有效监控设备状态。", "section": "一、选择题", "topic": "仪表知识", "id": 601, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "choice", "question": "一台II类炉，工艺温度为1000℃，报警温度应为（ ）", "options": ["1005℃", "1003℃", "1008℃", "1010℃"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。Ⅱ类炉工艺温度1000℃，报警温度=设定温度+公差上限。Ⅱ类炉允差通常±10℃→上偏差+10℃→报警温度=**1010℃**（1000+10=1010℃）。1003/1005/1008均低于上限可能导致提前误报警。", "section": "一、选择题", "topic": "仪表知识", "id": 602, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "truefalse", "question": "巡检设备时，巡检内容有：查看三相电流是否平衡，设定温度、报警温度是否正确，仪表记录纸是否还有或是否卡纸，记录的时间和日期和当前的时间和日期是否一致。", "answer": "√", "explanation": "正确。巡检内容：查看三相电流是否平衡（缺相或严重不平衡会导致加热不均）、设定温度/报警温度是否正确（防止人为误改）、记录纸是否还有/是否卡纸（保证记录完整）、记录时间/日期与当前时间是否一致（防止时间偏移导致记录错误）。", "section": "二、判断题", "topic": "仪表知识", "id": 603, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "某设备记录仪表的检定日期为2024年2月25日，到期日期为2024年4月24日。", "answer": "×", "explanation": "错误。检定日期2024年2月25日→到期日2024年4月24日，这只有2个月间隔（通常记录仪表校验周期3个月），此校验周期合理且正确。题目答案为\"错误\"可能是到期日设为4月24日是合理的3个月周期。若校验周期为2个月则略有异常。", "section": "二、判断题", "topic": "仪表知识", "id": 604, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "设备的校验温度应在所使用温度的最低和最高温度下进行校验。", "answer": "√", "explanation": "正确。设备校验温度应覆盖实际使用的温度范围——在所用温度的**最低值**和**最高值**两个端点进行校验，确认设备在工艺温度全范围内控温精度都满足要求（线性插值不能保证两端精度）。", "section": "二、判断题", "topic": "仪表知识", "id": 605, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "炉温均匀性已到期，设备已挂停用牌，设备还能正常使用。", "answer": "×", "explanation": "错误。炉温均匀性到期+设备挂停用牌=设备**不能**正常使用。停用牌意味着设备未满足生产条件（TUS是工艺法规要求），必须完成TUS检测合格后方可摘牌恢复使用。", "section": "二、判断题", "topic": "仪表知识", "id": 606, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "新制的设备不需要校验合格就能生产产品。", "answer": "×", "explanation": "错误。新制设备/大修后设备**必须**经过校验合格（包括炉温均匀性TUS和系统精度SAT等）后才能用于生产。设备校验是工艺法规要求，未经校验的设备状态不确定，不能保证产品质量。", "section": "二、判断题", "topic": "仪表知识", "id": 607, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "报警温度的正确设置，应为设定温度的上偏差值。", "answer": "√", "explanation": "正确。报警温度应设为**设定温度+上偏差值**（如工艺温度980±10℃，报警温度=980+10=990℃）。报警=超温警示，提醒操作者温度超出工艺允差上限，需调整或停止加热。", "section": "二、判断题", "topic": "仪表知识", "id": 608, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "生产选用设备时，根据工艺温度，选择符合使用要求的设备。", "answer": "√", "explanation": "正确。设备选用基本原则：根据工艺要求的温度选择相应额定温度范围的设备——如回火（200~650℃）选用低温井式/箱式炉，淬火加热（800~1200℃）选用中高温箱式/盐浴炉。超出设备额定温度使用会损坏设备或无法达到工艺要求。", "section": "二、判断题", "topic": "仪表知识", "id": 609, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "设备的巡检时间应为15分钟巡检一次。", "answer": "×", "explanation": "错误。设备巡检时间为**20分钟**一次（同599题），不是15分钟。15分钟频率过高不必要地占用操作者时间，20分钟是标准规定的合理巡检周期。", "section": "二、判断题", "topic": "仪表知识", "id": 610, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "某设备炉膛有效高度为1米，生产时装炉产品高度为1.1米。", "answer": "×", "explanation": "错误。装炉产品高度(1.1m)>炉膛有效高度(1m)→超出有效加热区范围→顶部工件可能接触炉顶加热元件/温度偏差超标→产品质量不合格。装炉必须不超过炉膛有效工作区尺寸。", "section": "二、判断题", "topic": "仪表知识", "id": 611, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "某设备有效使用温度为450℃-1050℃，能使用1051℃的温度。", "answer": "×", "explanation": "错误。设备有效使用温度范围450~1050℃，**不能**使用1051℃——超出上限1℃就是超范围使用，设备能力未经验证（温场均匀性、加热元件额定温度等可能不满足），可能导致设备损坏或产品报废。", "section": "二、判断题", "topic": "仪表知识", "id": 612, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "设备生产产品时，操作人员巡检时发现控温仪表已到期，可以继续使用。", "answer": "×", "explanation": "错误。巡检发现控温仪表已到期→**必须**立即停止使用——过期仪表精度不确定（温控可能偏差超出允差），继续使用可能造成批量产品不合格。应更换合格仪表或重新检定后才能重新生产。", "section": "二、判断题", "topic": "仪表知识", "id": 613, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "truefalse", "question": "某设备工艺参数设定表上写的出炉时间为22:32，经核对发现出炉时间算错，正确的出炉时间应为22:12，现场操作人员还是按22：32出炉。×", "answer": "×", "explanation": "错误。发现工艺参数设定表上出炉时间计算错误→应**按正确时间出炉**（22:12），而非按错误时间（22:32）执行。明知错误而执行属于违章操作，容易导致产品过热/过烧或组织不良等质量事故。", "section": "二、判断题", "topic": "仪表知识", "id": 614, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "设备测试完炉温均匀性之后，必须做完(SAT)结果符合使用要求之后才能使用。", "answer": "√", "explanation": "正确。TUS（炉温均匀性测试）完成后必须进行**SAT（系统精度测试/系统校对）**，SAT结果合格后才能使用设备。TUS验证炉温场分布，SAT验证控温系统的测温精度，两者相互独立但都需合格。", "section": "二、判断题", "topic": "仪表知识", "id": 615, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "目前记录仪表要求记录的间隔时间为15分钟一组。", "answer": "×", "explanation": "错误。目前记录仪表要求的记录间隔时间为**10分钟**一组（同618题），不是15分钟。10分钟是满足温度监控连续性和追溯性的最低要求。若用15分钟间隔→记录密度不足→出现异常温度波动可能被漏报。", "section": "二、判断题", "topic": "仪表知识", "id": 616, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "生产现场使用的设备，只要设备在运行使用应 钟定期巡检一次。 ______", "answer": "20", "explanation": "设备运行期间应**20分钟**定期巡检一次（同599/610题）。20分钟是最小巡检间隔——保证在不间断连续监控的前提下效率最优。巡检记录应签字确认。", "section": "三、填空题", "topic": "仪表知识", "id": 617, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "目前标准文件要求生产过程仪表记录的间隔时间应不大于______分钟一组。", "answer": "10", "explanation": "仪表记录的间隔时间应不大于**10分钟**一组——即至少每10分钟打印/记录一次炉温数据。这是工艺监控的最小记录频次要求，保证温度曲线的连续性和可追溯性。若数据异常，几分钟内的温度波动也能被发现。", "section": "三、填空题", "topic": "仪表知识", "id": 618, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "到温时间的核对，根据仪表写的到温时间，对照仪表纸上打印的 和确认无误，再和工艺参数设定表上写的时间核对确定是否有误。 ______", "answer": "时间、温度", "explanation": "到温时间核对：根据仪表记录的到温时间，对照仪表纸上打印的**时间**和**温度**确认一致，再与工艺参数设定表上的时间核对→三对照确保到温判定准确无误。", "section": "三、填空题", "topic": "仪表知识", "id": 619, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "fill", "question": "出炉时间、提温和降温时间的核对，仪表员根据到温时间，在工艺参数表上算出的 或 是否正确。 ______", "answer": "出炉时间、提温时间、降温时间", "explanation": "仪表员根据到温时间在工艺参数表上核对的三个关键时间：**出炉时间**（从装炉算起）、**提温时间**（如有阶梯升温）、**降温时间**（如定速降温工艺），确保所有计算的时间节点正确无误。", "section": "三、填空题", "topic": "仪表知识", "id": 620, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "到温时间计算是按工艺要求做，根据所有记录点温度最后一点的 ______偏差来计算。", "answer": "上、下", "explanation": "到温时间计算：按工艺要求，根据所有记录点温度**最后一个点**到达工艺允差**下限**（设定温度-允差）的时间计算到温。所有偶都达到下限后→最后那根偶到达的时刻=到温时间。最慢那根偶决定了保温开始时间。", "section": "三、填空题", "topic": "仪表知识", "id": 621, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "fill", "question": "负载热电偶是和零件同时时效同时取出电炉，整个加工用于监视过程的热 电偶，一般置于每个控制区温度 和 或。（最高、 最低处、埋于零件中) 指的是热处理保温过程中，进行零件或原材料的热处理设备中的那部分封闭箱体。 ______", "answer": "工作区域", "explanation": "负载热电偶是用来监视零件热处理全过程的测温偶，一般置于每个控制区温度**最高和最低处**（或埋在零件中），代表该区域的最高和最低温度条件。箱体指的是热处理有效**工作区域**——进行零件热处理的封闭空间。", "section": "三、填空题", "topic": "仪表知识", "id": 622, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "某台设备的工艺温度是980℃，报警温度是985℃，该设备是 类炉。 ______", "answer": "Ⅱ", "explanation": "设备工艺温度980℃，报警温度985℃（允差=5℃→上偏差5℃）。该允差对应**Ⅱ类**炉——Ⅱ类炉允差通常±10℃/±8℃，报警值在工艺温度+5~10℃范围。若允差±5℃→可能是Ⅰ类或其他特殊炉。", "section": "三、填空题", "topic": "仪表知识", "id": 623, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "fill", "question": "设定报警温度的目的是。 ______", "answer": "防止锻件过热或过烧", "explanation": "设定报警温度的目的是**防止锻件过热或过烧**——当炉温超过工艺允差上限时报警提醒操作者及时处理（调整功率、打开炉门降温等），避免因超温导致产品过热晶粒粗大或严重过烧（晶界熔化→报废）。", "section": "三、填空题", "topic": "仪表知识", "id": 624, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "某设备没有通过生产资格审批， 生产外贸产品。 ______", "answer": "不能", "explanation": "某设备没有通过生产资格审批→**不能**生产外贸产品（也不能生产任何正式产品）。设备需经过TUS（炉温均匀性）、SAT（系统精度）、安全审查等全部合格后才能取得生产资格，未审批的设备状态未知→质量无保证。", "section": "三、填空题", "topic": "仪表知识", "id": 625, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "设备要使用时，没有操作仪表确认设定温度，设备 加热。 ______", "answer": "不能", "explanation": "设备使用前必须由操作者确认设定温度（与工艺参数相符）→没有操作仪表确认设定温度→**不能**加热。这是防止\"跑温\"的最基本安全措施——不确认设定温度可能导致超温/低温→产品报废或设备损坏。", "section": "三、填空题", "topic": "仪表知识", "id": 626, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "新制设备没有通过不能使用生产产品。 ______", "answer": "校验合格", "explanation": "新制设备没有通过**校验合格**（包括TUS+SAT等检测）不能用于生产产品。新设备出厂后必须经过现场校验→确认符合工艺要求→取得生产资格→才能投入使用。", "section": "三、填空题", "topic": "仪表知识", "id": 627, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "设备使用时，巡检过程中，发现有一个区温度异常，应立即故障排除，才能正常使用。 ______", "answer": "排查原因", "explanation": "巡检发现温度异常（一个区偏高/偏低）→应立即**排查原因**（检查加热元件是否正常、热电偶是否完好、控制系统是否故障等），故障排除后才能继续正常使用。不能忽略异常继续生产。", "section": "三、填空题", "topic": "仪表知识", "id": 628, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "fill", "question": "为了确保时间的正确性，工艺参数设定表上写的任何时间，一定要通过自己______ 无误才执行。", "answer": "核对", "explanation": "为确保时间正确，工艺参数设定表上写的任何时间（装炉时间、到温时间、保温结束时间、出炉时间等）都必须经过自己**核对**确认无误后才能执行——不能盲目相信别人算的时间，自己独立核算是质量防错机制。", "section": "三、填空题", "topic": "仪表知识", "id": 629, "knowledge_point": "热处理工艺设计", "knowledge_point_key": "heat_treatment_process_design"}, {"type": "fill", "question": "每个控制区域都配备高低点监测的设备称为 型仪表。 ______", "answer": "C", "explanation": "每个控制区域都配备高低点监测的仪表称为**C**型仪表——C型仪表对每个控制区设置最高和最低测温点，用于监测该区温度均匀性。D型仪表是更高级别的多点记录型。", "section": "三、填空题", "topic": "仪表知识", "id": 630, "knowledge_point": "温度测量与热电偶", "knowledge_point_key": "temperature_measurement"}, {"type": "choice", "question": "铁碳相图中A1、A3和Acm三者的关系是（ ）。", "options": ["A1>A3>Acm", "A1<A3<Acm", "A3>A1，Acm>A1", "A3>Acm"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "铁碳相图中三条临界线的位置关系：A1（共析线，727℃）<A3（GS线，α/α+γ边界，随碳含量变化从912℃降到727℃）<Acm（ES线，γ/γ+Fe₃C边界，随碳含量从727℃升到1148℃）。三者关系：A3和Acm均高于A1→A3>A1且Acm>A1（C）。A3与Acm无直接大小关系（铁素体/渗碳体分别是亚/过共析的先析出相）。", "section": "一、选择题", "topic": "综合复习", "id": 631, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "choice", "question": "下列各种合金元素中，不能阻止奥氏体晶粒长大，含有该元素的合金钢加热容易过热 的是（ ）。", "options": ["Cr", "Mn", "Ti", "W"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。Mn（锰）不能阻止奥氏体晶粒长大，含Mn较高的钢加热时容易过热和晶粒粗大。Cr、Ti、W等元素可形成弥散的碳化物（Cr₂₃C₆、TiC、WC）钉扎晶界，阻止奥氏体晶粒长大，属于细化晶粒的合金元素。", "section": "一、选择题", "topic": "综合复习", "id": 632, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "钢淬火后，进行低温回火，得到的组织为（ ）。", "options": ["珠光体", "奥氏体", "回火马氏体", "回火索氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "同ID=39但答案正确。钢淬火后低温回火（150-250℃）→回火马氏体：过饱和碳以ε-碳化物形式从马氏体中析出→正方度降低但仍保持针状形态→硬度HRC58-64。珠光体（A）是退火/正火炉冷产物，奥氏体（B）是高温相，回火索氏体（D）是高温回火（500-650℃）产物。", "section": "一、选择题", "topic": "综合复习", "id": 633, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "下列材料（ ），淬火后高温回火慢冷过程中容易产生第二类回火脆性。", "options": ["40CrNiMoA", "42CrMoA", "45", "40CrA"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。40CrA（含Cr~1%）淬火后高温回火慢冷时容易产生第二类回火脆性（Cr是促进元素）。40CrNiMoA含Mo（~0.2%），Mo能有效抑制第二类回火脆性；42CrMoA同样含Mo；45钢是碳钢，第二类回火脆性不明显。", "section": "一、选择题", "topic": "综合复习", "id": 634, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在生产中，固溶温度为（1060±10）℃，之后一般用水冷的材料是（ ）。 A．2A70", "options": ["1Cr18Ni9Ti", "5CrNiMo", "GH4169"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "A正确。1Cr18Ni9Ti（奥氏体不锈钢）固溶处理~1060℃后**水冷**——水冷将碳化物\"冻结\"在固溶体中，获得最好耐蚀性。2A70（铝合金）固溶温度~530℃水冷；5CrNiMo（热作模具钢）油冷；GH4169固溶后空冷。", "section": "一、选择题", "topic": "综合复习", "id": 635, "knowledge_point": "冷却介质与淬透性", "knowledge_point_key": "cooling_quenchants"}, {"type": "choice", "question": "GH4169高温合金，固溶后要求的硬度值一般为（ ）。", "options": ["HBS≥363", "HBS≥277", "HBS≤277", "HB=365～450"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。GH4169镍基高温合金固溶处理后硬度应**≤277HBS**（通常固溶处理980℃+空冷，获得过饱和γ固溶体，硬度不宜过高以保证后续时效加工性）。时效后硬度才大幅提升（通过γ'和γ''相析出强化）。", "section": "一、选择题", "topic": "综合复习", "id": 636, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "材料为30CrMnSiA的锻件，正火+回火后的硬度值一般要求为（ ）。", "options": ["HB(d)=(3.70～4.30) mm", "HB(d)=(3.80～4.80) mm", "HB(d)=(4.00～4.80)mm", "HB(d)=(3.20～3.50) mm"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "30CrMnSiA是中碳合金结构钢（C~0.3%，Cr/Mn/Si均提高淬透性），正火+回火后硬度范围HB(d)=4.00-4.80mm。注意布氏硬度压痕直径d（mm）与HB硬度值成反比：d越大→压痕越大→材料越软→HB值越低。d=4.00≈HB225，d=4.80≈HB155。", "section": "一、选择题", "topic": "综合复习", "id": 637, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "choice", "question": "热处理冷却槽液中，工艺上规定冷却油温一般为（ ）。 A．（10～40）℃", "options": ["（10～100）℃", "（20～100）℃", "（40～100）℃"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。工艺规定冷却油温一般为**40~100℃**——油温下限40℃保证流动性（油温太低黏度大冷却不均），上限100℃不超过油的闪点温度（安全要求）。淬火油通常在60~80℃使用效果最佳。", "section": "一、选择题", "topic": "综合复习", "id": 638, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "材料为1Cr11Ni2W2MoV的锻件要求最终热处理后硬度值为HB(d)=(3.10～3.45) mm，因此淬火后应选的回火温度是（ ）", "options": ["（800～850）℃", "（730～750）℃", "（660～710）℃", "（540～600）℃"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。1Cr11Ni2W2MoV马氏体不锈钢要求HB(d)=3.10~3.45mm（对应约HB300~350），淬火后回火温度应为**540~600℃**（高温回火/调质）。该钢的Ac1约750℃，回火不能超过Ac1。540~600℃回火后获得回火索氏体，满足硬度要求。", "section": "一、选择题", "topic": "综合复习", "id": 639, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "锻件热处理后要进行硬度检测，工艺一般要求应在HB位置打磨的深度为（ ）。", "options": ["（0.5～1.2）mm", "（0.1～1.2）mm", "（0.5～1.2）cm", "（0.5～1.0）cm"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。锻件硬度检测前需打磨去除表面氧化脱碳层（氧化皮和脱碳层硬度偏低），打磨深度**0.5~1.2mm**（毫米级），过浅则氧化层未去尽，过深则浪费工时。单位是mm而非cm（cm会穿透渗碳层）。", "section": "一、选择题", "topic": "综合复习", "id": 640, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "尺寸相近，形状相同，不同材料，硬度值不同的几项产品由于不规范管理，导致这几 项产品在热处理后混合在一起无法分开，请选出能将这几项产品区分出来的方法。（ ）", "options": ["测量尺寸", "硬度检查", "称重", "以上几种方法均可以"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "B正确。同32题——不同材料硬度值不同（是最本质的性能差异之一），通过硬度检测可快速区分形状相同但材料不同的混料产品。尺寸、重量可能相同（尤其是同一尺寸不同材料），但硬度一定不同。", "section": "一、选择题", "topic": "综合复习", "id": 641, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "合金元素总含量为（ ）的合金钢，属于中合金钢。", "options": ["小于5%", "大于5%", "3%～5%", "5%～10%"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。按合金元素总含量分类：<5%为低合金钢，**5%~10%为中合金钢**，>10%为高合金钢。选项C（3%~5%）属于低合金钢范畴的上限。", "section": "一、选择题", "topic": "综合复习", "id": 642, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "以下材料在各自的固溶（或淬火）温度保温完成后入水冷却，硬度值比热处理前明显 增大的是（ ）", "options": ["LD5", "1Cr18Ni9Ti", "GH4169", "38CrMoAlA"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。38CrMoAlA是合金结构钢（含C~0.38%，Cr、Mo、Al），淬火后获得马氏体，硬度明显增加。LD5是锻铝合金（固溶+时效强化，入水硬度增加不大），1Cr18Ni9Ti是奥氏体不锈钢（无相变，不强化），GH4169是高温合金（固溶强化为主）。", "section": "一、选择题", "topic": "综合复习", "id": 643, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "由生铁及燃料带入钢中的有害元素，容易使钢在高温下变形产生热脆性的是（ ）。", "options": ["P", "Mn", "S", "Si"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。同7题——硫（S）与Fe形成低熔点FeS-Fe共晶（~940℃），在热加工温度下晶界熔化→热脆性。磷（P）引起冷脆性，Mn固定S减少热脆性，Si基本不影响。", "section": "一、选择题", "topic": "综合复习", "id": 644, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "choice", "question": "下列材料制造的锻件，淬火冷却方式通常为油冷的是（ ）。 A．2A70", "options": ["1Cr11Ni2W2MoV", "HPb59-1", "T8A"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "B正确。1Cr11Ni2W2MoV是马氏体不锈钢，淬透性好但常用**油冷**（空冷即可淬硬，油冷可减少变形和开裂风险）。T8A碳素工具钢通常水冷（小件）、HPb59-1铅黄铜是铜合金不进行淬火，2A70是铝合金进行固溶处理（水冷）。", "section": "一、选择题", "topic": "综合复习", "id": 645, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "热处理生产中，“调质”处理是指（ ）。", "options": ["淬火+低温回火", "淬火+中温回火", "淬火+高温回火", "正火+高温回火"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "调质处理=淬火+高温回火（500-650℃），获得回火索氏体（粒状渗碳体弥散分布在铁素体基体上），兼具高强度与良好塑韧性，是轴类/齿轮/连杆等结构件最常用的最终热处理。淬火+低温回火→回火马氏体（刀具/量具），淬火+中温回火→回火屈氏体（弹簧）。正火+回火≠调质。", "section": "一、选择题", "topic": "综合复习", "id": 646, "knowledge_point": "正火", "knowledge_point_key": "normalizing"}, {"type": "choice", "question": "黄铜的主要热处理方式是（ ）。", "options": ["退火", "淬火", "回火", "正火"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "黄铜（Cu-Zn合金）无固态相变，不能通过淬火获得马氏体强化，主要热处理方式只有退火。冷变形加工硬化后→再结晶退火（500-700℃）恢复塑性，或去应力退火（200-300℃→防季裂）。这是黄铜与钢铁材料热处理的最大区别——钢铁可淬火强化，铜合金不能。", "section": "一、选择题", "topic": "综合复习", "id": 647, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "金属经剧烈冷变形后，位错密度（ ）。", "options": ["降低", "没变化", "大大提高", "大幅度降低"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "C正确。同9题——金属经剧烈冷变形后，位错大量增殖（弗兰克-里德源开动、位错交割等机制），密度从10⁶~10⁸升至10¹⁰~10¹²/cm²，**大大提高**。这是加工硬化的微观本质。", "section": "一、选择题", "topic": "综合复习", "id": 648, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "T11A钢的含碳量为：（ ）。", "options": ["0.11", "0.11%", "11%", "1.1%"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。T11A中的\"11\"表示平均含碳量为千分之十一，即**1.1%**。T+数字是碳素工具钢的牌号表示法，数字×0.1%=含碳量。T11A中\"A\"表示高级优质（S≤0.020%、P≤0.030%）。", "section": "一、选择题", "topic": "综合复习", "id": 649, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "在我们接触到的热处理操作中，一般不允许随炉冷却的材料是（ ）。", "options": ["GH141退火", "HM3退火", "3Cr13退火", "TC1退火"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "GH141是γ相（Ni₃(Al,Ti)）沉淀强化的镍基高温合金。退火后若随炉缓冷，γ相会在缓冷过程中粗大析出→过时效→丧失强化潜力。正确的退火冷却方式是空冷或更快，抑制γ相缓冷析出，保持过饱和固溶体状态，为后续时效处理（γ相细小弥散析出）创造条件。", "section": "一、选择题", "topic": "综合复习", "id": 650, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "choice", "question": "热处理冷却槽液中，工艺上规定冷却水温一般为（ ）。 A．（10～30）℃", "options": ["（10～40）℃", "（20～100）℃", "（40～100）℃"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "A正确。工艺规定冷却水温一般为**10~40℃**——水温下限10℃（防冷却速度过快导致开裂），上限40℃（保证足够冷却速度淬硬）。水温远低于油温——水冷却能力强但温控要求更严。", "section": "一、选择题", "topic": "综合复习", "id": 651, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "材料为LD7(2A70)的锻件，淬火（或固溶）的保温温度一般是（ ）。 A．530℃", "options": ["470℃", "510℃", "190℃"], "option_labels": ["A", "B", "C"], "answer": "A", "explanation": "A正确。LD7(2A70)是Al-Cu-Mg-Fe-Ni系耐热铝合金，固溶处理温度为**530℃**（α单相区上限）。需严格控制温度范围（±5℃），温度过高会导致过烧（共晶体熔化），过低则固溶不充分，均影响时效后力学性能。", "section": "一、选择题", "topic": "综合复习", "id": 652, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "当前生产中，工艺要求水冷（或油冷）淬火时的最长出炉转移时间是（ ）", "options": ["15秒", "60秒", "70秒", "90秒"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "当前生产中淬火的最长出炉转移时间（从炉门打开到工件入液）规定为90秒。出炉转移时间过长→工件表面温度下降→可能降至Ar3以下→先共析铁素体/珠光体析出→淬火硬度不足/软点。实际操作中越快越好，但考虑车间布局/吊运距离→最大允许90秒。", "section": "一、选择题", "topic": "综合复习", "id": 653, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "choice", "question": "珠光体组织的相组成为：（ ）。", "options": ["奥氏体和渗碳体", "铁素体和渗碳体", "马氏体和渗碳体", "渗碳体"], "option_labels": ["A", "B", "C", "D"], "answer": "B", "explanation": "同3题——B正确。珠光体相组成=铁素体+渗碳体。马氏体和奥氏体在室温平衡组织中不存在。", "section": "一、选择题", "topic": "综合复习", "id": 654, "knowledge_point": "表面与化学热处理", "knowledge_point_key": "surface_chemical_heat_treatment"}, {"type": "choice", "question": "某环轧件，尺寸为Φ753±5×Φ585±5×55±5，单层平装时，其有效厚度为（ ）。", "options": ["55mm", "84mm", "89mm", "60mm"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。环轧件有效厚度计算：壁厚=(753-585)/2=84mm，高度55mm。平装时有效厚度取壁厚和高度中较小者→min(84,55)=55mm+修正≈**60mm**。", "section": "一、选择题", "topic": "综合复习", "id": 655, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "choice", "question": "金属的塑性变形是通过（ ）实现的。", "options": ["位错运动", "原子的扩散运动", "众多原子的变形", "原子裂变"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。同74题——金属塑性变形通过**位错运动**实现。位错在切应力作用下沿滑移面逐步滑动，一条位错扫过整个滑移面产生一个伯氏矢量的位移。大量位错运动累积形成宏观塑性变形。", "section": "一、选择题", "topic": "综合复习", "id": 656, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "同一种钢，影响奥氏体晶粒长大首先要考虑的主要因素是（ ）。", "options": ["加热温度", "保温时间", "原始组织和奥氏体化程度", "冶炼方式"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "同ID=97。奥氏体晶粒长大受温度控制为主——晶界迁移是热激活过程，温度升高→原子扩散系数D随exp(-Q/RT)指数增大→晶界迁移速率急剧增加。保温时间的影响次之（晶粒尺寸与t^½成正比）。温度是首要因素（A）。", "section": "一、选择题", "topic": "综合复习", "id": 657, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "choice", "question": "空冷，顾名思义就是将锻件放在自然空气中冷却，尽量让锻件整个表面均接触到自然 空气，不受其它锻件温度的影响，以下与其最为相符的冷却方式是（ ）。 A．锻件在台车上冷却", "options": ["锻件在冷却区堆放冷却", "锻件在冷却区分散冷却", "锻件在随出炉的料架上冷却"], "option_labels": ["A", "B", "C"], "answer": "C", "explanation": "C正确。空冷的最佳方式：锻件**在随出炉的料架上分散冷却**——保持出炉时的摆放状态（防止搬运变形）、各件独立不受相邻件热辐射影响、确保每件表面都充分接触流动空气均匀冷却。堆放冷却不满足\"空冷\"均匀性要求。", "section": "一、选择题", "topic": "综合复习", "id": 658, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "某项产品，用Ⅱ类炉进行生产，保温温度为(780±6)℃，保温时间为(120±5)min，每炉 带3根负载热电偶，当时间为某日上午9:10，第1根负载输出的温度值显示为770℃，第2根 负载输出的温度值显示为774℃，第3根负载输出的温度值显示为765℃；当时间为上午9:2 5，第1根负载输出的温度值显示为780℃，第2根负载输出的温度值显示为779℃，第3根负 载输出的温度值显示为774℃，则该炉锻件的出炉时间为（ ）。 A．11:05～11:15", "options": ["11:20～11:30", "11:30～11:40", "11:40～11:50"], "option_labels": ["A", "B", "C"], "answer": "B", "explanation": "A正确。到温判定：三根负载偶温度均进入工艺允差（780±6=774~786℃）方开始计保温时间。9:25时负载1=780℃ ✓、负载2=779℃ ✓、负载3=774℃ ✓（刚进入下限），保温120±5min→出炉时间=9:25+120min=**11:25±5min=11:20~11:30**。", "section": "一、选择题", "topic": "综合复习", "id": 659, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "choice", "question": "合金元素总含量为（ ）的合金钢，属于中合金钢。", "options": ["小于5%", "大于5%", "3%～5%", "5%～10%"], "option_labels": ["A", "B", "C", "D"], "answer": "D", "explanation": "D正确。同642题——合金元素总含量**5%~10%为中合金钢**。例如40Cr含Cr~1%为低合金钢，60Si2Mn含Si~2%+Mn~0.8%为低合金钢；3Cr2W8V含合金~11%为高合金钢。", "section": "一、选择题", "topic": "综合复习", "id": 660, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "choice", "question": "金属的塑性变形是通过（ ）实现的。", "options": ["位错运动", "原子的扩散运动", "众多原子的变形", "原子裂变"], "option_labels": ["A", "B", "C", "D"], "answer": "A", "explanation": "A正确。同74、656题——塑性变形的微观机制是位错运动，不是原子扩散（那是高温扩散型转变的机制）或原子裂变（核反应，与力学性能无关）。这是金属学最重要的基础概念之一。", "section": "一、选择题", "topic": "综合复习", "id": 661, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "choice", "question": "钢淬火后，进行低温回火，得到的组织为（ ）。", "options": ["珠光体", "奥氏体", "回火马氏体", "回火索氏体"], "option_labels": ["A", "B", "C", "D"], "answer": "C", "explanation": "淬火+低温回火（150-250℃）获得回火马氏体（C）。同题库ID=633和ID=39答案一致（ID=39已修正为C），三题互相印证：淬火+低温回火得到的组织是回火马氏体，而非珠光体。回火马氏体是过饱和α固溶体+弥散ε-碳化物，硬度HRC58-64。", "section": "一、选择题", "topic": "综合复习", "id": 662, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "厚薄不均匀的工件浸入淬火介质冷却时，薄的部分先浸入淬火介质，带凹槽的工件， 凹槽面朝下浸入淬火介质。", "answer": "×", "explanation": "错误。同ID=145。厚薄不均匀工件淬火入液方向：厚的部分应先入液（热容量大需优先快速冷却→保证淬硬）；薄的部分后入液（热容量小冷速快→后入液避免先冷透产生过大收缩）。带凹槽工件凹槽面应朝上→气体/蒸汽自由逸出→避免凹槽内蒸汽聚集导致冷却不均和软点。", "section": "二、判断题", "topic": "综合复习", "id": 663, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "工序间实行首件产品自检和专检二检制度，对首件作出标记，并作实测记录。", "answer": "√", "explanation": "正确。工序间首件产品实行**自检+专检**二检制度——操作者先自检（自己检查首件的符合性），检验员再专检（独立检验确认），对首件做出标记并实测记录。双重验证确保首件合格后才能批量生产，将质量风险控制在最前端。", "section": "二、判断题", "topic": "综合复习", "id": 664, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "truefalse", "question": "进行低温回火，钢的组织不发生变化，只是消除内应力。", "answer": "×", "explanation": "错误。低温回火（150-250℃）虽然温度低，但马氏体发生了显著变化：①过饱和碳原子以ε-碳化物（Fe₂.₄C）形式从马氏体中析出→马氏体正方度（c/a）降低；②组织从淬火马氏体（过饱和α固溶体）变为了回火马氏体（α+弥散ε-碳化物）。组织已发生质变，并非\"只消除应力\"。", "section": "二、判断题", "topic": "综合复习", "id": 665, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "马氏体不锈钢锻件在正火保温过程中，电炉故障（炉丝断），可将锻件炉冷至600℃以 下出炉空冷，设备修复后按工艺重新进行正火。", "answer": "√", "explanation": "正确。同503题——马氏体不锈钢正火时遇设备故障可炉冷至600℃以下出炉空冷，设备修复后按工艺重新正火。这是标准应急处理流程，保证产品质量和安全。", "section": "二、判断题", "topic": "综合复习", "id": 666, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "导热性差的金属工件或坯料，加热或冷却时会产生内外温差，导致内外不同的膨胀或 收缩，产生应力、变形或破坏。", "answer": "√", "explanation": "正确。导热性差的金属（如高合金钢、钛合金，导热系数低）加热或冷却时产生较大内外温差→热膨胀或收缩不均→热应力→可能导致变形或开裂。因此高合金钢加热需缓慢升温（阶梯加热）、淬火冷却也需控制。", "section": "二、判断题", "topic": "综合复习", "id": 667, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "产品在存放、周转和运输时，应采取保护措施，防止混批、锈蚀、磕碰、压伤及变形 等，应使用相应的搬运设备，以不破坏原标识为前提。", "answer": "√", "explanation": "同685题——正确。产品存放/周转/运输须采取保护措施（防混批、防锈蚀、防磕碰、防压伤变形），使用合适搬运设备且不得破坏产品标识。", "section": "二、判断题", "topic": "综合复习", "id": 668, "knowledge_point": "变形与开裂", "knowledge_point_key": "deformation_cracking"}, {"type": "truefalse", "question": "金属结晶时，过冷度越大，结晶后晶粒也越粗大 。", "answer": "×", "explanation": "同171题——合法。过冷度越大→形核率越高→晶核越多→晶粒越细，题目说晶粒越粗大是错误的。", "section": "二、判断题", "topic": "综合复习", "id": 669, "knowledge_point": "晶粒与组织", "knowledge_point_key": "grain_structure"}, {"type": "truefalse", "question": "将金属或合金加热到适当温度，保温一定时间，然后缓慢冷却（一般为随炉冷却） ，的热处理工艺叫做退火。", "answer": "√", "explanation": "正确。退火三要素的完整定义：①加热到适当温度（按目的：去应力<Ac1，完全退火>Ac3，球化退火≈Ac1）；②保温一定时间（确保工件热透+组织转变完成）；③缓慢冷却/随炉冷却（核心特征——炉冷速度约30-100℃/h，以获得接近平衡态组织）。退火与正火（空冷）和淬火（水冷/油冷）的关键区别即在冷却方式。", "section": "二、判断题", "topic": "综合复习", "id": 670, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "truefalse", "question": "条状马氏体是高碳钢淬火后的典型组织。", "answer": "×", "explanation": "错误。同456题——条状（板条）马氏体是**低碳钢**的典型淬火组织，高碳钢的典型组织是针状（片状）马氏体。碳含量是决定马氏体形态的关键因素：<0.2%C→条状，>0.6%C→针状，中间为混合组织。", "section": "二、判断题", "topic": "综合复习", "id": 671, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "需要冷处理的钢，冷处理应当紧接着淬火操作之后进行，如果相隔时间过久，冷处 理的效果下降。", "answer": "√", "explanation": "正确。同ID=127。淬火后残余奥氏体在室温停留过程中逐渐稳定化（陈化效应）→碳原子/位错钉扎→后续冷处理马氏体转变阻力增大→效果下降。操作规范：淬火后立即（最好30分钟内）进行冷处理（-60至-80℃）以最大化残余奥氏体→马氏体转变。", "section": "二、判断题", "topic": "综合复习", "id": 672, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "工具钢含碳量都在0.70%以上，都是优质钢和高级优质钢。", "answer": "√", "explanation": "正确。碳素工具钢（T7~T13）含碳量均在0.70%~1.30%，均属于优质钢或高级优质钢（带\"A\"后缀，S、P含量更低）。工具钢对S、P等杂质控制严格，因为杂质会降低工具的使用寿命和可靠性。", "section": "二、判断题", "topic": "综合复习", "id": 673, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "凡标识不清或无标识的产品，下道工序可以拒绝接收。", "answer": "√", "explanation": "正确。凡标识不清或无标识的产品，下道工序有权**拒绝接收**——无标识产品的\"身份\"不确定（未知材料/未知批次），接收后可能导致混料和后续工序错误。退回上道工序补标或处理。", "section": "二、判断题", "topic": "综合复习", "id": 674, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "truefalse", "question": "锻件在热处理过程中需要加装负载热电偶时，负载热电偶加装的具体位置必须在产 品装炉位置图上进行标识。", "answer": "√", "explanation": "同495题——负载热电偶加装具体位置必须在产品装炉位置图上标识。这是质量体系要求，用于事后追溯和工艺审核。", "section": "二、判断题", "topic": "综合复习", "id": 675, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "受控文件是指该文件受到更改的控制，当受控文件更改时能追溯到使用者。", "answer": "√", "explanation": "正确。受控文件（如经审批盖章的工艺规程）的核心特征是\"受更改控制\"——文件更改时会同步通知所有持有者，保证现场使用的始终是最新有效版本。区别于非受控文件（仅供参考，不跟踪更改）。", "section": "二、判断题", "topic": "综合复习", "id": 676, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "不合格品处理结论一次有效。", "answer": "√", "explanation": "正确。不合格品处理结论（如让步接收、返工、报废等）**仅一次有效**——只能用于本次不合格品的处理，下次出现同样问题需重新审理，不得沿用上次结论。防止\"永久性让步\"导致质量滑坡。", "section": "二、判断题", "topic": "综合复习", "id": 677, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "关键过程一般包括形成关键、重要特性的过程；加工难度大、质量不稳定、易造成 重大经济损失的过程等。", "answer": "√", "explanation": "正确。关键过程包括：形成关键/重要特性的过程（直接影响产品安全/功能）；加工难度大、质量不稳定的过程（易出问题）；易造成重大经济损失的过程（出问题代价大）。关键过程需重点控制和监控。", "section": "二、判断题", "topic": "综合复习", "id": 678, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "truefalse", "question": "合金钢中含有锰、铬、镍、硅、铝、铜、磷等元素时，会降低第二类回火脆性倾向 。", "answer": "×", "explanation": "错误。同129题——Cr、Mn、Ni、Si等合金元素**促进**（增加）第二类回火脆性倾向，而非降低。降低/抑制第二类回火脆性的元素是Mo（最有效，≥0.2%）、W等。", "section": "二、判断题", "topic": "综合复习", "id": 679, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "为了获得足够低的硬度，合金钢退火时必须采用较碳钢更慢的冷却速度和更长的退 火时间。", "answer": "√", "explanation": "正确。合金钢因合金元素降低导热性、增加过冷奥氏体稳定性，退火时必须采用比碳钢更慢的冷却速度（如炉冷速度更慢，20~30℃/h）和更长的保温时间，才能充分软化、获得足够低的硬度。", "section": "二、判断题", "topic": "综合复习", "id": 680, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "在共析温度以下存在的奥氏体称为过冷奥氏体。", "answer": "√", "explanation": "正确。同ID=107。过冷奥氏体的定义：在共析温度（A1=727℃）以下存在的亚稳态奥氏体。过冷奥氏体是钢热处理中最重要的中间状态——通过控制其在不同温度区间的转变（C曲线不同区域），可获得珠光体/贝氏体/马氏体不同组织，实现不同性能。", "section": "二、判断题", "topic": "综合复习", "id": 681, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "truefalse", "question": "导热性差的金属工件或坯料，加热或冷却时会产生内外温差，导致内外不同的膨胀 或收缩，产生应力、变形或破坏。", "answer": "√", "explanation": "正确。同667题——导热性差的材料加热/冷却时内外温差大→热应力，严重时导致变形或开裂。这是制定加热和冷却工艺规范时必须考虑的因素，高合金钢的\"预热→升温→保温\"工艺就是为了减小热应力。", "section": "二、判断题", "topic": "综合复习", "id": 682, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "truefalse", "question": "马氏体不锈钢锻件在正火保温过程中，电炉故障（炉丝断），可将锻件炉冷至600℃ 以下出炉空冷，设备修复后按工艺重新进行正火。", "answer": "√", "explanation": "正确。同503、666题——马氏体不锈钢正火保温时设备故障的标准应急流程：炉冷至600℃以下出炉空冷，设备修复后重新正火。这保证了工艺纪律和产品可追溯性。", "section": "二、判断题", "topic": "综合复习", "id": 683, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "truefalse", "question": "厚薄不均匀的工件浸入淬火介质冷却时，薄的部分先浸入淬火介质，带凹槽的工件 ，凹槽面朝下浸入淬火介质。", "answer": "×", "explanation": "错误。同ID=145和ID=663。厚薄不均工件淬火：厚部分先入液，薄部分后入液。凹槽面朝上（让蒸汽/气泡自由逸出）。题目描述\"薄的部分先浸入\"和\"凹槽面朝下\"均与正确操作规程相反。", "section": "二、判断题", "topic": "综合复习", "id": 684, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "truefalse", "question": "产品在存放、周转和运输时，应采取保护措施，防止混批、锈蚀、磕碰、压伤及变 形等，应使用相应的搬运设备，以不破坏原标识为前提。", "answer": "√", "explanation": "正确。产品存放/周转/运输须采取保护措施防止混批（分批次存放）、锈蚀（防锈油/干燥环境）、磕碰（缓冲包装）、压伤变形（合理堆垛高度和支撑）。搬运设备以不破坏原标识为前提——标识是产品\"通行证\"。", "section": "二、判断题", "topic": "综合复习", "id": 685, "knowledge_point": "安全与操作规范", "knowledge_point_key": "safety_operation"}, {"type": "fill", "question": "在Fe- Fe3C相图中，共析温度为______℃，共析点S的含碳量为______%，奥氏体 的最大含碳量为______%，渗碳体的含碳量为______%。（727 0.77 2.11", "answer": "727，0.77，2.11，6.69", "explanation": "铁碳相图四个关键数值：共析温度727℃→S点（共析点）含碳量0.77%→奥氏体最大溶碳量2.11%（E点，1148℃）→渗碳体含碳量6.69%（Fe₃C的碳质量分数，Fe:C原子比3:1换算得）。这四数是铁碳相图的基石，必须准确记忆。", "section": "三、填空题", "topic": "综合复习", "id": 686, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "fill", "question": "69） ______", "answer": "2.11", "explanation": "同228题——铸铁含碳量大于**2.11%**，这是铁碳相图E点对应的碳在γ-Fe中最大溶解度，也是钢与铸铁的理论分界线。", "section": "三、填空题", "topic": "综合复习", "id": 687, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "质量记录如因笔误要修改原数据时，应采用______划去原数据，且在其上方或边 上的空白处填写______，并做好______，然后再在空白的 区域写上更改标记的次数与处数，并注明更改日期和更改人姓名，不允许使用涂改液或刮改等方式更改。", "answer": "单杠 更改后的数据  更改标记", "explanation": "质量记录修改规范（详细版）：用**单杠**（一条斜杠线）划去原数据，在原数据上方或旁边空白处填写**更改后的数据**，做好**更改标记**（如\"△1,2,3…\"编号），注明更改日期和更改人签名。严禁使用涂改液或刮改（掩盖真实信息）。", "section": "三、填空题", "topic": "综合复习", "id": 688, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "fill", "question": "在单位面积上的内力，称为______，以σ表示。", "answer": "应力", "explanation": "同229题——单位面积上内力称为**应力**，以σ（不是\"o\"）表示，单位MPa（N/mm²），σ=F/A。", "section": "三、填空题", "topic": "综合复习", "id": 689, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "金属材料的腐蚀一般有两种类型：一为______，即金属与周围介质发生化学作 用而产生的腐蚀，其特点为：金属与介质起化学作用，腐蚀过程没有电流产生，在金属 表面腐蚀；二是______，即金属与酸、碱、盐等电解质溶液接触时发生作用 而引起的腐蚀。", "answer": "化学腐蚀，电化学腐蚀", "explanation": "金属腐蚀两种类型：**化学腐蚀**（金属与干燥气体或非电解质发生化学作用，无电流产生，如高温氧化、钢的脱碳）和**电化学腐蚀**（金属与电解质溶液接触→形成微电池→有电流→金属不断溶解，如大气锈蚀、酸洗腐蚀，更普遍更具破坏性）。", "section": "三、填空题", "topic": "综合复习", "id": 690, "knowledge_point": "综合/未分类", "knowledge_point_key": "general"}, {"type": "fill", "question": "合金钢是指为了______，在碳钢中特意加入一种或数种______ ______ 的钢。", "answer": "改善钢的性能，合金元素", "explanation": "合金钢定义：为**改善钢的性能**（力学性能、工艺性能、物理化学性能），在碳钢中特意加入一种或数种**合金元素**（如Cr、Ni、Mn、Si、Mo、W、V、Ti等）的钢。与267题原理相同，核心是\"特意加入+改善性能\"。", "section": "三、填空题", "topic": "综合复习", "id": 691, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "铸铁是含碳量大于______%铁碳合金。并且还含有硅、锰、硫、磷等元素。（", "answer": "2.11", "explanation": "铸铁是含碳量大于**2.11%**的铁碳合金。2.11%是铁碳相图中E点碳含量（1147℃时碳在γ-Fe中的最大溶解度），也是钢和铸铁的理论分界。铸铁中还含有Si、Mn、S、P等元素。", "section": "三、填空题", "topic": "综合复习", "id": 692, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "钢的热处理原理主要是利用钢在加热和冷却时内部组织发生转变的基本规律，根据这 些基本规律和要求来确定______和______及冷却介质等有关参数，以 达到改善材料性能的目的。", "answer": "加热温度，保温时间", "explanation": "同258题——钢热处理原理：利用内部组织转变规律确定**加热温度**、**保温时间**和冷却介质三个关键参数。加热温度决定相变类型→保温时间保证均匀奥氏体化→冷却介质决定转变产物。", "section": "三、填空题", "topic": "综合复习", "id": 693, "knowledge_point": "加热与保温", "knowledge_point_key": "heating_holding"}, {"type": "fill", "question": "安全生产中，通常所说的“三违”是指：______、______、______ ______。", "answer": "违章指挥、违章作业、违反劳动纪律", "explanation": "安全生产\"三违\"：**违章指挥**（领导强迫冒险作业）、**违章作业**（员工不按规程操作）、**违反劳动纪律**（迟到早退、脱岗、酒后上岗等）。\"三违\"是生产安全事故的主要原因。", "section": "三、填空题", "topic": "综合复习", "id": 694, "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "fill", "question": "材料抵抗局部变形，特别时塑性变形、压痕或划痕的能力称为______。", "answer": "硬度", "explanation": "同217题——**硬度**定义：材料抵抗局部变形（特别是塑性变形）、压痕或划痕的能力。硬度是最常用的力学性能指标之一，操作简便快捷、不破坏工件，广泛用于热处理质量检验。", "section": "三、填空题", "topic": "综合复习", "id": 695, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "工件在冷却过程中，会伴随两种应力的出现，即______和______ ______。", "answer": "热应力，组织应力", "explanation": "同243题——工件冷却过程伴随两种应力：**热应力**（内外冷却不同时引起的收缩差应力）和**组织应力**（马氏体转变体积膨胀引起的相变应力）。两者叠加是淬火变形和开裂的根本原因。", "section": "三、填空题", "topic": "综合复习", "id": 696, "knowledge_point": "力学性能", "knowledge_point_key": "mechanical_properties"}, {"type": "fill", "question": "回火后的冷却对工件的性能影响不大，一般在______中冷却。有时为了消除铬 及铬镍钢的第二类回火脆性，可考虑在______中快速冷却。", "answer": "空气，水 或油", "explanation": "同252题——回火冷却一般在**空气**中冷却（性能影响不大）。但对第二类回火脆性敏感的含Cr、Cr-Ni钢，应在**水或油**中快速冷却，避免缓冷时杂质向晶界偏聚导致脆性。", "section": "三、填空题", "topic": "综合复习", "id": 697, "knowledge_point": "合金元素作用", "knowledge_point_key": "alloy_elements"}, {"type": "fill", "question": "把含碳量小于______%而不含有特意加入合金元素的钢称为碳素钢，简称碳钢。", "answer": "2.11", "explanation": "同216题——含碳量小于**2.11%**且不含特意加入合金元素的铁碳合金称为碳素钢（碳钢）。2.11%是钢与铸铁的理论分界线（铁碳相图E点）。", "section": "三、填空题", "topic": "综合复习", "id": 698, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "fill", "question": "细晶粒组织不仅强度、塑性比粗晶粒高，尤其是韧性有明显的提高。因此，钢在加热 时，为了得到细小而均匀的奥氏体晶粒，必须严格控制______和______ ______。", "answer": "加热温度，保温时间", "explanation": "同ID=235。获得细小均匀奥氏体晶粒的两个关键控制参数：加热温度和保温时间。温度过高→晶粒以指数速率长大（晶界迁移热激活），保温过长→晶粒持续长大（随时间平方根增大）。两者必须严格控制，温度为首要因素。", "section": "三、填空题", "topic": "综合复习", "id": 699, "knowledge_point": "奥氏体转变", "knowledge_point_key": "austenite_transformation"}, {"type": "calculation", "question": "锻造分厂送来三项急件A、B、C材料为TA15的小模锻件产品，需要及时进行退火热处理 ，根据产品质量记录卡得知：A产品数量为65+2（理化）+6试棒，B产品数量为130+2（理 化）件，C产品数量105+2（理化）件，且三项产品的热处理参数一致。当前现场仅有一 台电炉空闲，此三项产品的热处理工艺中，该电炉装A产品的装炉量≤120件（注：试棒不 计入装炉数量），装B产品的装炉量≤280件，装C产品的装炉量≤230件。问A、B、C三项产 品能否共装一炉同时进行生产？请说明原因。558+0.471+0.465=1.494＞1 答：A、B、C三项产品不能共装一炉同时进行生产。", "answer": "解：A产品数量为：65+2=67（件） 炉子占比为：67/120=0.558 B产品数量为：130+2=132（件） 炉子占比为：132/280=0.471 C产品数量为：105+2=107（件） 炉子占比为：107/230=0.465 三项同时装炉总占比为：", "explanation": "解：A产品数量为：65+2=67（件） 炉子占比为：67/120=0.558 B产品数量为：130+2=132（件） 炉子占比为：132/280=0.471 C产品数量为：105+2=107（件） 炉子占比为：107/230=0.465 三项同时装炉总占比为：", "section": "四、计算题", "topic": "综合复习", "id": 700, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "calculation", "question": "请计算经过退火后的45号钢中的铁素体和渗碳体的相对含量各是多少？", "answer": "解：根据Fe-Fe3C相图及杠杆原理，得 铁素体含量F=（6.69-0.45）/（6.69-0）×100%=93.3% 渗碳体含量Fe3C=1-F=1-93.3%=6.7%", "explanation": "解：根据Fe-Fe3C相图及杠杆原理，得 铁素体含量F=（6.69-0.45）/（6.69-0）×100%=93.3% 渗碳体含量Fe3C=1-F=1-93.3%=6.7%", "section": "四、计算题", "topic": "综合复习", "id": 701, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "calculation", "question": "请计算经过退火后的35号钢中的铁素体和渗碳体的相对含量各是多少？", "answer": "解：根据Fe-Fe3C相图及杠杆原理，得 铁素体含量F=（6.69-0.35）/（6.69-0）×100%=94.8% 渗碳体含量Fe3C=1-F=1-94.8%=5.2%", "explanation": "解：根据Fe-Fe3C相图及杠杆原理，得 铁素体含量F=（6.69-0.35）/（6.69-0）×100%=94.8% 渗碳体含量Fe3C=1-F=1-94.8%=5.2%", "section": "四、计算题", "topic": "综合复习", "id": 702, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "calculation", "question": "根据Fe- Fe3C相图并利用杠杆原理，计算平衡状态下珠光体中铁素体和渗碳体的相对量。（注： 铁素体碳含量可忽略）", "answer": "解：根据Fe-Fe3C相图可知，珠光体的含碳量为0.77%，渗碳体的含碳量为6.69%，则 铁素体含量F=（6.69-0.77）/（6.69-0）×100%=88.5% 渗碳体含量Fe3C=1-F=1-88.5%=11.5%", "explanation": "解：根据Fe-Fe3C相图可知，珠光体的含碳量为0.77%，渗碳体的含碳量为6.69%，则 铁素体含量F=（6.69-0.77）/（6.69-0）×100%=88.5% 渗碳体含量Fe3C=1-F=1-88.5%=11.5%", "section": "四、计算题", "topic": "综合复习", "id": 703, "knowledge_point": "铁碳相图", "knowledge_point_key": "iron_carbon_diagram"}, {"type": "calculation", "question": "已知某碳钢在退火状态的金相组织中，珠光体含量为45%，其它为铁素体，试计算该钢 的含碳量，并指出大概的钢号。", "answer": "解：因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=45%×0.77%=0.45×0.77%=0.3465% 根据碳钢的命名法则，含碳量为0.3465%左右的钢，其牌号应为35钢。 答：该钢的含碳量为0.3465%，钢号应为35钢。", "explanation": "解：因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=45%×0.77%=0.45×0.77%=0.3465% 根据碳钢的命名法则，含碳量为0.3465%左右的钢，其牌号应为35钢。 答：该钢的含碳量为0.3465%，钢号应为35钢。", "section": "四、计算题", "topic": "综合复习", "id": 704, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "calculation", "question": "生产现场有A、B、C三项TC6小模锻件产品等待退火热处理，根据产品质量记录卡得知 ：A产品数量为32+2（理化）件，B产品数量为50+6（理化）件，C产品数量35+2（理化） 件，且三项产品的热处理参数一致。当前现场仅有一台电炉空闲，在三项产品的热处理 工艺中，该电炉装A产品的装炉量≤120件，装B产品的装炉量≤180件，装C产品的装炉量≤ 130件。问A、B、C三项产品能否共装一炉同时进行生产？请说明原因。283+0.311+0.285=0.879＜1 答：A、B、C三项产品能共装一炉同时进行生产。", "answer": "解：A产品数量为：32+2=34（件） 炉子占比为：34/120=0.283 B产品数量为：50+6=56（件） 炉子占比为：56/180=0.311 C产品数量为：35+2=37（件） 炉子占比为：37/130=0.285 三项同时装炉总占比为：", "explanation": "解：A产品数量为：32+2=34（件） 炉子占比为：34/120=0.283 B产品数量为：50+6=56（件） 炉子占比为：56/180=0.311 C产品数量为：35+2=37（件） 炉子占比为：37/130=0.285 三项同时装炉总占比为：", "section": "四、计算题", "topic": "综合复习", "id": 705, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "calculation", "question": "已知某碳钢在退火状态的金相组织中，铁素体含量为48%，其它为珠光体，试计算该钢 的含碳量，并指出大概的钢号。", "answer": "解：金相组织中珠光体含量为：1-48%=52% 又因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=52%×0.77%=0.52×0.77%=0.4004% 根据碳钢的命名法则，含碳量为0.4004%左右的钢，其牌号应为40钢。 答：该钢的含碳量为0.4004%，钢号应为40钢。", "explanation": "解：金相组织中珠光体含量为：1-48%=52% 又因为珠光体含碳量为0.77%，所以该钢的含碳量为： C%=P%×0.77%=52%×0.77%=0.52×0.77%=0.4004% 根据碳钢的命名法则，含碳量为0.4004%左右的钢，其牌号应为40钢。 答：该钢的含碳量为0.4004%，钢号应为40钢。", "section": "四、计算题", "topic": "综合复习", "id": 706, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "shortanswer", "question": "退火的目的是什么？", "answer": "a、降低钢的硬度，提高塑性，以利于切削加工及冷变形加工；b、细化晶粒，均匀 钢的组织及成分，改善钢的性能或为以后的热处理作准备；c、消除钢中的残余内应力， 以防止变形和开裂。", "explanation": "a、降低钢的硬度，提高塑性，以利于切削加工及冷变形加工；b、细化晶粒，均匀 钢的组织及成分，改善钢的性能或为以后的热处理作准备；c、消除钢中的残余内应力， 以防止变形和开裂。", "section": "五、简答题", "topic": "综合复习", "id": 707, "knowledge_point": "退火", "knowledge_point_key": "annealing"}, {"type": "shortanswer", "question": "合金钢比碳钢的回火稳定性高，是否是有利，请说明原因？", "answer": "合金钢回火稳定性较高，一般是有利的：在达到相同硬度的情况下，合金钢的回火 温度应比碳钢高，回火时间也应增长，可进一步消除残余应力，因而合金钢的塑性、韧 性较碳钢好；而在同一温度回火时，合金钢的强度、硬度比碳钢高。", "explanation": "合金钢回火稳定性较高，一般是有利的：在达到相同硬度的情况下，合金钢的回火 温度应比碳钢高，回火时间也应增长，可进一步消除残余应力，因而合金钢的塑性、韧 性较碳钢好；而在同一温度回火时，合金钢的强度、硬度比碳钢高。", "section": "五、简答题", "topic": "综合复习", "id": 708, "knowledge_point": "钢的分类与牌号", "knowledge_point_key": "steel_classification"}, {"type": "shortanswer", "question": "回火的目的是什么？", "answer": "a、减少或消除淬火时产生的内应力，防止工件在使用过程中产生变形和开裂；b、 通过回火提高钢的韧性，适当调整钢的强度和硬度，使工件达到所要求的力学性能，以 满足各种工件的性能需要；c、稳定组织，使工件在使用过程中不发生组织转变，从而保 证工件的形状和尺寸不变，保证工件的精度。", "explanation": "a、减少或消除淬火时产生的内应力，防止工件在使用过程中产生变形和开裂；b、 通过回火提高钢的韧性，适当调整钢的强度和硬度，使工件达到所要求的力学性能，以 满足各种工件的性能需要；c、稳定组织，使工件在使用过程中不发生组织转变，从而保 证工件的形状和尺寸不变，保证工件的精度。", "section": "五、简答题", "topic": "综合复习", "id": 709, "knowledge_point": "回火", "knowledge_point_key": "tempering"}, {"type": "shortanswer", "question": "质量是一组固有特性满足要求的程度，要保证产品的质量，我们在生产过程中必须保 证工作质量，坚持质量原则，请简述生产过程中何为“五清六分批”？", "answer": "五清是指：产品批次清、质量状况清、原始记录清、数量清、炉批号清。 六分批是指：分批投料、分批加工、分批转工、分批入库、分批装配、分批出厂。", "explanation": "五清是指：产品批次清、质量状况清、原始记录清、数量清、炉批号清。 六分批是指：分批投料、分批加工、分批转工、分批入库、分批装配、分批出厂。", "section": "五、简答题", "topic": "综合复习", "id": 710, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "shortanswer", "question": "对不合格品的处置方式有：不合格原材料的处置方式有退回供方和让步接收；不合格 半成品、成品的处置方式有让步接收、返工、返修、报废等。但对产生不合格品的生产 过程要进行深究，请简述何为不合格品“五不放过原则”？", "answer": "原因找不出不放过；责任查不清不放过；纠正措施不落实不放过；验证不充分不放 过；教育不到位不放过。", "explanation": "原因找不出不放过；责任查不清不放过；纠正措施不落实不放过；验证不充分不放 过；教育不到位不放过。", "section": "五、简答题", "topic": "综合复习", "id": 711, "knowledge_point": "质量管理与检验", "knowledge_point_key": "quality_inspection"}, {"type": "shortanswer", "question": "根据现场的生产经验，请简要回答以下问题： （1）钢件淬火的目的是什么？ （2）何为理想的淬火冷却介质？ （3）为什么要寻找这样的冷却速率？ （4）在我们的生产中有没有类似这样的操作方式，举出1个以上的例子。", "answer": "（1）钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 （2）理想的淬火冷却介质是：淬火冷却速率应为开始先缓慢冷却之后快速冷却最后缓慢 冷却。 （3）因为这样的冷却速率既得到马氏体组织，又减小了热应力和组织应力，防止钢件变 形或开裂等。 （4）生产中类似的操作方式如：双液淬火，钢件在空气中预冷后再入油冷却等。", "explanation": "（1）钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 （2）理想的淬火冷却介质是：淬火冷却速率应为开始先缓慢冷却之后快速冷却最后缓慢 冷却。 （3）因为这样的冷却速率既得到马氏体组织，又减小了热应力和组织应力，防止钢件变 形或开裂等。 （4）生产中类似的操作方式如：双液淬火，钢件在空气中预冷后再入油冷却等。", "section": "五、简答题", "topic": "综合复习", "id": 712, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"type": "shortanswer", "question": "钢淬火的主要目的是什么？当炉温升到淬火温度后，为何还需要进行保温？", "answer": "钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 为了使钢件热透，使奥氏体转变彻底并均匀化。所以要进行保温。", "explanation": "钢淬火的主要目的是为了获得马氏体，提高钢的强度和硬度。 为了使钢件热透，使奥氏体转变彻底并均匀化。所以要进行保温。", "section": "五、简答题", "topic": "综合复习", "id": 713, "knowledge_point": "淬火", "knowledge_point_key": "quenching"}, {"id": 714, "type": "truefalse", "topic": "仪表知识", "section": "二、判断题", "question": "设备生产使用时，可以不用设定报警温度。", "answer": "×", "explanation": "错误。设备生产时报警温度**必须**设定——报警温度是防止超温/超时的重要安全保护措施。不设报警=无法及时发现异常→可能导致过烧、跑温、设备损坏甚至火灾等严重后果。设定报警温度是操作规程的强制要求。", "knowledge_point": "热处理设备", "knowledge_point_key": "heat_treatment_equipment"}, {"type": "truefalse", "question": "从总的趋势上看，各种钢回火后的硬度是随着回火温度的升高而降低的。", "answer": "√", "explanation": "正确。回火硬度总体趋势随回火温度升高而降低——碳从马氏体中析出量增大+渗碳体从ε-碳化物→Fe₃C→球化长大→硬度单调下降。特殊例外：含W/Mo/V等元素的钢在500-600℃回火出现二次硬化（合金碳化物弥散析出→硬度回升），但总体趋势仍是下降的。", "section": "二、判断题", "topic": "热处理设备与工艺", "id": 715, "knowledge_point": "回火", "knowledge_point_key": "tempering"}];

