KP_MAP["atmosphere_control"] = {"key": "atmosphere_control", "name": "气氛控制", "explanation": "热处理保护气氛可防止工件氧化脱碳。常用气氛：吸热式气氛、放热式气氛、氮基气氛、氨分解气、真空。碳势是表征气氛渗碳能力的参数，用氧探头或露点仪测量。脱碳会降低表面硬度和疲劳强度，氧化会形成氧化皮影响尺寸。真空热处理能完全避免氧化脱碳，且具有表面净化效果。", "key_concepts": ["碳势控制", "氧化与脱碳", "保护气氛类型", "真空热处理的优点", "氧探头/露点仪"], "exam_focus": "常考：保护气氛的目的、氧化脱碳的危害、碳势概念"};
KP_MAP["quality_inspection"] = {"key": "quality_inspection", "name": "质量管理与检验", "explanation": "热处理质量检验包括：①硬度检测（最常用的验收指标）；②金相组织检查（显微组织是否符合要求）；③变形与尺寸检查；④表面质量检查（裂纹、软点、脱碳等）；⑤无损探伤（磁粉/渗透/超声波/X射线）。不合格品处理：返修、让步接收或报废。温度仪表、热电偶等需按周期校准，确保过程受控。材料牌号与料单、图号必须一致方可生产。", "key_concepts": ["硬度为首要检验指标", "金相组织检查", "无损探伤方法", "不合格品处理流程", "材料核对"], "exam_focus": "常考：检验项目、无损探伤方法选择、不合格品处理"};
KP_MAP["deformation_cracking"] = {"key": "deformation_cracking", "name": "变形与开裂", "explanation": "热处理变形与开裂主要由内应力引起：①热应力（加热/冷却不均匀导致的热胀冷缩差异）；②相变应力（组织转变引起的体积变化，如奥氏体→马氏体体积膨胀）。预防措施：合理选材、正确设计零件结构、合理制定工艺（如预热、分级淬火、等温淬火）、淬火后及时回火。淬火裂纹一旦产生即不可修复→废品。", "key_concepts": ["热应力vs相变应力", "变形原因", "开裂原因", "淬火后及时回火", "结构设计合理性"], "exam_focus": "常考：热应力与相变应力的概念、变形开裂的预防措施"};
KP_MAP["heating_holding"] = {"key": "heating_holding", "name": "加热与保温", "explanation": "加热速度需考虑：①工件尺寸与形状（大件/复杂件应慢热，防变形开裂）；②钢的导热性（高合金钢导热差，需预热或阶梯加热）；③原始组织。保温时间应保证工件透烧和组织转变充分，通常按有效厚度计算：t=α·K·D（α为加热系数，K为装炉系数，D为有效厚度）。加热不足导致组织转变不充分，过热/过烧导致晶粒粗大甚至晶界氧化→不可逆转。", "key_concepts": ["有效厚度计算", "加热时间公式", "过烧vs过热", "预热/阶梯加热"], "exam_focus": "常考：有效厚度概念、加热时间公式参数含义、过热过烧区别"};
KP_MAP["cooling_quenchants"] = {"key": "cooling_quenchants", "name": "冷却介质与淬透性", "explanation": "理想冷却介质的冷却特性：在C曲线鼻子处（~550°C）快冷避开珠光体转变，在Ms点以下慢冷减少马氏体转变应力。常用介质冷却能力：10%NaCl水溶液>水>油>空气。淬透性表示钢接受淬火获得马氏体的能力，取决于过冷奥氏体稳定性（C曲线位置）。淬硬性表示钢淬火后能达到的最高硬度，取决于马氏体含碳量。淬透性好≠淬硬性好。", "key_concepts": ["理想冷却曲线", "介质冷却能力排序", "淬透性vs淬硬性", "临界直径"], "exam_focus": "高频考点：淬透性与淬硬性的区别（几乎必考）、介质冷却能力排序"};
KP_MAP["grain_structure"] = {"key": "grain_structure", "name": "晶粒与组织", "explanation": "金属通常是多晶体，由许多晶粒组成，晶粒之间为晶界。晶粒越细小→强度硬度越高、塑性韧性越好（细晶强化）。加热温度过高或保温时间过长会导致晶粒粗大→力学性能下降。再结晶温度以上加热可使冷变形金属形成新的无畸变等轴晶粒。同素异构转变（如α-Fe ↔ γ-Fe）是钢能进行热处理的基础。晶体结构类型：体心立方（α-Fe）、面心立方（γ-Fe）、密排六方。", "key_concepts": ["细晶强化", "晶粒粗大原因与危害", "再结晶", "同素异构转变", "三种晶体结构"], "exam_focus": "常考：细晶强化的原理、同素异构与热处理的关系、再结晶概念"};
KP_MAP["nonferrous_heat_treatment"] = {"key": "nonferrous_heat_treatment", "name": "有色金属热处理", "explanation": "有色金属热处理与钢不同：①铝合金主要热处理方式是固溶+时效（强化相析出），如硬铝LY12、超硬铝LC4；②铜合金主要用去应力退火防止「季裂」（黄铜的应力腐蚀开裂），以及再结晶退火；③钛合金可进行退火和固溶时效。有色金属不发生马氏体相变（钛合金除外）。固溶处理将合金元素溶入基体，时效使强化相弥散析出→提高强度。过时效=温度过高或时间过长→强化相聚集长大→合金软化。", "key_concepts": ["铝合金固溶+时效", "黄铜季裂=去应力退火", "过时效=软化", "固溶温度选择", "自然时效vs人工时效"], "exam_focus": "常考：铝合金热处理方式、铜合金季裂原因及防止、过时效现象"};
KP_MAP["heat_treatment_process_design"] = {"key": "heat_treatment_process_design", "name": "热处理工艺设计", "explanation": "热处理工艺设计需综合考虑：①零件技术要求（硬度、强度、组织等）；②材料特性（临界点、淬透性、回火稳定性等）；③零件结构（有效厚度、形状复杂程度、截面变化等）；④生产批量与设备条件。预备热处理（退火/正火）改善切削加工性和组织均匀性；最终热处理（淬火+回火/渗碳/氮化等）赋予零件最终性能。工序安排：锻造→预备热处理→粗加工→最终热处理→精加工。", "key_concepts": ["预备热处理vs最终热处理", "工艺路线安排", "有效厚度计算", "技术要求的解读"], "exam_focus": "常考：工序安排顺序、预备热处理的目的和选择"};
KP_MAP["hardness_testing"] = {"key": "hardness_testing", "name": "硬度检测", "explanation": "硬度是热处理质量检验最常用、最快速的指标。常用方法：①布氏硬度（HBW）：用硬质合金球压头，适合较软金属和毛坯；②洛氏硬度（HRC/HRB/HRA）：用金刚石圆锥或钢球压头，最常用，HRA用于硬质合金等超硬材料，HRC用于淬火件，HRB用于软材料；③维氏硬度（HV）：适合薄件、渗层、显微硬度。不同硬度之间可近似换算，但应以实测为准。硬度检测部位应在图样上明确标注。", "key_concepts": ["HBW/HRC/HV适用场景", "HRC用于淬火件", "维氏硬度适合渗层", "硬度换算", "硬度检测位置要求"], "exam_focus": "常考：三种硬度方法的适用范围、HRC是淬火件最常用指标"};
KP_MAP["vacuum_heat_treatment"] = {"key": "vacuum_heat_treatment", "name": "真空热处理", "explanation": "真空热处理在低于大气压的环境中进行，优点：①完全避免氧化脱碳；②表面净化（氧化物分解挥发）；③脱气效果（去除氢等有害气体）；④变形小（加热和冷却均匀）。真空炉冷却方式：真空气淬（用高纯氮气/氩气高速循环冷却）、真空油淬。真空炉操作安全：出炉前必须确认炉温降至安全温度（通常<200°C），确认料框升到位、穿销位灯亮方可出炉。", "key_concepts": ["真空热处理优点", "真空气淬vs油淬", "出炉安全条件", "无氧化脱碳"], "exam_focus": "常考：真空热处理的优点、出炉温度和安全操作要求"};
KP_MAP["safety_operation"] = {"key": "safety_operation", "name": "安全与操作规范", "explanation": "热处理生产安全要点：①防烫伤（穿戴防护用品、确认工件温度）；②防火灾爆炸（油淬必须开启排烟、可燃气体管道安全）；③防中毒（渗碳/渗氮气氛有毒、氨气泄漏）；④设备安全（控制柜门不得常开、设备故障须上报挂牌、不得带病作业）；⑤吊运安全（吊具定期检查、不同颜色标识不同吨位、完成后吊具不得悬挂）；⑥TPM/自主维护（操作者也是设备管理者，点检、清扫、紧固、润滑）。", "key_concepts": ["劳保穿戴", "吊具管理", "设备故障上报", "TPM/自主维护", "油淬排烟", "管道颜色标识"], "exam_focus": "常考：设备故障处理流程、吊具管理要求、操作者维护职责"};
